import { getDb, nowTs } from '../database';

// ── Types ──────────────────────────────────────────────────────────────────

export interface MindMap {
  id: number;
  title: string;
  subjectId: number | null;
  topicId: number | null;
  viewportJson: string;
  createdAt: number;
  updatedAt: number;
}

export interface MindMapNode {
  id: number;
  mapId: number;
  topicId: number | null;
  label: string;
  x: number;
  y: number;
  color: string | null;
  isCenter: boolean;
  aiGenerated: boolean;
  explanation: string | null;
  createdAt: number;
}

export interface MindMapEdge {
  id: number;
  mapId: number;
  sourceNodeId: number;
  targetNodeId: number;
  label: string | null;
  isCrossLink: boolean;
  createdAt: number;
}

export interface MindMapFull {
  map: MindMap;
  nodes: MindMapNode[];
  edges: MindMapEdge[];
}

// ── Row mappers ────────────────────────────────────────────────────────────

function toMap(row: any): MindMap {
  return {
    id: row.id,
    title: row.title,
    subjectId: row.subject_id,
    topicId: row.topic_id,
    viewportJson: row.viewport_json,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
  };
}

function toNode(row: any): MindMapNode {
  return {
    id: row.id,
    mapId: row.map_id,
    topicId: row.topic_id,
    label: row.label,
    x: row.x,
    y: row.y,
    color: row.color,
    isCenter: !!row.is_center,
    aiGenerated: !!row.ai_generated,
    explanation: row.explanation ?? null,
    createdAt: row.created_at,
  };
}

function toEdge(row: any): MindMapEdge {
  return {
    id: row.id,
    mapId: row.map_id,
    sourceNodeId: row.source_node_id,
    targetNodeId: row.target_node_id,
    label: row.label,
    isCrossLink: !!row.is_cross_link,
    createdAt: row.created_at,
  };
}

// ── Queries ────────────────────────────────────────────────────────────────

export async function listMindMaps(): Promise<MindMap[]> {
