export async function updateUserProfile(updates: Partial<UserProfile>): Promise<void> {
  const db = getDb();
  const map: Record<string, string> = {
    displayName: 'display_name',
    totalXp: 'total_xp',
    currentLevel: 'current_level',
    streakCurrent: 'streak_current',
