  }, []);

  const handlePipelineProgress = useCallback((progress: LecturePipelineProgress) => {
    if (cancelRequestedRef.current) return;
    if (progress.stage === 'enhancing') {
      return;
    }
    const now = Date.now();
    setActiveStage((current) => {
      if (current !== progress.stage) {
        setStageStartedAt(now);
      }
      return progress.stage;
    });
    setStageMessage(progress.message);
    setStageDetail(progress.detail ?? '');
    setProgressPercent(progress.percent ?? 0);
    setProgressStep(progress.step ?? null);
    setProgressTotalSteps(progress.totalSteps ?? null);
    setProgressAttempt(progress.attempt ?? null);
    setProgressMaxAttempts(progress.maxAttempts ?? null);
    setProgressProvider(progress.provider ?? null);

    const signature = [
      progress.stage,
      progress.message,
      progress.detail ?? '',
      progress.percent ?? '',
      progress.step ?? '',
      progress.totalSteps ?? '',
      progress.attempt ?? '',
      progress.maxAttempts ?? '',
      progress.provider ?? '',
    ].join('|');
    if (lastProgressSignatureRef.current === signature) {
      return;
    }
    lastProgressSignatureRef.current = signature;
    setProgressHistory((current) => {
      const next = [
        ...current,
        {
          id: now,
          stage: progress.stage,
          message: progress.message,
          detail: progress.detail,
          createdAt: now,
        },
      ];
      return next.slice(-5);
    });
  }, []);

  useEffect(() => {
    let cancelled = false;

    async function syncSubjectRequirement() {
      if (!analysis) {
        setSubjectSelectionRequired(false);
        setSelectedSubjectName(null);
        return;
      }

      const resolution = await resolveLectureSubjectRequirement(analysis.subject);
      if (cancelled) return;

      setSubjectSelectionRequired(resolution.requiresSelection);
      setSelectedSubjectName(
        resolution.requiresSelection
          ? null
          : (resolution.matchedSubject?.name ?? resolution.normalizedSubjectName),
      );
    }

    void syncSubjectRequirement();
    return () => {
      cancelled = true;
    };
  }, [analysis]);

  const runTranscription = useCallback(async () => {
    const runId = ++transcriptionRunIdRef.current;
    cancelRequestedRef.current = false;
    progressHeartbeatAtRef.current = Date.now();
    setPhase('transcribing');
    setIsExpanded(false);
    setQuizQuestions([]);
    setQuizLoading(false);
    handlePipelineProgress({
      stage: 'transcribing',
      message: 'Preparing lecture transcription',
      detail: 'Checking the recording and selecting the transcription path',
      percent: 4,
    });
    // Clear any existing stall-check interval before creating a new one
    if (stallCheckIntervalRef.current) {
      clearInterval(stallCheckIntervalRef.current);
      stallCheckIntervalRef.current = null;
    }
    stallCheckIntervalRef.current = setInterval(() => {
      if (runId !== transcriptionRunIdRef.current || cancelRequestedRef.current) {
        clearInterval(stallCheckIntervalRef.current!);
        stallCheckIntervalRef.current = null;
        return;
      }
      if (Date.now() - progressHeartbeatAtRef.current < TRANSCRIPTION_STALL_TIMEOUT_MS) {
        return;
      }

      clearInterval(stallCheckIntervalRef.current!);
      stallCheckIntervalRef.current = null;
      transcriptionRunIdRef.current += 1;
      setActiveStage(null);
      setStageMessage('');
      setStageDetail('');
      setProgressPercent(0);
      setProgressStep(null);
      setProgressTotalSteps(null);
      setProgressAttempt(null);
      setProgressMaxAttempts(null);
      setProgressProvider(null);
      setIsExpanded(true);
      setErrorMsg(
        'Lecture transcription stalled before any usable result came back. Audio is still saved, so retry once or reopen Guru.',
      );
      void updateSessionTranscriptionStatus(logId, 'failed', 'Lecture transcription stalled');
      setPhase('error');
      console.warn('[LectureReturn] Transcription watchdog timed out', {
        logId,
        appName,
        recordingPath,
        timeoutMs: TRANSCRIPTION_STALL_TIMEOUT_MS,
      });
    }, TRANSCRIPTION_STALL_CHECK_INTERVAL_MS);
    try {
      if (__DEV__) {
        console.log('[LectureReturn] Starting lecture transcription', {
          logId,
          appName,
          recordingPath,
          durationMinutes,
        });
      }
      await updateSessionTranscriptionStatus(logId, 'transcribing');
      const result = await transcribeLectureWithRecovery({
        recordingPath: recordingPath!,
        groqKey: groqKey || undefined,
        useLocalWhisper: !!(profile?.useLocalWhisper && profile?.localWhisperPath),
        localWhisperPath: profile?.localWhisperPath || undefined,
        includeEmbedding: false,
        maxRetries: 1,
        logId,
        onProgress: (progress) => {
          if (runId !== transcriptionRunIdRef.current || cancelRequestedRef.current) return;
          progressHeartbeatAtRef.current = Date.now();
          handlePipelineProgress(progress);
        },
      });
      if (stallCheckIntervalRef.current) {
        clearInterval(stallCheckIntervalRef.current);
        stallCheckIntervalRef.current = null;
      }

      if (!visible || cancelRequestedRef.current || runId !== transcriptionRunIdRef.current) {
        if (!visible)
          await updateSessionTranscriptionStatus(logId, 'pending', 'Transcription backgrounded');
        return;
      }

      if (!result.transcript?.trim()) {
        setActiveStage(null);
        setStageMessage('');
        setStageDetail('');
        await updateSessionTranscriptionStatus(
          logId,
          'no_audio',
          'No speech detected in recording',
        );
        // Auto-dismiss — no useful content to show
        void cleanupAndClose();
        return;
      }
      setAnalysis(result);
      setTranscriptionCompleted(true);
      setSessionSaved(false);
      setActiveStage(null);
      setStageMessage('');
      setStageDetail('');
      setProgressPercent(100);
      setProgressStep(null);
      setProgressTotalSteps(null);
      setProgressAttempt(null);
      setProgressMaxAttempts(null);
      setProgressProvider(null);
      await updateSessionTranscriptionStatus(logId, 'pending');
      setPhase('results');
      if (Array.isArray(result.precomputedQuiz) && result.precomputedQuiz.length > 0) {
        setQuizQuestions(result.precomputedQuiz);
      } else if (result.topics.length > 0) {
        generateQuiz(result);
      }
    } catch (e: any) {
      if (stallCheckIntervalRef.current) {
        clearInterval(stallCheckIntervalRef.current);
        stallCheckIntervalRef.current = null;
      }
      if (!visible || cancelRequestedRef.current || runId !== transcriptionRunIdRef.current) {
        return;
      }
      console.error('[Transcription] Error:', e);

      // Handle Metro bundler disconnect (dev mode only) — not a real transcription failure
      const isMetroDisconnect =
        e?.name === 'LoadBundleFromServerRequestError' ||
        e?.message?.includes('Could not load bundle');

      const message = isMetroDisconnect
        ? 'Connection to dev server lost. Audio preserved — retry when reconnected.'
        : (e?.message ?? 'Transcription failed');

      setActiveStage(null);
      setStageMessage('');
      setStageDetail('');
      setErrorMsg(`${message}. Audio has been preserved for auto-retry on next launch.`);
      await updateSessionTranscriptionStatus(
        logId,
        isMetroDisconnect ? 'pending' : 'failed',
        message,
      );
      setPhase(isMetroDisconnect ? 'intro' : 'error');
    }
  }, [
    appName,
    cleanupAndClose,
    durationMinutes,
    logId,
    recordingPath,
    groqKey,
    profile,
    visible,
    handlePipelineProgress,
    generateQuiz,
  ]);

  runTranscriptionRef.current = runTranscription;

  const saveSessionQuickly = useCallback(async (): Promise<boolean> => {
    if (!analysis) return false;
    if (subjectSelectionRequired && !selectedSubjectName) {
      Alert.alert('Subject required', 'Choose the lecture subject before saving this lecture.');
      return false;
    }

    try {
      setIsSaving(true);
      handlePipelineProgress({
        stage: 'saving',
        message: 'Generating lecture note',
        detail: 'Turning the transcript into an ADHD-friendly study note',
        percent: 94,
      });
      const finalConfidence = userConfidence ?? analysis.estimatedConfidence;
      const analysisWithConfidence =
        finalConfidence === analysis.estimatedConfidence
          ? analysis
          : { ...analysis, estimatedConfidence: finalConfidence };
      const resolvedSubjectName = selectedSubjectName ?? analysisWithConfidence.subject;
      const analysisToSave =
        resolvedSubjectName === analysisWithConfidence.subject
          ? analysisWithConfidence
          : { ...analysisWithConfidence, subject: resolvedSubjectName };

      let noteToSave: string;
      try {
        noteToSave = await generateADHDNote(analysisToSave);
      } catch (e) {
        console.warn('[LectureReturn] ADHD note generation failed, using quick note:', e);
        noteToSave = buildQuickLectureNote(analysisToSave);
      }

      // If the note is still empty/very short, fall back to summary or transcript content
      if (!noteToSave || noteToSave.trim().length < 10) {
        console.warn('[LectureReturn] Note is too short, falling back to summary/transcript.');
        if (analysisToSave.lectureSummary && analysisToSave.lectureSummary.trim().length >= 10) {
          noteToSave = analysisToSave.lectureSummary.trim();
        } else if (analysisToSave.transcript && analysisToSave.transcript.trim().length >= 10) {
          // Use first 500 chars of transcript as a last resort
          noteToSave = analysisToSave.transcript.trim().slice(0, 500);
        }
      }

      handlePipelineProgress({
        stage: 'saving',
        message: 'Saving lecture summary',
        detail: 'Marking topics, updating XP, and storing the note',
        percent: 98,
      });
      await saveLectureAnalysisQuick({
        analysis: analysisToSave,
        appName,
        durationMinutes,
        logId,
        embedding: analysis.embedding,
        noteOverride: noteToSave,
        recordingPath: recordingPath ?? undefined,
      });
      await updateSessionNoteEnhancementStatus(logId, 'completed');

      setAnalysis(analysisToSave);
      setSessionSaved(true);
      setActiveStage(null);
      setStageMessage('');
      setStageDetail('');
      setProgressPercent(100);
      return true;
    } catch (e: unknown) {
      console.warn('[LectureReturn] save error:', e);
      setActiveStage(null);
      setStageMessage('');
      setStageDetail('');
      const errMsg = e instanceof Error ? e.message : 'Failed while saving lecture note';
      setErrorMsg(`${errMsg}. Audio has been preserved for retry.`);
      setPhase('error');
      return false;
    } finally {
      setIsSaving(false);
    }
  }, [
    analysis,
    recordingPath,
    userConfidence,
    subjectSelectionRequired,
    selectedSubjectName,
    appName,
    durationMinutes,
    logId,
    handlePipelineProgress,
  ]);

  const handleMarkStudied = useCallback(async () => {
    const saved = await saveSessionQuickly();
    if (saved) {
      await cleanupAndClose();
    }
  }, [saveSessionQuickly, cleanupAndClose]);

  const handleMarkAndQuiz = useCallback(async () => {
    const saved = await saveSessionQuickly();
    if (saved) {
      setCurrentQ(0);
      setSelected(null);
      setShowExpl(false);
      setScore(0);
      setPhase('quiz');
    }
  }, [saveSessionQuickly]);

  const handleSaveAndClose = useCallback(async () => {
    const saved = await saveSessionQuickly();
    if (saved) {
      await cleanupAndClose();
    }
  }, [saveSessionQuickly, cleanupAndClose]);

  const handleSelectAnswer = useCallback(
    (idx: number) => {
      if (selected !== null) return;
      const q = quizQuestions[currentQ];
      if (!q) return;
      setSelected(idx);
      setShowExpl(true);
      if (idx === q.correctIndex) {
        setScore((s) => s + 1);
      }
    },
    [selected, quizQuestions, currentQ],
  );

  const handleNextQuestion = useCallback(async () => {
    if (currentQ < quizQuestions.length - 1) {
      setCurrentQ((c) => c + 1);
      setSelected(null);
      setShowExpl(false);
    } else {
      const bonusXp = score * 15;
      if (bonusXp > 0) await profileRepository.addXp(bonusXp);
      setPhase('quiz_done');
    }
  }, [currentQ, quizQuestions.length, score]);

  const handleCancelTranscription = useCallback(() => {
    Alert.alert(
      'Cancel transcription?',
      'Processing will stop in the UI. Audio is preserved and can be retried later.',
      [
        { text: 'Keep processing', style: 'cancel' },
        {
          text: 'Cancel',
          style: 'destructive',
          onPress: () => {
            cancelRequestedRef.current = true;
            setActiveStage(null);
            setStageMessage('');
            setStageDetail('');
            setPhase('intro');
            void updateSessionTranscriptionStatus(
              logId,
              'pending',
              'Transcription cancelled by user',
            );
            void cleanupAndClose();
          },
        },
      ],
    );
  }, [logId, cleanupAndClose]);

  const handleSkip = useCallback(() => {
    if (phase === 'intro' || phase === 'transcribing') {
      setIsExpanded(false);
      return;
    }
    void cleanupAndClose();
  }, [phase, cleanupAndClose]);

  // Effects
  useEffect(() => {
    if (visible && canTranscribe && !transcriptionStartedRef.current) {
      if (__DEV__) {
        console.log('[LectureReturn] Scheduling auto transcription', {
          logId,
          appName,
          recordingPath,
        });
      }
      autoStartTimeoutFiredRef.current = false;
      transcriptionStartedRef.current = true;
      setIsExpanded(false);
      const delay = setTimeout(() => {
        autoStartTimeoutFiredRef.current = true;
        void runTranscriptionRef.current?.();
      }, 150);
      return () => {
        clearTimeout(delay);
        if (!autoStartTimeoutFiredRef.current) {
          transcriptionStartedRef.current = false;
        }
      };
    } else if (visible && !recordingPath) {
      void updateSessionTranscriptionStatus(logId, 'no_audio', 'No recording file captured');
      // Auto-dismiss — nothing to process
      void cleanupAndClose();
    } else if (visible && recordingPath && !groqKey && !hasHuggingFace && !hasLocalWhisper) {
      setIsExpanded(true);
      setErrorMsg(
        'No transcription engine is configured. Add Groq or Hugging Face credentials, or enable Local Transcription in Settings.',
      );
      void updateSessionTranscriptionStatus(logId, 'failed', 'No transcription engine configured');
      setPhase('error');
    }
  }, [
    visible,
    recordingPath,
    groqKey,
    hasHuggingFace,
    hasLocalWhisper,
    canTranscribe,
    logId,
    appName,
    cleanupAndClose,
  ]);

  useEffect(() => {
    if (!visible) {
      setPhase('intro');
      setAnalysis(null);
      setErrorMsg('');
      setIsExpanded(false);
      setActiveStage(null);
      setStageMessage('');
      setStageDetail('');
      setProgressPercent(0);
      setProgressStep(null);
      setProgressTotalSteps(null);
      setProgressAttempt(null);
      setProgressMaxAttempts(null);
      setProgressProvider(null);
      setStageStartedAt(null);
      setProgressHistory([]);
      setTranscriptionCompleted(false);
      setSessionSaved(false);
      setIsSaving(false);
      setUserConfidence(null);
      setQuizQuestions([]);
      setQuizLoading(false);
      setCurrentQ(0);
      setSelected(null);
      setShowExpl(false);
      setScore(0);
      lastProgressSignatureRef.current = '';
      transcriptionStartedRef.current = false;
      autoStartTimeoutFiredRef.current = false;
      cancelRequestedRef.current = false;
      if (stallCheckIntervalRef.current) {
        clearInterval(stallCheckIntervalRef.current);
        stallCheckIntervalRef.current = null;
      }
    }
  }, [visible]);

  // Cleanup stall-check interval on unmount to prevent leaks
  useEffect(() => {
    return () => {
      if (stallCheckIntervalRef.current) {
        clearInterval(stallCheckIntervalRef.current);
        stallCheckIntervalRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    if (!visible) return;
    if (phase === 'quiz' || phase === 'quiz_done') {
      setIsExpanded(true);
    }
  }, [phase, visible]);

  return {
    phase,
    analysis,
    setAnalysis,
    errorMsg,
    isExpanded,
    setIsExpanded,
    activeStage,
    stageMessage,
    stageDetail,
    progressPercent,
    progressStep,
    progressTotalSteps,
    progressAttempt,
    progressMaxAttempts,
    progressProvider,
    stageStartedAt,
    progressHistory,
    transcriptionCompleted,
    sessionSaved,
    isSaving,
    userConfidence,
    setUserConfidence,
    quizQuestions,
    quizLoading,
    currentQ,
    selected,
    showExpl,
    score,
    canTranscribe,
    subjectSelectionRequired,
    selectedSubjectName,
    setSelectedSubjectName,
    runTranscription,
    handleCancelTranscription,
    handleMarkStudied,
    handleMarkAndQuiz,
    handleSaveAndClose,
    handleSelectAnswer,
    handleNextQuestion,
    handleSkip,
    cleanupAndClose,
  };
}

import React from 'react';
import { View, useWindowDimensions } from 'react-native';

const TABLET_BREAKPOINT = 600;

const SPACING_FACTOR = 1.8;
const FONT_FACTOR = 1.3;
const SIZE_FACTOR = 1.4;

export function useResponsive() {
  const { width, height } = useWindowDimensions();
  const shortestEdge = Math.min(width, height);
  const isTablet = shortestEdge >= TABLET_BREAKPOINT;
  const isLandscape = width > height;
  // Portrait tablets: cap at 800. Landscape: use 95% of screen width so it fills the device.
  const maxContentWidth = isTablet
    ? isLandscape
      ? Math.round(width * 0.95)
      : Math.min(800, Math.round(width * 0.95))
    : undefined;

  const s = isTablet
    ? (value: number) => Math.round(value * SPACING_FACTOR)
    : (value: number) => value;
  const f = isTablet
    ? (value: number) => Math.round(value * FONT_FACTOR)
    : (value: number) => value;
  const sz = isTablet
    ? (value: number) => Math.round(value * SIZE_FACTOR)
    : (value: number) => value;

  return { s, f, sz, isTablet, isLandscape, maxContentWidth };
}

export function ResponsiveContainer({
  children,
  style,
  testID,
}: {
  children: React.ReactNode;
  style?: any;
  testID?: string;
}) {
  const { isTablet, maxContentWidth } = useResponsive();

  return React.createElement(
    View,
    {
      style: [
        { flex: 1, width: '100%' },
        isTablet && { maxWidth: maxContentWidth, alignSelf: 'center' as const },
        style,
      ],
      testID,
    },
    children,
  );
}

import { useCallback, useEffect, useRef, useState } from 'react';
import { useIsFocused } from '@react-navigation/native';
import AsyncStorage from '@react-native-async-storage/async-storage';

/**
 * Persist and restore scroll position for FlatList/ScrollView across app backgrounding.
 *
 * Usage:
 *   const { onScroll, onContentSizeChange, listRef } = useScrollRestoration('notes-vault');
 *   <FlatList ref={listRef} onScroll={onScroll} onContentSizeChange={onContentSizeChange} ... />
 */
export function useScrollRestoration(key: string) {
  const listRef = useRef<any>(null);
  const isFocused = useIsFocused();
  const scrollY = useRef(0);
  const saveTimerRef = useRef<ReturnType<typeof setTimeout>>(undefined!);

  const saveScrollPosition = useCallback(async () => {
    if (scrollY.current > 0) {
      try {
        await AsyncStorage.setItem(`@scroll:${key}`, String(scrollY.current));
      } catch {
        // silent
      }
    }
  }, [key]);

  // Restore on mount / focus
  useEffect(() => {
    if (!isFocused || !listRef.current) return;

    const restore = async () => {
      try {
        const saved = await AsyncStorage.getItem(`@scroll:${key}`);
        if (saved && listRef.current) {
          const y = parseInt(saved, 10);
          if (y > 0) {
            setTimeout(() => {
              listRef.current?.scrollToOffset?.({ offset: y, animated: false });
              listRef.current?.scrollTo?.({ y, animated: false });
            }, 200);
          }
        }
      } catch {
        // silent
      }
    };
    restore();
  }, [key, isFocused]);

  // Save on blur
  useEffect(() => {
    if (!isFocused) {
      void saveScrollPosition();
    }
  }, [isFocused, saveScrollPosition]);

  const onScroll = useCallback((event: any) => {
    scrollY.current = event.nativeEvent.contentOffset.y;
  }, []);

  const onContentSizeChange = useCallback(() => {
    if (scrollY.current === 0) {
      saveTimerRef.current = setTimeout(() => {
        void saveScrollPosition();
      }, 300);
    }
  }, [saveScrollPosition]);

  useEffect(() => {
    return () => {
      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    };
  }, []);

  return { onScroll, onContentSizeChange, listRef };
}

/**
 * Persist a text input value across app backgrounding.
 *
 * Usage:
 *   const [search, setSearch] = usePersistedInput('notes-vault-search', '');
 */
export function usePersistedInput(
  key: string,
  initialValue: string = '',
): [string, (v: string) => void] {
  const [value, setValue] = useState(initialValue);
  const initialized = useRef(false);

  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;

    const load = async () => {
      try {
        const saved = await AsyncStorage.getItem(`@input:${key}`);
        if (saved !== null) setValue(saved);
      } catch {
        // silent
      }
    };
    void load();
  }, [key]);

  const saveRef = useRef<ReturnType<typeof setTimeout>>(undefined!);

  const setAndSave = useCallback(
    (next: string) => {
      setValue(next);
      if (saveRef.current) clearTimeout(saveRef.current);
      saveRef.current = setTimeout(async () => {
        try {
          await AsyncStorage.setItem(`@input:${key}`, next);
        } catch {
          // silent
        }
      }, 300);
    },
    [key],
  );

  useEffect(() => {
    return () => {
      if (saveRef.current) clearTimeout(saveRef.current);
    };
  }, []);

  return [value, setAndSave];
}

