              ]}
            >
              <View style={styles.proofIconContainer}>
                <Ionicons name="alert-circle-outline" size={32} color={n.colors.error} />
                <Animated.View
                  style={[
                    styles.proofPulseRing,
                    {
                      opacity: proofGlowAnim,
                      transform: [
                        {
                          scale: proofGlowAnim.interpolate({
                            inputRange: [0, 1],
                            outputRange: [1, 1.3],
