              Swipe left: Again · Swipe right: Good · Swipe up: Easy
            </LinearText>
          </View>
        )}

        {/* Controls */}
        <View style={styles.controls}>
          {isFlipped ? (
            <View style={styles.ratings}>
              {RATINGS.map((r) => (
                <LinearButton
                  key={r.label}
