                            Add to syllabus
                          </LinearText>
                        )}
                      </TouchableOpacity>
                    </View>
                  </LinearSurface>
                );
              })}
            </View>
          ) : null}

          {isInitialLoad ? (
            <SyllabusSkeleton />
          ) : (
            <FlatList
              data={filteredSubjects}
              extraData={entryComplete}
              keyExtractor={keyExtractor}
              keyboardDismissMode="on-drag"
              contentContainerStyle={styles.list}
              removeClippedSubviews={true}
              initialNumToRender={6}
              maxToRenderPerBatch={6}
              windowSize={5}
              updateCellsBatchingPeriod={50}
              onRefresh={async () => {
                setRefreshing(true);
                await loadData();
                setRefreshing(false);
              }}
              refreshing={refreshing}
              ListHeaderComponent={listHeaderComponent}
              ListEmptyComponent={
                <View style={styles.emptyState}>
                  <LinearText variant="body" tone="secondary" style={styles.emptyTitle}>
                    {searchLower.length >= 2
                      ? 'No subjects or topics matched'
                      : 'No subjects matched'}
                  </LinearText>
                  <LinearText variant="caption" tone="muted" style={styles.emptySub}>
                    Try a different subject name, short code, or topic keyword.
                  </LinearText>
                </View>
              }
              renderItem={renderSubjectItem}
            />
          )}
        </ResponsiveContainer>
      </ScreenMotion>
    </SafeAreaView>
  );
}

