      const { text, modelUsed } =
        backend === 'local'
          ? await attemptLocalLLM(messages, profile.localModelPath!, true)
          : await attemptCloudLLM(
              messages,
              orKey,
              true,
              groqKey,
              options?.chosenModel,
              geminiKey,
              geminiFallbackKey,
              cfAccountId,
              cfApiToken,
              deepseekKey,
