  if (_launchInProgress) return false;
  _launchInProgress = true;
  try {
    return await _launchMedicalAppInner(appKey, faceTracking, options);
  } finally {
    _launchInProgress = false;
  }
}

async function _launchMedicalAppInner(
  appKey: SupportedMedicalApp,
  faceTracking: boolean,
  options?: LaunchMedicalAppOptions,
): Promise<boolean> {
  const app = MEDICAL_APP_SCHEMES[appKey];
  if (Platform.OS !== 'android') return false;

  if (MOCK_EXTERNAL_LECTURE_AUDIO_ENABLED) {
    return launchMockLectureAudio(app.name, faceTracking, options);
  }

  let targetPackage = app.androidStore;
  let installed = await isAppInstalled(targetPackage);

  if (appKey === 'youtube') {
    installed = false;
    for (const pkg of YOUTUBE_PREFERRED_PACKAGES) {
      if (await isAppInstalled(pkg)) {
        targetPackage = pkg;
        installed = true;
        break;
      }
    }
  }

  let logId: number | undefined;

  if (installed) {
    try {
      let recordingPath: string | null = null;

      const micGranted = await requestRecordingPermissions();
      if (!micGranted) {
        Alert.alert(
          'Microphone Required',
          'Guru needs microphone access to capture the lecture audio while you use another app.',
        );
        return false;
      }

      const hasOverlay = await ensureOverlayPermission();
      if (!hasOverlay) {
        // user was likely already alerted by ensureOverlayPermission
        return false;
      }

      options?.onMicUsed?.();
      try {
        const deepgramKey = options?.deepgramKey?.trim();
        const groqKey = options?.groqKey?.trim();
        recordingPath = await startExternalRecordingWithFallback(
          deepgramKey || undefined,
          groqKey || undefined,
        );
        if (!recordingPath) {
          alertRecordingStartFailed();
          return false;
        }
        const huggingFaceToken = options?.huggingFaceToken?.trim();
        const localWhisperPath = options?.localWhisperPath?.trim();
        startRecordingHealthCheck(
          recordingPath,
          app.name,
          groqKey || huggingFaceToken || localWhisperPath
            ? {
                groqKey: groqKey || undefined,
                huggingFaceToken: huggingFaceToken || undefined,
                huggingFaceModel: options?.huggingFaceModel,
                localWhisperPath: localWhisperPath || undefined,
              }
            : undefined,
        );
        logId = await startExternalAppSession(app.name, recordingPath);
      } catch (e) {
        if (recordingPath) {
          try {
            await nativeStopRecording();
          } catch {
            /* ignore cleanup errors */
          }
        }
        console.warn('[AppLauncher] Recording start failed:', e);
        alertRecordingStartFailed();
        return false;
      }

      try {
        const { profile } = useAppStore.getState();
        const overlayTimeout = new Promise<never>((_, reject) =>
          setTimeout(() => reject(new Error('Overlay start timed out')), 5000),
        );
        await Promise.race([
          showOverlay(
            app.name,
            faceTracking,
            profile?.pomodoroEnabled ?? true,
            profile?.pomodoroIntervalMinutes ?? 20,
          ),
          overlayTimeout,
        ]);
        await new Promise((r) => setTimeout(r, OVERLAY_START_DELAY_MS));
      } catch (overlayErr: unknown) {
        console.error('[AppLauncher] Overlay failed:', overlayErr);
        const msg =
          overlayErr instanceof Error ? overlayErr.message : 'Unknown overlay error';
        throw new Error(`Overlay failed: ${msg}`, { cause: overlayErr });
      }

      const opened = await launchApp(targetPackage);
      if (opened) {
        return true;
      } else {
        throw new Error(`Could not launch ${app.name}.`);
      }
    } catch (err: any) {
      console.error('[AppLauncher] Launch sequence failed:', err);
      Alert.alert('Launch Error', `Failed to open ${app.name}: ${err?.message || 'Unknown error'}`);
      await cleanupAbortedLaunch(
        logId,
        'Launch failed before lecture app opened',
        err?.message || 'Launch failed before lecture app opened',
        '[AppLauncher] Failed to stop recording after launch error:',
        '[AppLauncher] Failed to finalize aborted session:',
        '[AppLauncher] Failed to hide overlay after launch error:',
      );
      return false;
    }
  }

  try {
    await Linking.openURL(`market://details?id=${app.androidStore}`);
  } catch (marketErr) {
    console.warn('[AppLauncher] Market link failed, trying browser:', marketErr);
    try {
      await Linking.openURL(`https://play.google.com/store/apps/details?id=${app.androidStore}`);
    } catch (browserErr) {
      console.error('[AppLauncher] Browser link also failed:', browserErr);
      Alert.alert('Error', 'Could not open Play Store to install the app.');
    }
  }
  return false;
}

async function launchMockLectureAudio(
  appName: string,
  faceTracking: boolean,
  options?: LaunchMedicalAppOptions,
): Promise<boolean> {
  let logId: number | undefined;
  try {
    const micGranted = await requestRecordingPermissions();
    if (!micGranted) {
      Alert.alert(
        'Microphone Required',
        'Guru needs microphone access to capture the mock lecture audio.',
      );
      return false;
    }

    const hasOverlay = await ensureOverlayPermission();
    if (!hasOverlay) return false;

    options?.onMicUsed?.();
    const deepgramKey = options?.deepgramKey?.trim();
    const groqKey = options?.groqKey?.trim();
    const recordingPath = await startExternalRecordingWithFallback(
      deepgramKey || undefined,
      groqKey || undefined,
    );
    if (!recordingPath) {
      alertRecordingStartFailed();
      return false;
    }

    const huggingFaceToken = options?.huggingFaceToken?.trim();
    const localWhisperPath = options?.localWhisperPath?.trim();
    startRecordingHealthCheck(
      recordingPath,
      `${appName} (Mock Audio)`,
      groqKey || huggingFaceToken || localWhisperPath
        ? {
            groqKey: groqKey || undefined,
            huggingFaceToken: huggingFaceToken || undefined,
            huggingFaceModel: options?.huggingFaceModel,
            localWhisperPath: localWhisperPath || undefined,
          }
        : undefined,
    );
    logId = await startExternalAppSession(`${appName} (Mock Audio)`, recordingPath);

    const { profile } = useAppStore.getState();
    await showOverlay(
      `${appName} Mock`,
      faceTracking,
      profile?.pomodoroEnabled ?? true,
      profile?.pomodoroIntervalMinutes ?? 20,
    );
    await new Promise((r) => setTimeout(r, 600));

    await Linking.openURL(MOCK_EXTERNAL_LECTURE_AUDIO_URL);
    return true;
  } catch (err: any) {
    console.error('[AppLauncher] Mock lecture launch failed:', err);
    Alert.alert(
      'Mock Lecture Launch Error',
      `Failed to open mock lecture audio: ${err?.message || 'Unknown error'}`,
    );
    await cleanupAbortedLaunch(
      logId,
      'Mock lecture launch failed',
      err?.message || 'Mock lecture launch failed',
      '[AppLauncher] Failed to stop recording after mock launch error:',
      '[AppLauncher] Failed to finalize mock session:',
      '[AppLauncher] Failed to hide overlay after mock launch error:',
    );
    return false;
  }
}

import * as FileSystem from 'expo-file-system/legacy';
import { Platform } from 'react-native';
import { profileRepository } from '../db/repositories';
import { stripFileUri } from './fileUri';
import { copyFileToPublicBackup } from '../../modules/app-launcher';

const PUBLIC_BACKUP_DIR = FileSystem.documentDirectory + 'backups/db/';

/**
 * Automatically triggers a JSON backup of the entire database
 * and saves it to public storage that survives app uninstalls.
 */
export async function runAutoPublicBackup() {
  try {
    const profile = await profileRepository.getProfile();
    if (__DEV__) console.log('[AutoBackup] Starting periodic database backup...');

    const DB_NAME = 'neet_study.db';
    const DB_PATH = FileSystem.documentDirectory + 'SQLite/' + DB_NAME;
    const backupName = `guru_auto_db_${new Date().toISOString().slice(0, 10)}.db`;

    // 1. Primary Backup: User-Selected Public/Cloud Folder (SAF)
    if (Platform.OS === 'android' && profile.backupDirectoryUri) {
      try {
        const { StorageAccessFramework } = FileSystem;
        const backupUri = await StorageAccessFramework.createFileAsync(
          profile.backupDirectoryUri,
          backupName,
          'application/octet-stream',
        );
        const dbBase64 = await FileSystem.readAsStringAsync(DB_PATH, {
          encoding: FileSystem.EncodingType.Base64,
        });
        await FileSystem.writeAsStringAsync(backupUri, dbBase64, {
          encoding: FileSystem.EncodingType.Base64,
        });
        if (__DEV__) console.log('[AutoBackup] Cloud/SAF backup successful:', backupName);
      } catch (safErr) {
        console.warn('[AutoBackup] Cloud/SAF backup failed:', safErr);
      }
    }

    // 2. Secondary Backup: Native Public Storage (Survives app uninstall)
    const success = await copyFileToPublicBackup(stripFileUri(DB_PATH), 'guru_latest.db');
    if (__DEV__) {
      if (success) console.log('[AutoBackup] Native public backup successful: guru_latest.db');
      else console.warn('[AutoBackup] Native public backup failed.');
    }
  } catch (err) {
    console.warn('[AutoBackup] Periodic backup failed:', err);
  }
}

import * as FileSystem from 'expo-file-system/legacy';
import * as DocumentPicker from 'expo-document-picker';
import { Alert } from 'react-native';
import { shareBackupFileOrAlert } from './backupShare';

const Updates = (() => {
  try {
    return require('expo-updates') as { reloadAsync: () => Promise<void> };
  } catch {
    return null;
  }
})();

const DB_NAME = 'neet_study.db';
const DB_DIR = `${FileSystem.documentDirectory}SQLite`;
const DB_PATH = `${DB_DIR}/${DB_NAME}`;
const SQLITE_HEADER = 'SQLite format 3';

async function hasSQLiteHeader(filePath: string): Promise<boolean> {
  try {
    const headerBase64 = await FileSystem.readAsStringAsync(filePath, {
      encoding: FileSystem.EncodingType.Base64,
      position: 0,
      length: 16,
    });
    const header = atob(headerBase64);
    return header.startsWith(SQLITE_HEADER);
  } catch {
    return false;
  }
}

export async function exportDatabase() {
  try {
    const fileExists = await FileSystem.getInfoAsync(DB_PATH);
    if (!fileExists?.exists) {
      Alert.alert('Error', 'Database file not found.');
      return;
    }

    // Copy to a temporary file with a readable name
    const tempPath = `${FileSystem.cacheDirectory}neet_study_backup_${new Date().toISOString().slice(0, 10)}.db`;
    await FileSystem.copyAsync({ from: DB_PATH, to: tempPath });

    await shareBackupFileOrAlert(tempPath, {
      mimeType: 'application/octet-stream',
      dialogTitle: 'Export Backup',
      unavailableAlert: {
        title: 'Error',
        message: 'Sharing is not available on this device',
      },
    });
  } catch (e) {
    if (__DEV__) console.error('Backup error', e);
    Alert.alert('Error', 'Failed to export backup.');
  }
}

export async function importDatabase() {
  try {
    const result = await DocumentPicker.getDocumentAsync({
      copyToCacheDirectory: true,
      type: '*/*',
    });

    if (result.canceled) return;

    const asset = result.assets[0];
    const tempImportPath = `${FileSystem.cacheDirectory}neet_study_import_tmp_${Date.now()}.db`;
    const rollbackPath = `${DB_PATH}.rollback_${Date.now()}.bak`;

    // Ensure SQLite dir exists first
    const dirInfo = await FileSystem.getInfoAsync(DB_DIR);
    if (!dirInfo?.exists) {
      await FileSystem.makeDirectoryAsync(DB_DIR, { intermediates: true });
    }

    // Copy selected file to temp path and validate SQLite signature
    await FileSystem.copyAsync({ from: asset.uri, to: tempImportPath });
    const validSqlite = await hasSQLiteHeader(tempImportPath);
    if (!validSqlite) {
      await FileSystem.deleteAsync(tempImportPath, { idempotent: true });
      Alert.alert('Invalid backup', 'Selected file is not a valid SQLite database backup.');
      return;
    }

    // Close current DB connection before replacing file
    try {
      const { getDb } = require('../db/database');
      const db = getDb();
      db.closeSync();
    } catch (err) {
      if (__DEV__) console.warn('[Backup] Failed to close DB before import:', err);
    }
    const { resetDbSingleton } = require('../db/database');
    resetDbSingleton();

    const existing = await FileSystem.getInfoAsync(DB_PATH);
    if (existing?.exists) {
      await FileSystem.copyAsync({ from: DB_PATH, to: rollbackPath });
    }

    try {
      await FileSystem.copyAsync({ from: tempImportPath, to: DB_PATH });
      await FileSystem.deleteAsync(tempImportPath, { idempotent: true });
      // Keep rollback until we verify the new DB is valid
    } catch (replaceError) {
      // Restore old DB if replacement fails
      const rollbackExists = await FileSystem.getInfoAsync(rollbackPath);
      if (rollbackExists?.exists) {
        await FileSystem.copyAsync({ from: rollbackPath, to: DB_PATH });
      }
      await FileSystem.deleteAsync(tempImportPath, { idempotent: true });
      await FileSystem.deleteAsync(rollbackPath, { idempotent: true });
      throw replaceError;
    }

    // Verify the imported DB can be opened and has expected tables
    try {
      const { getDb } = require('../db/database');
      const testDb = getDb();
      await testDb.getFirstAsync('SELECT COUNT(*) FROM subjects');
      // DB is valid — clean up rollback
      await FileSystem.deleteAsync(rollbackPath, { idempotent: true });
    } catch (validationError) {
      // Imported DB is corrupt — rollback
      const rollbackExists = await FileSystem.getInfoAsync(rollbackPath);
      if (rollbackExists?.exists) {
        await FileSystem.copyAsync({ from: rollbackPath, to: DB_PATH });
      }
      await FileSystem.deleteAsync(rollbackPath, { idempotent: true });
      Alert.alert(
        'Invalid Backup',
        'The backup file failed schema validation. Your original data has been restored.',
      );
      return;
    }

    Alert.alert('Success', 'Backup restored successfully! The app will now restart.', [
      {
        text: 'Restart',
        onPress: () => {
          // Force a full restart so all components get fresh DB handles
          try {
            void Updates?.reloadAsync?.();
          } catch {
            // Fallback for dev builds where Updates isn't available
            Alert.alert('Please restart the app manually.');
          }
        },
      },
    ]);
  } catch (e) {
    if (__DEV__) console.error('Import error', e);
    Alert.alert('Error', 'Failed to import backup.');
  }
}

import { EventEmitter } from 'eventemitter3';

/**
 * Global event bus for database updates.
 * Use this to notify the UI or stores when data has changed from background tasks.
 */
export const dbEvents = new EventEmitter();

export const DB_EVENT_KEYS = {
  LECTURE_SAVED: 'LECTURE_SAVED',
  TRANSCRIPT_RECOVERED: 'TRANSCRIPT_RECOVERED',
  RECORDING_RECOVERED: 'RECORDING_RECOVERED',
  PROGRESS_UPDATED: 'PROGRESS_UPDATED',
  PROFILE_UPDATED: 'PROFILE_UPDATED',
};

export function notifyDbUpdate(event: string, payload?: any) {
  if (__DEV__) console.log(`[DB_EVENT] Notifying: ${event}`);
  dbEvents.emit(event, payload);
}

export type SyncMessage =
  | { type: 'LECTURE_STARTED'; subjectId: number }
  | { type: 'LECTURE_STOPPED' }
  | { type: 'DOOMSCROLL_DETECTED' }
  | { type: 'NOTE_SAVED'; note: string }
  | { type: 'BREAK_STARTED'; durationSeconds: number }
  | { type: 'LECTURE_RESUMED' };

import { encryptPayload, decryptPayload, clearKeyCache } from './syncCrypto';
import { showToast } from '../components/Toast';

const BROKER_URL = 'wss://broker.emqx.io:8084/mqtt';
// v2 prefix: incompatible with old un-encrypted v1 clients
const ROOM_PREFIX = 'guru/v2/room/';

let client: any = null;
let currentRoomCode: string | null = null;
let mqttModule: any = null;
let mqttUnavailable = false;
const CLOCK_SKEW_TOLERANCE_MS = 5 * 60 * 1000;
const MAX_RECENT_MESSAGE_IDS = 300;
const SYNC_CONNECTION_LOST_MESSAGE = 'Device sync connection lost';
const seenMessageIds = new Map<string, number>();
const subscribers = new Map<string, (msg: SyncMessage) => void>();
let nextSubscriberId = 0;
const outgoingQueue: SyncMessage[] = [];
let isConnected = false;

export function normalizeSyncCode(code: string): string {
  return code
    .trim()
    .toUpperCase()
    .replace(/[^A-Z0-9]/g, '');
}

function notifySyncConnectionLost(): void {
  showToast(SYNC_CONNECTION_LOST_MESSAGE, 'warning');
}

function markAndCheckReplay(msgId: string, ts: number): boolean {
  const now = Date.now();
  for (const [existingId, existingTs] of seenMessageIds.entries()) {
    if (now - existingTs > CLOCK_SKEW_TOLERANCE_MS) {
      seenMessageIds.delete(existingId);
    }
  }

  if (seenMessageIds.has(msgId)) return true;
  seenMessageIds.set(msgId, ts);

  if (seenMessageIds.size > MAX_RECENT_MESSAGE_IDS) {
    const oldestKey = seenMessageIds.keys().next().value;
    if (oldestKey) seenMessageIds.delete(oldestKey);
  }

  return false;
}

async function getMqtt() {
  if (mqttModule) return mqttModule;
  if (mqttUnavailable) return null;
  try {
    // @ts-expect-error - lazy load; types may be absent if polyfills are missing
    mqttModule = require('mqtt/dist/mqtt');
    return mqttModule;
  } catch {
    mqttUnavailable = true;
    return null;
  }
}

/** Returns true if the MQTT module is loadable and sync is available */
export function isSyncAvailable(): boolean {
  if (mqttModule) return true;
  if (mqttUnavailable) return false;
  try {
    // @ts-expect-error - probe loadability only
    require('mqtt/dist/mqtt');
    return true;
  } catch {
    return false;
  }
}

let connectPromise: Promise<void> | null = null;
let activeTopic: string | null = null;
let connectingRoomCode: string | null = null;

function closeClient(): void {
  if (client) {
    try {
      client.end(true);
    } catch (error) {
      console.warn('[DeviceSyncService] Failed to end MQTT client:', error);
    }
  }
  client = null;
  currentRoomCode = null;
  activeTopic = null;
  connectPromise = null;
  connectingRoomCode = null;
  isConnected = false;
  seenMessageIds.clear();
}

async function getRoomTopic(code: string): Promise<string> {
  const cleanCode = normalizeSyncCode(code);
  const raw = new TextEncoder().encode(cleanCode + '::topic-v2');
  const hashBuffer = await globalThis.crypto.subtle.digest('SHA-256', raw);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  const hashHex = hashArray.map((b) => b.toString(16).padStart(2, '0')).join('');
  return ROOM_PREFIX + hashHex.slice(0, 16);
}

function generateSecureId(prefix: string): string {
  const bytes = globalThis.crypto.getRandomValues(new Uint8Array(4));
  const hex = Array.from(bytes)
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('');
  return prefix + '_' + hex;
}

async function ensureConnected(code: string): Promise<void> {
  const normalizedCode = normalizeSyncCode(code);
  if (!normalizedCode) {
    console.warn('[DeviceSync] Cannot connect with empty room code');
    return;
  }

  if (mqttUnavailable) {
    console.warn('[DeviceSync] MQTT module unavailable');
    return;
  }

  if (client && currentRoomCode === normalizedCode && isConnected) return;
  if (
    connectPromise &&
    (currentRoomCode === normalizedCode || connectingRoomCode === normalizedCode)
  ) {
    await connectPromise;
    return;
  }

  if (client && currentRoomCode === normalizedCode && !isConnected) {
    closeClient();
  }

  if (currentRoomCode !== normalizedCode) {
    clearKeyCache();
    closeClient();
  }

  connectingRoomCode = normalizedCode;
  connectPromise = (async () => {
    const mqtt = await getMqtt();
    if (!mqtt) {
      console.warn('[DeviceSync] MQTT module not available');
      return;
    }
    if (client && currentRoomCode === normalizedCode && isConnected) return;

    const clientId = generateSecureId('guru');
    const nextClient = mqtt.connect(BROKER_URL, {
      clientId,
      // Add connection timeout and keepalive
      connectTimeout: 10 * 1000,
      keepalive: 60,
      clean: true,
      // Reject unauthorized connections (basic auth not supported by public broker)
      // In production, use a private broker with authentication
    });

    const topic = await getRoomTopic(normalizedCode);

    nextClient.on('connect', () => {
      client = nextClient;
      isConnected = true;
      if (__DEV__) console.log('[DeviceSync] Connected to MQTT broker');
      nextClient.subscribe(topic, (err: any) => {
        if (err) {
          console.error('[DeviceSync] Failed to subscribe to topic:', err);
        } else {
          if (__DEV__) console.log('[DeviceSync] Subscribed to topic:', topic);
        }
      });

      // Flush outgoing queue
      while (outgoingQueue.length > 0) {
        const msg = outgoingQueue.shift();
        if (msg) sendSyncMessage(msg);
      }
    });

    nextClient.on('message', async (receivedTopic: string, message: any) => {
      if (receivedTopic !== topic) return;

      try {
        const decrypted = await decryptPayload(code, message.toString());
        if (!decrypted) {
          console.warn('[DeviceSync] Failed to decrypt message');
          return;
        }

        // Validate timestamp (with clock skew tolerance)
        if (decrypted.ts && Math.abs(Date.now() - decrypted.ts) > CLOCK_SKEW_TOLERANCE_MS) {
          console.warn('[DeviceSync] Message timestamp too old or from future, ignoring');
          return;
        }

        // Check for replay attacks
        if (decrypted.msgId && markAndCheckReplay(decrypted.msgId, decrypted.ts ?? Date.now())) {
          console.debug('[DeviceSync] Duplicate message detected, ignoring');
          return;
        }

        const msg = decrypted.payload as Record<string, unknown>;
        if (!msg?.type) {
          console.warn('[DeviceSync] Message missing type field');
          return;
        }

        // Validate message type
        const validTypes: string[] = [
          'LECTURE_STARTED',
          'LECTURE_STOPPED',
          'DOOMSCROLL_DETECTED',
          'NOTE_SAVED',
          'BREAK_STARTED',
          'LECTURE_RESUMED',
        ];
        if (typeof msg.type !== 'string' || !validTypes.includes(msg.type)) {
          console.warn('[DeviceSync] Unknown message type:', msg.type);
          return;
        }

        // Validate message structure based on type
        switch (msg.type) {
          case 'LECTURE_STARTED':
            if (typeof msg.subjectId !== 'number') {
              console.warn('[DeviceSync] LECTURE_STARTED missing subjectId');
              return;
            }
            break;
          case 'BREAK_STARTED':
            if (typeof msg.durationSeconds !== 'number') {
              console.warn('[DeviceSync] BREAK_STARTED missing durationSeconds');
              return;
            }
            break;
          case 'NOTE_SAVED':
            if (typeof msg.note !== 'string') {
              console.warn('[DeviceSync] NOTE_SAVED missing note string');
              return;
            }
            break;
        }

        for (const listener of subscribers.values()) {
          try {
            listener(msg as SyncMessage);
          } catch (err) {
            console.warn('[DeviceSync] subscriber callback failed:', err);
          }
        }
      } catch (err) {
        console.warn('[DeviceSync] Failed to process message:', err);
      }
    });

    nextClient.on('error', (err: any) => {
      isConnected = false;
      console.error('[DeviceSync] MQTT error:', err?.message ?? err);
      notifySyncConnectionLost();
    });

    nextClient.on('offline', () => {
      isConnected = false;
      console.warn('[DeviceSync] MQTT went offline');
      notifySyncConnectionLost();
    });

    nextClient.on('close', () => {
      isConnected = false;
      if (subscribers.size === 0 && client === nextClient) {
        client = null;
      }
      if (__DEV__) console.log('[DeviceSync] MQTT connection closed');
    });

    // Handle reconnection
    nextClient.on('reconnect', () => {
      if (__DEV__) console.log('[DeviceSync] MQTT reconnecting...');
    });

    client = nextClient;
    currentRoomCode = normalizedCode;
    activeTopic = topic;
  })();

  try {
    await connectPromise;
  } catch (err) {
    console.error('[DeviceSync] Connection failed:', err);
    throw err;
  } finally {
    connectPromise = null;
    connectingRoomCode = null;
  }
}

export function connectToRoom(code: string, onMessage: (msg: SyncMessage) => void) {
  if (!code || typeof code !== 'string' || code.trim().length === 0) {
    console.error('[DeviceSync] Invalid room code provided');
    return () => {};
  }

  const cleanCode = normalizeSyncCode(code);
  if (!cleanCode) {
    console.error('[DeviceSync] Invalid room code provided');
    return () => {};
  }

  // Validate room code format (4-16 uppercase alphanumeric after normalization)
  if (!/^[A-Z0-9]{4,16}$/.test(cleanCode)) {
    console.warn('[DeviceSync] Unusual room code format:', code);
  }

  const subscriberId = `sync_${nextSubscriberId++}`;
  subscribers.set(subscriberId, onMessage);

  ensureConnected(cleanCode).catch((err) => {
    console.warn('[DeviceSync] Failed to connect:', err);
    notifySyncConnectionLost();
  });

  return () => {
    subscribers.delete(subscriberId);
    if (subscribers.size === 0) {
      clearKeyCache();
      closeClient();
      isConnected = false;
    }
  };
}

export function sendSyncMessage(msg: SyncMessage) {
  if (!isConnected || !client || !currentRoomCode || !activeTopic) {
    if (outgoingQueue.length < 50) {
      outgoingQueue.push(msg);
    } else {
      console.warn('[DeviceSync] Outgoing queue full, dropping message');
      showToast('Sync message queue full \u2014 some messages dropped', 'warning');
    }
    return;
  }

  const code = currentRoomCode;
  // Encrypt async, then publish
  encryptPayload(code, msg)
    .then((envelope) => {
      if (client && isConnected) {
        client.publish(activeTopic, envelope, (err: any) => {
          if (err) {
            console.warn('[DeviceSync] Publish failed:', err);
            // Re-queue for retry
            if (outgoingQueue.length < 50) {
              outgoingQueue.push(msg);
            }
          }
        });
      } else {
        // Connection lost, re-queue
        if (outgoingQueue.length < 50) {
          outgoingQueue.push(msg);
        }
      }
    })
    .catch((err) => {
      console.warn('[DeviceSync] encrypt failed, dropping message:', err);
    });
}

import AsyncStorage from '@react-native-async-storage/async-storage';
import { profileRepository } from '../db/repositories';

type ExamCode = 'inicet' | 'neetpg';

