/**
 * Keep only the latest `keepPerDevice` backups per device on GDrive.
 */
export async function cleanupOldGDriveBackups(keepPerDevice: number = 3): Promise<void> {
  const accessToken = await getAccessToken();
  const backups = await listGDriveBackups();

  // Group by deviceId
  const byDevice = new Map<string, GDriveBackupMeta[]>();
  for (const b of backups) {
    const key = b.deviceId || b.deviceName || 'unknown';
    if (!byDevice.has(key)) byDevice.set(key, []);
    byDevice.get(key)!.push(b);
  }

  // For each device, sort by exportedAt and delete old ones
  for (const [, deviceBackups] of byDevice) {
    const sorted = deviceBackups.sort(
      (a, b) => new Date(b.exportedAt).getTime() - new Date(a.exportedAt).getTime(),
    );

    const toDelete = sorted.slice(keepPerDevice);
    for (const backup of toDelete) {
      try {
        await fetch(`${DRIVE_FILES_URL}/${backup.fileId}`, {
          method: 'DELETE',
          headers: { Authorization: `Bearer ${accessToken}` },
        });
      } catch (e) {
        console.warn('[GDrive] Failed to delete old backup:', backup.name, e);
      }
    }
  }
}

/** Required by https://meta.wikimedia.org/wiki/User-agent_policy — missing this yields plain-text errors starting with "Please…" and breaks JSON.parse. */
const WIKI_API_HEADERS = {
  'User-Agent': 'GuruStudyApp/1.0 (https://guru.study; help@guru.study)',
  Accept: 'application/json',
} as const;

// In-memory image cache with TTL (5 minutes). Prevents redundant network calls
// when the same topic is shown across multiple content cards in a session.
const IMAGE_CACHE_TTL_MS = 5 * 60 * 1000;
const imageCache = new Map<string, { url: string | null; expiresAt: number }>();

/** Get cached image URL or null (cache miss / expired). */
function getCachedImage(key: string): string | null | undefined {
  const entry = imageCache.get(key);
  if (!entry) return undefined;
  if (Date.now() > entry.expiresAt) {
    imageCache.delete(key);
    return undefined;
  }
  return entry.url;
}

/** Store image URL in cache (including null for "not found" to avoid repeated misses). */
function setCachedImage(key: string, url: string | null): void {
  imageCache.set(key, { url, expiresAt: Date.now() + IMAGE_CACHE_TTL_MS });
}

// #region agent log
function dbgImageService(
  hypothesisId: string,
  message: string,
  data: Record<string, unknown>,
): void {
  fetch('http://127.0.0.1:7507/ingest/f6a0734c-b45d-4770-9e51-aa07e5c2da6e', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'X-Debug-Session-Id': 'ca9385' },
    body: JSON.stringify({
      sessionId: 'ca9385',
      hypothesisId,
      location: 'imageService.ts:wikiJson',
      message,
      data,
      timestamp: Date.now(),
    }),
  }).catch(() => {});
}
// #endregion

async function wikiApiJson(res: Response, step: string): Promise<unknown | null> {
  let text: string;
  try {
    text = await res.text();
  } catch {
    return null;
  }
  const trimmed = text.trimStart();
  if (!trimmed.startsWith('{') && !trimmed.startsWith('[')) {
    // #region agent log
    dbgImageService('A', 'wiki non-json body', {
      step,
      status: res.status,
      contentType: res.headers.get('content-type') ?? '',
      prefix: trimmed.slice(0, 120),
    });
    // #endregion
    return null;
  }
  try {
    return JSON.parse(text) as unknown;
  } catch (e) {
    // #region agent log
    dbgImageService('B', 'wiki json parse error', {
      step,
      status: res.status,
      prefix: trimmed.slice(0, 120),
      err: String(e),
    });
    // #endregion
    return null;
  }
}

export async function fetchWikipediaImage(topicName: string): Promise<string | null> {
  const cacheKey = `wiki:${topicName}`;
  const cached = getCachedImage(cacheKey);
  if (cached !== undefined) return cached;

  const cleaned = topicName
    .replace(
      /^(Anatomy of|Physiology of|Pathology of|Mechanism of|Management of|Treatment of|Introduction to|Overview of)\s+/i,
      '',
    )
    .trim();

  async function searchWiki(query: string): Promise<string | null> {
    try {
      const url = `https://en.wikipedia.org/w/api.php?action=query&titles=${encodeURIComponent(query)}&prop=pageimages&format=json&pithumbsize=500&origin=*`;
      const response = await fetch(url, { headers: WIKI_API_HEADERS });
      const data = (await wikiApiJson(response, `searchWiki:${query.slice(0, 40)}`)) as {
        query?: { pages?: Record<string, { thumbnail?: { source?: string } }> };
      } | null;
      if (!data) return null;
      const pages = data?.query?.pages;
      if (!pages) return null;
      const pageId = Object.keys(pages)[0];
      if (pageId === '-1') return null;
      return pages[pageId]?.thumbnail?.source || null;
    } catch (e) {
      return null;
    }
  }

  // 1. Try exact match & cleaned match
  let url = await searchWiki(topicName);
  if (url) {
    setCachedImage(cacheKey, url);
    return url;
  }

  if (cleaned !== topicName) {
    url = await searchWiki(cleaned);
    if (url) {
      setCachedImage(cacheKey, url);
      return url;
    }
  }

  // 2. Wikipedia Search Match
  try {
    const searchUrl = `https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch=${encodeURIComponent(topicName)}&format=json&srlimit=1&origin=*`;
    const searchRes = await fetch(searchUrl, { headers: WIKI_API_HEADERS });
    const searchData = (await wikiApiJson(searchRes, 'wikiListSearch')) as {
      query?: { search?: Array<{ title?: string }> };
    } | null;
    if (!searchData) {
      throw new Error('wiki search empty or non-json');
    }
    const firstResult = searchData?.query?.search?.[0]?.title;
    if (firstResult) {
      url = await searchWiki(firstResult);
      if (url) {
        setCachedImage(cacheKey, url);
        return url;
      }
    }
  } catch (e) {
    if (__DEV__) console.debug('[imageService] Wikipedia list search failed:', e);
  }

  // 3. Wikimedia Commons Media (Files directly)
  try {
    const commonsUrl = `https://commons.wikimedia.org/w/api.php?action=query&list=search&srsearch=${encodeURIComponent(cleaned)}&srnamespace=6&format=json&origin=*&srlimit=1`;
    const commonsRes = await fetch(commonsUrl, { headers: WIKI_API_HEADERS });
    const commonsData = (await wikiApiJson(commonsRes, 'commonsListSearch')) as {
      query?: { search?: Array<{ title?: string }> };
    } | null;
    if (!commonsData) {
      throw new Error('commons search empty or non-json');
    }
    const fileTitle = commonsData?.query?.search?.[0]?.title;

    if (fileTitle) {
      const fileInfoUrl = `https://commons.wikimedia.org/w/api.php?action=query&titles=${encodeURIComponent(fileTitle)}&prop=imageinfo&iiprop=url&iiurlwidth=500&format=json&origin=*`;
      const fileInfoRes = await fetch(fileInfoUrl, { headers: WIKI_API_HEADERS });
      const fileInfoData = (await wikiApiJson(fileInfoRes, 'commonsImageInfo')) as {
        query?: { pages?: Record<string, { imageinfo?: Array<{ thumburl?: string }> }> };
      } | null;
      if (!fileInfoData) {
        throw new Error('commons imageinfo empty or non-json');
      }
      const pages = fileInfoData?.query?.pages;
      if (pages) {
        const pageId = Object.keys(pages)[0];
        if (pageId !== '-1') {
          const thumbUrl = pages[pageId]?.imageinfo?.[0]?.thumburl || null;
          if (thumbUrl) setCachedImage(cacheKey, thumbUrl);
          return thumbUrl;
        }
      }
    }
  } catch (e) {
    if (__DEV__) console.debug('[imageService] Commons fallback failed:', e);
  }

  // 4. Ultimate Fallback: Return null to avoid rendering random irrelevant images.
  setCachedImage(cacheKey, null);
  return null;
}

import * as FileSystem from 'expo-file-system/legacy';
import * as DocumentPicker from 'expo-document-picker';
import type { SQLiteDatabase } from 'expo-sqlite';
import { getDb } from '../db/database';
import { getAiCacheDb } from '../db/aiCacheDatabase';
import { shareBackupFileOrAlert } from './backupShare';

const BACKUP_VERSION = 4;
const JSON_BACKUP_TABLES = [
  'user_profile',
  'topic_progress',
  'daily_log',
  'lecture_notes',
  'ai_cache',
  'sessions',
  'external_app_logs',
  'brain_dumps',
  'lecture_learned_topics',
  'generated_study_images',
  'topic_suggestions',
  'chat_history',
  'guru_chat_session_memory',
  'daily_agenda',
  'plan_events',
  'offline_ai_queue',
] as const;

/** Child tables before parents (FK-safe clears during restore). */
const JSON_BACKUP_DELETE_ORDER: BackupTableName[] = [
  'external_app_logs',
  'ai_cache',
  'topic_progress',
  'sessions',
  'lecture_learned_topics',
  'generated_study_images',
  'topic_suggestions',
  'chat_history',
  'guru_chat_session_memory',
  'daily_agenda',
  'plan_events',
  'offline_ai_queue',
  'lecture_notes',
  'daily_log',
  'brain_dumps',
  'user_profile',
];

const JSON_BACKUP_RESTORE_ORDER: BackupTableName[] = [
  'daily_log',
  'lecture_notes',
  'topic_progress',
  'ai_cache',
  'sessions',
  'external_app_logs',
  'lecture_learned_topics',
  'generated_study_images',
  'topic_suggestions',
  'chat_history',
  'guru_chat_session_memory',
  'daily_agenda',
  'plan_events',
  'offline_ai_queue',
  'brain_dumps',
  'user_profile',
];

type BackupTableName = (typeof JSON_BACKUP_TABLES)[number];
type BackupRow = Record<string, unknown>;

function connectionForTable(table: BackupTableName, main: SQLiteDatabase): SQLiteDatabase {
  return table === 'ai_cache' ? getAiCacheDb() : main;
}
type BackupTableData = Record<BackupTableName, BackupRow[]>;
type SubjectBackupRef = { shortCode: string; name: string };
type TopicBackupRef = { subjectShortCode: string; topicName: string };
type BackupMetadata = {
  subjects: SubjectBackupRef[];
  topics: TopicBackupRef[];
};

function isRecord(value: unknown): value is Record<string, unknown> {
  return !!value && typeof value === 'object' && !Array.isArray(value);
}

function createTopicRefKey(ref: TopicBackupRef): string {
  return `${ref.subjectShortCode}::${ref.topicName}`.toLowerCase();
}

function parseJsonNumberArray(value: unknown): number[] {
  if (Array.isArray(value)) {
    return value.filter(
      (entry): entry is number => typeof entry === 'number' && Number.isFinite(entry),
    );
  }
  if (typeof value !== 'string') return [];
  try {
    const parsed = JSON.parse(value);
    return Array.isArray(parsed)
      ? parsed.filter(
          (entry): entry is number => typeof entry === 'number' && Number.isFinite(entry),
        )
      : [];
  } catch (err) {
    console.warn('[Backup] Failed to parse number array:', err);
    return [];
  }
}

function toBindValue(val: unknown): string | number | null {
  if (val === null || val === undefined) return null;
  if (typeof val === 'boolean') return val ? 1 : 0;
  if (typeof val === 'object') return JSON.stringify(val);
  return val as string | number;
}

export async function exportJsonBackup(): Promise<boolean> {
  const db = getDb();
  const [subjects, topics] = await Promise.all([
    db.getAllAsync<{ id: number; name: string; short_code: string }>(
      'SELECT id, name, short_code FROM subjects',
    ),
    db.getAllAsync<{ id: number; name: string; subject_id: number; short_code: string }>(
      `SELECT t.id, t.name, t.subject_id, s.short_code
         FROM topics t
         JOIN subjects s ON t.subject_id = s.id`,
    ),
  ]);
  const subjectRefsById = new Map<number, SubjectBackupRef>(
    subjects.map((subject) => [subject.id, { shortCode: subject.short_code, name: subject.name }]),
  );
  const topicRefsById = new Map<number, TopicBackupRef>(
    topics.map((topic) => [
      topic.id,
      { subjectShortCode: topic.short_code, topicName: topic.name },
    ]),
  );

  const serializeBackupRow = (table: BackupTableName, row: BackupRow): BackupRow => {
    const nextRow = { ...row };

    if (table === 'topic_progress' || table === 'ai_cache') {
      const topicId = typeof nextRow.topic_id === 'number' ? nextRow.topic_id : null;
      const topicRef = topicId ? topicRefsById.get(topicId) : null;
      if (topicRef) {
        nextRow.topic_ref = topicRef;
      }
    }

    if (table === 'lecture_notes') {
      const subjectId = typeof nextRow.subject_id === 'number' ? nextRow.subject_id : null;
      const subjectRef = subjectId ? subjectRefsById.get(subjectId) : null;
      if (subjectRef) {
        nextRow.subject_ref = subjectRef;
      }
    }

    if (table === 'sessions') {
      const plannedRefs = parseJsonNumberArray(nextRow.planned_topics)
        .map((topicId) => topicRefsById.get(topicId))
        .filter((ref): ref is TopicBackupRef => !!ref);
      const completedRefs = parseJsonNumberArray(nextRow.completed_topics)
        .map((topicId) => topicRefsById.get(topicId))
        .filter((ref): ref is TopicBackupRef => !!ref);
      nextRow.planned_topic_refs = plannedRefs;
      nextRow.completed_topic_refs = completedRefs;
    }

    if (table === 'generated_study_images' || table === 'lecture_learned_topics') {
      const topicId = typeof nextRow.topic_id === 'number' ? nextRow.topic_id : null;
      const topicRef = topicId ? topicRefsById.get(topicId) : null;
      if (topicRef) {
        nextRow.topic_ref = topicRef;
      }
    }

    if (table === 'topic_suggestions') {
      const subjectId = typeof nextRow.subject_id === 'number' ? nextRow.subject_id : null;
      const subjectRef = subjectId ? subjectRefsById.get(subjectId) : null;
      if (subjectRef) {
        nextRow.subject_ref = subjectRef;
      }
      const approvedId =
        typeof nextRow.approved_topic_id === 'number' ? nextRow.approved_topic_id : null;
      const approvedRef = approvedId ? topicRefsById.get(approvedId) : null;
      if (approvedRef) {
        nextRow.approved_topic_ref = approvedRef;
      }
    }

    return nextRow;
  };

  const tables = {} as BackupTableData;
  for (const table of JSON_BACKUP_TABLES) {
    const conn = connectionForTable(table, db);
    const rows = await conn.getAllAsync<BackupRow>(`SELECT * FROM ${table}`);
    tables[table] = rows.map((row) => serializeBackupRow(table, row));
  }

  const backup = {
    version: BACKUP_VERSION,
    exportedAt: new Date().toISOString(),
    tables,
    metadata: {
      subjects: Array.from(subjectRefsById.values()),
      topics: Array.from(topicRefsById.values()),
    },
  };

  const json = JSON.stringify(backup, null, 2);
  const dateStr = new Date().toISOString().slice(0, 10);
  const filePath = `${FileSystem.cacheDirectory}guru_backup_${dateStr}.json`;
  await FileSystem.writeAsStringAsync(filePath, json);

  try {
    await shareBackupFileOrAlert(filePath, {
      mimeType: 'application/json',
      dialogTitle: 'Save Guru Backup',
    });
    return true;
  } catch (err) {
    console.error('[Backup] Sharing failed:', err);
    return false;
  }
}

export async function importJsonBackup(): Promise<{ ok: boolean; message: string }> {
  const result = await DocumentPicker.getDocumentAsync({
    type: 'application/json',
    copyToCacheDirectory: true,
  });
  if (result.canceled || !result.assets?.[0]) return { ok: false, message: 'Cancelled' };

  const content = await FileSystem.readAsStringAsync(result.assets[0].uri);
  let backup: Record<string, unknown>;
  try {
    backup = JSON.parse(content);
    if (!backup || typeof backup !== 'object') throw new Error('Not an object');
  } catch (err) {
    console.error('[Backup] JSON parse failed during import:', err);
    return { ok: false, message: 'Invalid JSON file' };
  }

  if (!backup.version) {
    return { ok: false, message: 'Invalid backup format — missing version' };
  }
  if (typeof backup.version === 'number' && backup.version > BACKUP_VERSION) {
    return { ok: false, message: 'Backup was made with a newer version of the app' };
  }

  const db = getDb();
  const [subjects, topics] = await Promise.all([
    db.getAllAsync<{ id: number; name: string; short_code: string }>(
      'SELECT id, name, short_code FROM subjects',
    ),
    db.getAllAsync<{ id: number; name: string; subject_id: number; short_code: string }>(
      `SELECT t.id, t.name, t.subject_id, s.short_code
         FROM topics t
         JOIN subjects s ON t.subject_id = s.id`,
    ),
  ]);

  const subjectIdsByShortCode = new Map<string, number>(
    subjects.map((subject) => [subject.short_code.toLowerCase(), subject.id]),
  );
  const topicIdsByRefKey = new Map<string, number>(
    topics.map((topic) => [
      createTopicRefKey({ subjectShortCode: topic.short_code, topicName: topic.name }),
      topic.id,
    ]),
  );

  const tablesFromBackup: Partial<Record<BackupTableName, BackupRow[]>> =
    backup.tables && typeof backup.tables === 'object' ? backup.tables : {};
  const restoredCounts: Partial<Record<BackupTableName, number>> = {};

  const getColumns = async (table: string): Promise<string[]> => {
    try {
      const conn = table === 'ai_cache' ? getAiCacheDb() : db;
      const info = await conn.getAllAsync<{ name: string }>(`PRAGMA table_info(${table})`);
      return info.map((c: { name: string }) => c.name);
    } catch (err) {
      console.error(`[Backup] Failed to get columns for ${table}:`, err);
      return [];
    }
  };

  const sanitizeRow = (table: BackupTableName, rawRow: BackupRow): BackupRow | null => {
    const row = { ...rawRow };
    delete row.topic_ref;
    delete row.subject_ref;
    delete row.approved_topic_ref;
    delete row.planned_topic_refs;
    delete row.completed_topic_refs;

    if (table === 'topic_progress' || table === 'ai_cache') {
      const ref = rawRow.topic_ref as Record<string, unknown> | undefined;
      if (ref && typeof ref.subjectShortCode === 'string' && typeof ref.topicName === 'string') {
        const tid = topicIdsByRefKey.get(createTopicRefKey(ref as unknown as TopicBackupRef));
        if (tid) row.topic_id = tid;
        else return null;
      }
    }
    if (table === 'lecture_notes') {
      const ref = rawRow.subject_ref as Record<string, unknown> | undefined;
      if (ref && typeof ref.shortCode === 'string') {
        const sid = subjectIdsByShortCode.get(ref.shortCode.toLowerCase());
        if (sid) row.subject_id = sid;
        else row.subject_id = null;
      }
    }
    if (table === 'sessions') {
      const pRefs = rawRow.planned_topic_refs as Array<Record<string, unknown>> | undefined;
      if (Array.isArray(pRefs)) {
        row.planned_topics = JSON.stringify(
          pRefs
            .map((r) => topicIdsByRefKey.get(createTopicRefKey(r as unknown as TopicBackupRef)))
            .filter((id) => !!id),
        );
      }
      const cRefs = rawRow.completed_topic_refs as Array<Record<string, unknown>> | undefined;
      if (Array.isArray(cRefs)) {
        row.completed_topics = JSON.stringify(
          cRefs
            .map((r) => topicIdsByRefKey.get(createTopicRefKey(r as unknown as TopicBackupRef)))
            .filter((id) => !!id),
        );
      }
    }
    if (table === 'generated_study_images' || table === 'lecture_learned_topics') {
      const ref = rawRow.topic_ref as Record<string, unknown> | undefined;
      if (ref && typeof ref.subjectShortCode === 'string' && typeof ref.topicName === 'string') {
        const tid = topicIdsByRefKey.get(createTopicRefKey(ref as unknown as TopicBackupRef));
        if (tid) row.topic_id = tid;
        else return null;
      }
    }
    if (table === 'topic_suggestions') {
      const sref = rawRow.subject_ref as Record<string, unknown> | undefined;
      if (sref && typeof sref.shortCode === 'string') {
        const sid = subjectIdsByShortCode.get(String(sref.shortCode).toLowerCase());
        if (sid) row.subject_id = sid;
        else return null;
      }
      const aref = rawRow.approved_topic_ref as Record<string, unknown> | undefined;
      if (aref && typeof aref.subjectShortCode === 'string' && typeof aref.topicName === 'string') {
        const tid = topicIdsByRefKey.get(createTopicRefKey(aref as unknown as TopicBackupRef));
        row.approved_topic_id = tid ?? null;
      }
    }
    return row;
  };

  try {
    await db.execAsync('PRAGMA defer_foreign_keys = ON');
    await db.execAsync('BEGIN IMMEDIATE');

    for (const table of JSON_BACKUP_DELETE_ORDER) {
      if (table === 'user_profile') continue;
      if (!(table in tablesFromBackup)) continue;
      await connectionForTable(table, db).runAsync(`DELETE FROM ${table}`);
      restoredCounts[table] = 0;
    }

    if (tablesFromBackup.user_profile?.[0]) {
      const row = tablesFromBackup.user_profile[0];
      const userCols = await getColumns('user_profile');
      const setCols = Object.keys(row).filter((c) => c !== 'id' && userCols.includes(c));
      if (setCols.length > 0) {
        const setSql = setCols.map((c) => `${c} = ?`).join(', ');
        const values = setCols.map((c) => toBindValue(row[c]));
        await db.runAsync(`UPDATE user_profile SET ${setSql} WHERE id = 1`, values);
      }
      restoredCounts.user_profile = 1;
    }

    for (const table of JSON_BACKUP_RESTORE_ORDER) {
      if (table === 'user_profile') continue;
      const rows = tablesFromBackup[table];
      if (!rows || rows.length === 0) continue;
      const tableCols = await getColumns(table);
      const conn = connectionForTable(table, db);

      for (const rawRow of rows) {
        const sanitizedRow = sanitizeRow(table, rawRow);
        if (!sanitizedRow) continue;
        const cols = Object.keys(sanitizedRow).filter((c) => tableCols.includes(c));
        const placeholders = cols.map(() => '?').join(', ');
        const values = cols.map((c) => toBindValue(sanitizedRow[c]));
        await conn.runAsync(
          `INSERT OR REPLACE INTO ${table} (${cols.join(', ')}) VALUES (${placeholders})`,
          values,
        );
        restoredCounts[table] = (restoredCounts[table] ?? 0) + 1;
      }
    }
    await db.execAsync('COMMIT');
  } catch (err) {
    console.error('[Backup] Restore transaction failed:', err);
    try {
      await db.execAsync('ROLLBACK');
    } catch (rbErr) {
      console.warn('[Backup] Rollback also failed:', rbErr);
    }
    return { ok: false, message: 'Import failed during restore.' };
  }

  return { ok: true, message: 'Restored backup successfully' };
}

