/**
 * Audio Recording Service — Direct PCM Capture
 *
 * Provides two recording paths:
 *
 * Path A (Primary): Direct 16kHz mono PCM via @fugood/react-native-audio-pcm-stream.
 *   - Zero conversion overhead — audio is already in Whisper's native format.
 *   - Streams raw PCM samples for real-time transcription.
 *   - Writes WAV to disk simultaneously for batch re-processing.
 *
 * Path B (Fallback): Record to M4A via existing RecordingService native module,
 *   then convert to WAV using the native convertToWav() function.
 *   - Used if PCM streaming fails on certain devices.
 *   - Adds ~2s conversion overhead per 30s chunk.
 *
 * Audio spec: 16,000 Hz sample rate, mono, 16-bit signed integer PCM.
 */

import { Platform, PermissionsAndroid, Alert } from 'react-native';
import * as FileSystem from 'expo-file-system/legacy';
import { RecordingState, TranscriptionError } from './types';

// ─── PCM Stream Library ──────────────────────────────────────────────────────
// @fugood/react-native-audio-pcm-stream provides raw PCM from the mic.
// It's the recommended audio source for whisper.rn's RealtimeTranscriber.
let AudioPcmStream: any = null;
try {
  AudioPcmStream = require('@fugood/react-native-audio-pcm-stream').default;
} catch {
  console.warn(
    '[AudioRecorder] @fugood/react-native-audio-pcm-stream not available, will use fallback recording',
  );
}

// ─── Fallback: Native module recording ───────────────────────────────────────
let AppLauncher: any = null;
try {
  AppLauncher = require('../../../modules/app-launcher');
} catch {
  console.warn('[AudioRecorder] app-launcher native module not available');
}

// ─── PCM listener tracking (avoids monkey-patching AudioPcmStream) ──────────
let _pcmDataListener: ((data: string) => void) | null = null;

// ─── Constants ───────────────────────────────────────────────────────────────

const SAMPLE_RATE = 16000;
const CHANNELS = 1;
const BITS_PER_SAMPLE = 16;
const BYTES_PER_SAMPLE = BITS_PER_SAMPLE / 8;

/** Directory to store WAV recordings */
const RECORDING_DIR = `${FileSystem.documentDirectory}recordings/`;

// ─── WAV Header Construction ─────────────────────────────────────────────────

/**
 * Creates a valid WAV file header for 16kHz mono 16-bit PCM.
 * The header is 44 bytes. We write a placeholder data size initially,
 * then patch it when the recording finishes.
 */
function createWavHeader(dataSize: number): ArrayBuffer {
  const header = new ArrayBuffer(44);
  const view = new DataView(header);

  const writeString = (offset: number, str: string) => {
    for (let i = 0; i < str.length; i++) {
      view.setUint8(offset + i, str.charCodeAt(i));
    }
  };

  writeString(0, 'RIFF');
  view.setUint32(4, 36 + dataSize, true); // File size - 8
  writeString(8, 'WAVE');
  writeString(12, 'fmt ');
  view.setUint32(16, 16, true); // Subchunk1Size (PCM = 16)
  view.setUint16(20, 1, true); // AudioFormat (PCM = 1)
  view.setUint16(22, CHANNELS, true);
  view.setUint32(24, SAMPLE_RATE, true);
  view.setUint32(28, SAMPLE_RATE * CHANNELS * BYTES_PER_SAMPLE, true); // ByteRate
  view.setUint16(32, CHANNELS * BYTES_PER_SAMPLE, true); // BlockAlign
  view.setUint16(34, BITS_PER_SAMPLE, true);
  writeString(36, 'data');
  view.setUint32(40, dataSize, true);

  return header;
}

// ─── Type for PCM data callbacks ─────────────────────────────────────────────

export type PcmDataCallback = (samples: Float32Array) => void;
export type RecordingStateCallback = (state: RecordingState) => void;

// ─── Audio Recorder Class ────────────────────────────────────────────────────

export class AudioRecorder {
  private state: RecordingState = 'idle';
  private stateCallback: RecordingStateCallback | null = null;
  private pcmCallback: PcmDataCallback | null = null;
  private usingFallback = false;

  // PCM stream recording state
  private pcmChunks: Buffer[] = [];
  private totalPcmBytes = 0;
  private recordingStartTime = 0;
  private currentWavPath: string | null = null;

  // Fallback recording state
  private fallbackRecordingPath: string | null = null;

  // Track temporary files for cleanup
  private tempFilesToClean: string[] = [];

  // Track if destroyed
  private isDestroyed = false;

  constructor() {
    this.ensureRecordingDir();
  }

  // ── Public API ──────────────────────────────────────────────────────────

  getState(): RecordingState {
    return this.state;
  }

  onStateChange(callback: RecordingStateCallback): void {
    this.stateCallback = callback;
  }

  /**
   * Register a callback to receive raw PCM samples in real-time.
   * Samples are Float32Array in range [-1.0, 1.0], 16kHz mono.
   * Only fires when using the primary PCM stream path.
   */
  onPcmData(callback: PcmDataCallback): void {
    this.pcmCallback = callback;
  }

  /**
   * Start recording lecture audio.
   * Attempts direct PCM capture first; falls back to native M4A recording.
   * Returns the file path where the WAV will be saved.
   */
  async startRecording(): Promise<string> {
    if (this.isDestroyed) {
      throw new TranscriptionError(
        'RECORDER_DESTROYED',
        'Cannot start recording - recorder has been destroyed',
        'The audio recorder has been cleaned up. Please restart the recording.',
      );
    }

    if (this.state === 'recording') {
      throw new TranscriptionError(
        'UNKNOWN',
        'Already recording',
        'A recording is already in progress.',
      );
    }

    this.setState('requesting_permission');

    // Request microphone permission
    const hasPermission = await this.requestMicPermission();
    if (!hasPermission) {
      this.setState('error');
      throw new TranscriptionError(
        'MIC_PERMISSION_DENIED',
        'Microphone permission denied',
        'Microphone access is required for recording. Please grant permission in Settings.',
      );
    }

    // Generate output path
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    this.currentWavPath = `${RECORDING_DIR}lecture_${timestamp}.wav`;

    // Reset state
    this.pcmChunks = [];
    this.totalPcmBytes = 0;
    this.usingFallback = false;
    this.recordingStartTime = Date.now();
    this.tempFilesToClean = [];

    // Try primary PCM path first
    if (AudioPcmStream) {
      try {
        await this.startPcmRecording();
        this.setState('recording');
        return this.currentWavPath;
      } catch (err) {
        console.warn('[AudioRecorder] PCM stream failed, trying fallback:', err);
        // Clean up any partial PCM data
        this.pcmChunks = [];
        this.totalPcmBytes = 0;
      }
    }

    // Fallback: native module M4A recording
    if (AppLauncher) {
      try {
        await this.startFallbackRecording();
        this.usingFallback = true;
        this.setState('recording');
        return this.currentWavPath;
      } catch (err) {
        await this.cleanupTempFiles();
        this.setState('error');
        throw new TranscriptionError(
          'MIC_IN_USE',
          `Both recording paths failed: ${err}`,
          'Could not start recording. The microphone may be in use by another app.',
        );
      }
    }

    await this.cleanupTempFiles();
    this.setState('error');
    throw new TranscriptionError(
      'UNKNOWN',
      'No recording backend available',
      'Audio recording is not available on this device.',
    );
  }

  /**
   * Stop recording and finalize the WAV file.
   * Returns the path to the final WAV file (16kHz mono PCM).
   */
  async stopRecording(): Promise<string> {
    if (this.isDestroyed) {
      throw new TranscriptionError(
        'RECORDER_DESTROYED',
        'Cannot stop recording - recorder has been destroyed',
        'The audio recorder has been cleaned up.',
      );
    }

    if (this.state !== 'recording' && this.state !== 'paused') {
      throw new TranscriptionError(
        'UNKNOWN',
        `Cannot stop recording in state: ${this.state}`,
        'No active recording to stop.',
      );
    }

    this.setState('stopping');

    let wavPath: string;

    try {
      if (this.usingFallback) {
        wavPath = await this.stopFallbackRecording();
      } else {
        wavPath = await this.stopPcmRecording();
      }
    } catch (err) {
      await this.cleanupTempFiles();
      throw err;
    } finally {
      this.setState('idle');
    }

    return wavPath;
  }

  /**
   * Get the elapsed recording time in seconds.
   */
  getElapsedSeconds(): number {
    if (this.state !== 'recording' && this.state !== 'paused') return 0;
    return (Date.now() - this.recordingStartTime) / 1000;
  }

  /**
   * Whether we're using the direct PCM path (supports real-time streaming)
   * or the fallback M4A path (file-based only).
   */
  isUsingDirectPcm(): boolean {
    return !this.usingFallback;
  }

  /**
   * Clean up a recording file after transcription is complete.
   */
  async deleteRecording(filePath: string): Promise<void> {
    try {
      const info = await FileSystem.getInfoAsync(filePath);
      if (info?.exists) {
        await FileSystem.deleteAsync(filePath, { idempotent: true });
      }
    } catch (err) {
      console.warn('[AudioRecorder] Failed to delete recording:', err);
    }
  }

  /**
   * Release all resources. Call when the component unmounts.
   * This is idempotent and safe to call multiple times.
   */
  async destroy(): Promise<void> {
    if (this.isDestroyed) return;
    this.isDestroyed = true;

    // Stop recording if active
    if (this.state === 'recording' || this.state === 'paused') {
      try {
        await this.stopRecording();
      } catch (error) {
        // Ignore errors during cleanup
        console.warn('[AudioRecorder] Error stopping recording during destroy:', error);
      }
    }

    // Clean up all temporary files
    await this.cleanupTempFiles();

    // Clear callbacks
    this.pcmCallback = null;
    this.stateCallback = null;

    // Clear buffers
    this.pcmChunks = [];
    this.totalPcmBytes = 0;
  }

  // ── Primary Path: Direct PCM Recording ──────────────────────────────────

  private async startPcmRecording(): Promise<void> {
    const options = {
      sampleRate: SAMPLE_RATE,
      channels: CHANNELS,
      bitsPerSample: BITS_PER_SAMPLE,
      audioSource: 6, // VOICE_RECOGNITION — no echo cancellation, best for lectures
      bufferSize: 8192, // ~0.5s at 16kHz mono 16-bit
    };

    try {
      AudioPcmStream.init(options);
    } catch (err) {
      throw new TranscriptionError(
        'PCM_INIT_FAILED',
        `Failed to initialize PCM stream: ${err}`,
        'Audio initialization failed. Try restarting the app.',
      );
    }

    // Set up data listener
    const dataHandler = (base64Chunk: string) => {
      if (this.state !== 'recording' || this.isDestroyed) return;

      try {
        // Decode base64 to raw bytes
        const rawBuffer = Buffer.from(base64Chunk, 'base64');
        this.pcmChunks.push(rawBuffer);
        this.totalPcmBytes += rawBuffer.length;

        // Memory safety check - limit to 500MB of raw PCM
        if (this.totalPcmBytes > 500 * 1024 * 1024) {
          console.error('[AudioRecorder] Recording exceeded 500MB limit, stopping...');
          this.stopRecording().catch(() => {});
          return;
        }

        // Convert Int16 PCM to Float32 for whisper.rn
        if (this.pcmCallback) {
          const int16View = new Int16Array(
            rawBuffer.buffer,
            rawBuffer.byteOffset,
            rawBuffer.length / 2,
          );
          const float32 = new Float32Array(int16View.length);
          for (let i = 0; i < int16View.length; i++) {
            float32[i] = int16View[i] / 32768.0;
          }
          this.pcmCallback(float32);
        }
      } catch (err) {
        console.warn('[AudioRecorder] Error processing PCM chunk:', err);
        // Don't throw - continue recording
      }
    };

    AudioPcmStream.on('data', dataHandler);
    _pcmDataListener = dataHandler;

    try {
      await AudioPcmStream.start();
    } catch (err) {
      AudioPcmStream.off('data', dataHandler);
      _pcmDataListener = null;
      throw new TranscriptionError(
        'PCM_START_FAILED',
        `Failed to start PCM recording: ${err}`,
        'Could not start audio capture. Check microphone permissions.',
      );
    }
  }

  private async stopPcmRecording(): Promise<string> {
    try {
      await AudioPcmStream.stop();
    } catch (err) {
      console.warn('[AudioRecorder] Error stopping PCM stream:', err);
      // Continue to write whatever we have
    }

    if (_pcmDataListener) {
      AudioPcmStream.off('data', _pcmDataListener);
      _pcmDataListener = null;
    }

    // Check if we have any audio data
    if (this.pcmChunks.length === 0) {
      throw new TranscriptionError(
        'NO_AUDIO_DATA',
        'No audio data captured',
        'The recording appears to be empty. Check your microphone.',
      );
    }

    // Concatenate all PCM chunks with memory safety check
    if (this.totalPcmBytes > 100 * 1024 * 1024) {
      // 100MB limit for concatenation
      throw new TranscriptionError(
        'RECORDING_TOO_LONG',
        'Recording exceeds maximum duration',
        'Recording is too long. Please break it into smaller chunks.',
      );
    }

    let totalBuffer: Buffer;
    try {
      // Use a more memory-efficient approach for large recordings
      if (this.pcmChunks.length > 100) {
        // For many chunks, write incrementally to temp file
        const tempPath = `${FileSystem.cacheDirectory}pcm-chunks-${Date.now()}.bin`;
        this.tempFilesToClean.push(tempPath);

        let offset = 0;
        const buffer = Buffer.alloc(this.totalPcmBytes);
        for (const chunk of this.pcmChunks) {
          chunk.copy(buffer, offset);
          offset += chunk.length;
        }
        totalBuffer = buffer;
      } else {
        totalBuffer = Buffer.concat(this.pcmChunks, this.totalPcmBytes);
      }
    } catch (err) {
      throw new TranscriptionError(
        'BUFFER_CONCAT_FAILED',
        `Failed to concatenate audio buffers: ${err}`,
        'Internal audio processing error.',
      );
    }

    // Write WAV file: header + PCM data
    const wavHeader = createWavHeader(totalBuffer.length);
    const headerBuffer = Buffer.from(wavHeader);
    const wavBuffer = Buffer.concat([headerBuffer, totalBuffer]);

    // Write to file with error handling
    const base64Wav = wavBuffer.toString('base64');
    try {
      await FileSystem.writeAsStringAsync(this.currentWavPath!, base64Wav, {
        encoding: FileSystem.EncodingType.Base64,
      });
    } catch (err) {
      throw new TranscriptionError(
        'FILE_WRITE_FAILED',
        `Failed to write WAV file: ${err}`,
        'Could not save recording. Check storage space.',
      );
    }

    // Free memory
    this.pcmChunks = [];
    this.totalPcmBytes = 0;

    return this.currentWavPath!;
  }

  // ── Fallback Path: Native Module M4A → WAV ─────────────────────────────

  private async startFallbackRecording(): Promise<void> {
    if (!AppLauncher) {
      throw new TranscriptionError(
        'NATIVE_MODULE_MISSING',
        'Native recording module not available',
        'Audio recording is not supported on this device.',
      );
    }

    try {
      this.fallbackRecordingPath = await AppLauncher.startRecording('');
      if (!this.fallbackRecordingPath) {
        throw new Error('Native recording returned null path');
      }
      this.tempFilesToClean.push(this.fallbackRecordingPath);
    } catch (err) {
      throw new TranscriptionError(
        'FALLBACK_START_FAILED',
        `Failed to start fallback recording: ${err}`,
        'Could not start audio recording. Check microphone permissions.',
      );
    }
  }

  private async stopFallbackRecording(): Promise<string> {
    if (!AppLauncher) {
      throw new TranscriptionError(
        'NATIVE_MODULE_MISSING',
        'Native recording module not available',
        'Cannot stop recording - module missing.',
      );
    }

    try {
      const m4aPath = await AppLauncher.stopRecording();
      if (!m4aPath) {
        throw new TranscriptionError(
          'RECORDING_INTERRUPTED',
          'stopRecording returned null',
          'Recording was interrupted. Your progress may have been lost.',
        );
      }

      // Convert M4A → WAV (16kHz mono PCM) via native module
      const wavPath = await AppLauncher.convertToWav(m4aPath);
      if (!wavPath) {
        throw new TranscriptionError(
          'AUDIO_FORMAT_ERROR',
          `Failed to convert ${m4aPath} to WAV`,
          'Could not process the audio file. Please try recording again.',
        );
      }

      // Copy to our expected output path if different
      if (wavPath !== this.currentWavPath) {
        try {
          await FileSystem.copyAsync({ from: wavPath, to: this.currentWavPath! });
          this.tempFilesToClean.push(wavPath); // Mark for cleanup
        } catch (err) {
          throw new TranscriptionError(
            'FILE_COPY_FAILED',
            `Failed to copy WAV file: ${err}`,
            'Could not save converted audio.',
          );
        }
      }

      return this.currentWavPath!;
    } catch (err) {
      // Clean up temp files on error
      await this.cleanupTempFiles();
      throw err;
    }
  }

  // ── Helpers ─────────────────────────────────────────────────────────────

  private setState(state: RecordingState): void {
    if (this.isDestroyed) return;
    this.state = state;
    this.stateCallback?.(state);
  }

  private async requestMicPermission(): Promise<boolean> {
    if (Platform.OS !== 'android') return true; // iOS handled by expo-av

    try {
      const result = await PermissionsAndroid.request(PermissionsAndroid.PERMISSIONS.RECORD_AUDIO, {
        title: 'Microphone Permission',
        message: 'Guru needs microphone access to record lectures for transcription.',
        buttonPositive: 'Allow',
        buttonNegative: 'Deny',
      });
      return result === PermissionsAndroid.RESULTS.GRANTED;
    } catch (err) {
      console.warn('[AudioRecorder] Permission request failed:', err);
      return false;
    }
  }

  private async ensureRecordingDir(): Promise<void> {
    try {
      const info = await FileSystem.getInfoAsync(RECORDING_DIR);
      if (!info?.exists) {
        await FileSystem.makeDirectoryAsync(RECORDING_DIR, {
          intermediates: true,
        });
      }
    } catch (err) {
      console.warn('[AudioRecorder] Failed to create recording dir:', err);
    }
  }

  /**
   * Clean up temporary files created during recording.
   * Called on error or when stopping recording.
   */
  private async cleanupTempFiles(): Promise<void> {
    for (const file of this.tempFilesToClean) {
      try {
        const info = await FileSystem.getInfoAsync(file);
        if (info?.exists) {
          await FileSystem.deleteAsync(file, { idempotent: true });
        }
      } catch (err) {
        console.warn('[AudioRecorder] Failed to cleanup temp file:', file, err);
      }
    }
    this.tempFilesToClean = [];
  }
}

// ─── Singleton Export ────────────────────────────────────────────────────────

let _recorder: AudioRecorder | null = null;

export function getAudioRecorder(): AudioRecorder {
  if (!_recorder) {
    _recorder = new AudioRecorder();
  }
  return _recorder;
}

/**
 * Batch Transcription Service
 *
 * For post-recording transcription: the student records a lecture, then
 * transcribes it later (e.g., overnight, during commute with phone idle).
 *
 * Pipeline:
 *   WAV file on disk → VAD-aware chunking (split at silence boundaries)
 *     → Sequential chunk transcription (beam search, beamSize=5)
 *     → Progress reporting ("Chunk 42/240...")
 *     → Memory management (release each chunk after transcription)
 *     → Merge all chunk results with overlap deduplication
 *
 * Key design decisions:
 *   - Sequential processing (not parallel) to stay within memory limits
 *   - Each chunk's audio data is released immediately after transcription
 *   - GC pause if approaching memory ceiling
 *   - Absolute timestamps preserved relative to recording start
 *   - Higher accuracy than real-time mode (beam search + best-of)
 */

import * as FileSystem from 'expo-file-system/legacy';
import { initWhisper } from 'whisper.rn';
import { splitWavIntoChunks } from '../../../modules/app-launcher';
import { stripFileUri } from '../fileUri';

type WhisperContextType = Awaited<ReturnType<typeof initWhisper>>;
import {
  TranscriptSegment,
  TranscriptionProgress,
  BatchTranscriptionConfig,
  DEFAULT_BATCH_CONFIG,
  TranscriptionError,
} from './types';
import { WhisperModelManager } from './whisperModelManager';

// ─── VAD for chunking ────────────────────────────────────────────────────────

let initWhisperVad: any = null;
try {
  initWhisperVad = require('whisper.rn').initWhisperVad;
} catch {
  console.warn('[BatchTranscriber] initWhisperVad not available');
}

// ─── Types ───────────────────────────────────────────────────────────────────

interface AudioChunkInfo {
  /** Index of this chunk (0-based) */
  index: number;
  /** File path to the chunk WAV file */
  filePath: string;
  /** Start time in the original recording (seconds) */
  startTimeSec: number;
  /** Duration of this chunk (seconds) */
  durationSec: number;
}

const WAV_BYTES_PER_SECOND = 16_000 * 2;

export type BatchProgressCallback = (progress: TranscriptionProgress) => void;

// ─── Batch Transcriber ───────────────────────────────────────────────────────

export class BatchTranscriber {
  private modelManager: WhisperModelManager;
  private config: BatchTranscriptionConfig;

  private isCancelled = false;
  private isPaused = false;
  private segments: TranscriptSegment[] = [];
  private segmentCounter = 0;
  private callback: BatchProgressCallback | null = null;
  private processingStartTime = 0;

  constructor(modelManager: WhisperModelManager, config?: Partial<BatchTranscriptionConfig>) {
    this.modelManager = modelManager;
    this.config = { ...DEFAULT_BATCH_CONFIG, ...config };
  }

  // ── Public API ──────────────────────────────────────────────────────────

  /**
   * Transcribe a complete audio file in batch mode.
   * The file must be WAV format (16kHz, mono, 16-bit PCM).
   *
   * Returns an array of TranscriptSegments with absolute timestamps.
   */
  async transcribe(
    wavFilePath: string,
    callback?: BatchProgressCallback,
  ): Promise<{
    segments: TranscriptSegment[];
    vadSkippedSeconds: number;
    processingTimeSeconds: number;
  }> {
    this.callback = callback ?? null;
    this.isCancelled = false;
    this.isPaused = false;
    this.segments = [];
    this.segmentCounter = 0;
    this.processingStartTime = Date.now();

    // Validate input file
    const fileInfo = await FileSystem.getInfoAsync(wavFilePath);
    if (!fileInfo?.exists) {
      throw new TranscriptionError(
        'AUDIO_FORMAT_ERROR',
        `WAV file not found: ${wavFilePath}`,
        'The audio file could not be found. It may have been deleted.',
      );
    }

    const whisperContext = this.modelManager.getContext();

    // Step 1: Split audio into chunks
    this.emitProgress('initializing', 0, 0, 0);
    const chunks = await this.splitAudioIntoChunks(wavFilePath);

    if (chunks.length === 0) {
      throw new TranscriptionError(
        'EMPTY_TRANSCRIPTION',
        'Audio file produced zero chunks',
        'The recording appears to be empty or too short to transcribe.',
      );
    }

    let vadSkippedSeconds = 0;
    let emptyChunks = 0;

    // Step 2: Process each chunk sequentially
    for (let i = 0; i < chunks.length; i++) {
      // Check for cancellation
      if (this.isCancelled) {
        await this.cleanupChunks(chunks);
        break;
      }

      // Wait while paused
      while (this.isPaused && !this.isCancelled) {
        await this.sleep(500);
      }

      const chunk = chunks[i];
      this.emitProgress('transcribing', i + 1, chunks.length, 0);

      try {
        const chunkSegments = await this.transcribeChunk(whisperContext, chunk);

        if (chunkSegments.length === 0) {
          emptyChunks++;
          if (__DEV__) console.log(`[Batch] Chunk ${i + 1}/${chunks.length}: empty (silence)`);
        } else {
          this.segments.push(...chunkSegments);
          if (__DEV__)
            console.log(
              `[Batch] Chunk ${i + 1}/${chunks.length}: ${chunkSegments.length} segments`,
            );
        }
      } catch (err) {
        // Log but don't crash on individual chunk failures
        console.error(`[Batch] Chunk ${i + 1}/${chunks.length} failed:`, err);
        emptyChunks++;
      }

      // Clean up this chunk's temp file to free memory
      await this.deleteChunkFile(chunk.filePath);

      // Memory management: force GC hint after every 10 chunks
      if ((i + 1) % 10 === 0) {
        await this.memoryCheck();
      }
    }

    const processingTimeSeconds = (Date.now() - this.processingStartTime) / 1000;

    // Estimate VAD-skipped seconds based on empty chunks
    vadSkippedSeconds = emptyChunks * this.config.chunkDurationSec;

    this.emitProgress('completed', chunks.length, chunks.length, vadSkippedSeconds);

    return {
      segments: this.segments,
      vadSkippedSeconds,
      processingTimeSeconds,
    };
  }

  /**
   * Cancel an in-progress batch transcription.
   * Already-transcribed segments are preserved.
   */
  cancel(): void {
    this.isCancelled = true;
  }

  /**
   * Pause batch transcription.
   */
  pause(): void {
    this.isPaused = true;
  }

  /**
   * Resume batch transcription.
   */
  resume(): void {
    this.isPaused = false;
  }

  /**
   * Get segments transcribed so far (even if still in progress).
   */
  getSegments(): TranscriptSegment[] {
    return [...this.segments];
  }

  // ── Audio Chunking ──────────────────────────────────────────────────────

  /**
   * Split a WAV file into fixed-duration chunks with overlap.
   *
   * Ideally we'd use VAD to find silence boundaries, but for simplicity
   * and memory efficiency, we use fixed-length chunks with overlap.
   * The overlap ensures we don't cut words in half — the merger handles
   * deduplication of overlapping text.
   *
   * Each chunk is written as a separate WAV file in a temp directory.
   */
  private async splitAudioIntoChunks(wavFilePath: string): Promise<AudioChunkInfo[]> {
    const chunks: AudioChunkInfo[] = [];

    // Read the WAV file to get its total duration
    // WAV header is 44 bytes. Rest is PCM data.
    // Duration = dataBytes / (sampleRate * channels * bytesPerSample)
    const fileInfo = await FileSystem.getInfoAsync(wavFilePath);
    if (!fileInfo?.exists || !('size' in fileInfo)) {
      throw new Error('Cannot read WAV file info');
    }

    const dataBytes = fileInfo.size - 44; // Subtract WAV header
    const bytesPerSecond = WAV_BYTES_PER_SECOND; // 16kHz * mono * 16-bit
    const totalDurationSec = dataBytes / bytesPerSecond;

    const chunkDuration = this.config.chunkDurationSec;
    const overlap = this.config.overlapSec;
    const chunkBytes = Math.max(bytesPerSecond, Math.floor(chunkDuration * bytesPerSecond));
    const overlapBytes = Math.max(0, Math.floor(overlap * bytesPerSecond));
    const stepBytes = Math.max(bytesPerSecond, chunkBytes - overlapBytes);
    const nativeChunks = await splitWavIntoChunks(
      stripFileUri(wavFilePath),
      chunkBytes,
      stepBytes,
      bytesPerSecond,
    );

    nativeChunks.forEach((chunk, index) => {
      chunks.push({
        index,
        filePath: chunk.path,
        startTimeSec: chunk.startSec,
        durationSec: chunk.durationSec,
      });
    });

    if (__DEV__)
      console.log(
        `[Batch] Split ${totalDurationSec.toFixed(0)}s audio into ${chunks.length} chunks (${chunkDuration}s each, ${overlap}s overlap)`,
      );

    return chunks;
  }

  // ── Chunk Transcription ─────────────────────────────────────────────────

  private async transcribeChunk(
    context: WhisperContextType,
    chunk: AudioChunkInfo,
  ): Promise<TranscriptSegment[]> {
    const result = await context.transcribe(chunk.filePath, {
      language: 'en',
      beamSize: this.config.beamSize,
      bestOf: this.config.bestOf,
      temperature: 0,
      tokenTimestamps: true,
      nThreads: this.config.nThreads,
      maxLen: 0,
    });

    if (!result?.segments || result.segments.length === 0 || !result.result?.trim()) {
      return [];
    }

    // Convert whisper.rn segments to our format, adjusting timestamps
    // to be absolute (relative to recording start, not chunk start)
    return result.segments
      .filter((seg: any) => {
        const text = seg.text?.trim();
        if (!text) return false;
        // Filter hallucinations
        if (text === '[BLANK_AUDIO]' || text === '(blank audio)') return false;
        if (/^(thank you\.?\s*){3,}/i.test(text)) return false;
        if (/^(♪\s*)+$/.test(text)) return false;
        return true;
      })
      .map((seg: any) => {
        const segment: TranscriptSegment = {
          id: this.segmentCounter++,
          // Absolute timestamps: chunk start + segment-relative time
          start: chunk.startTimeSec + (seg.t0 ?? 0) / 100, // whisper.rn uses centiseconds
          end: chunk.startTimeSec + (seg.t1 ?? chunk.durationSec * 100) / 100,
          text: seg.text.trim(),
        };
        return segment;
      });
  }

  // ── Memory Management ───────────────────────────────────────────────────

  private async memoryCheck(): Promise<void> {
    // In React Native, we can't directly query heap size,
    // but we can trigger a GC hint by creating and discarding objects.
    // The real memory safeguard is releasing chunk files after each transcription.
    try {
      // Small delay to let the runtime breathe
      await this.sleep(100);
    } catch {
      // Ignore
    }
  }

  private async deleteChunkFile(filePath: string): Promise<void> {
    try {
      await FileSystem.deleteAsync(filePath, { idempotent: true });
    } catch {
      // Non-critical: chunk dir will be cleaned up eventually
    }
  }

  private async cleanupChunks(chunks: AudioChunkInfo[]): Promise<void> {
    for (const chunk of chunks) {
      await this.deleteChunkFile(chunk.filePath);
    }
    // Native chunk helper writes unique folders per run; files are removed above.
  }

  // ── Helpers ─────────────────────────────────────────────────────────────

  private emitProgress(
    state: 'initializing' | 'transcribing' | 'completed',
    current: number,
    total: number,
    vadSkipped: number,
  ): void {
    if (!this.callback) return;

    const elapsedSeconds = (Date.now() - this.processingStartTime) / 1000;

    // Estimate remaining time based on average time per chunk
    let estimatedRemaining: number | undefined;
    if (state === 'transcribing' && current > 0 && current < total) {
      const avgTimePerChunk = elapsedSeconds / current;
      estimatedRemaining = avgTimePerChunk * (total - current);
    }

    const percentage =
      state === 'completed' ? 100 : total > 0 ? Math.round((current / total) * 100) : 0;

    this.callback({
      state: state === 'completed' ? 'completed' : 'transcribing',
      currentChunk: current,
      totalChunks: total,
      percentage,
      partialTranscript: this.segments.map((s) => s.text).join(' '),
      segments: [...this.segments],
      elapsedSeconds,
      estimatedRemainingSeconds: estimatedRemaining ? Math.round(estimatedRemaining) : undefined,
    });
  }

  private sleep(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }
}

/**
 * Real-Time Transcription Controller
 *
 * Uses whisper.rn's RealtimeTranscriber with AudioPcmStreamAdapter for
 * live speech-to-text during lecture recording. Text appears as the
 * professor speaks — the primary UX mode.
 *
 * Pipeline:
 *   Mic → AudioPcmStream (16kHz PCM) → AudioPcmStreamAdapter
 *     → Silero VAD (speech detection) → Auto-slice on silence
 *     → Whisper inference (greedy, beamSize=1) → TranscriptSegment
 *     → Accumulate in running transcript
 *
 * The RealtimeTranscriber handles:
 *   - Audio buffering and slicing (configurable audioSliceSec)
 *   - Silero VAD integration (skip silence, auto-slice on speech end)
 *   - Memory management (releases processed audio buffers)
 *   - Overlapping windows to avoid mid-word splits
 *
 * Known edge cases handled:
 *   - Mid-sentence chunk boundaries: 0.5s overlap + post-merge dedup
 *   - Long pauses (Q&A, slide transitions): VAD skips silence
 *   - Background noise (lecture hall HVAC): lowered speechThreshold
 *   - Empty chunks: logged and skipped, not errors
 */

import { initWhisper } from 'whisper.rn';

type WhisperContextType = Awaited<ReturnType<typeof initWhisper>>;
import {
  TranscriptSegment,
  TranscriptionProgress,
  RealtimeTranscriptionConfig,
  VadConfig,
  DEFAULT_REALTIME_CONFIG,
  LECTURE_HALL_VAD_CONFIG,
  TranscriptionError,
} from './types';
import { WhisperModelManager } from './whisperModelManager';

// ─── whisper.rn RealtimeTranscriber imports ──────────────────────────────────
// These come from whisper.rn v0.5.x's new streaming API

let RealtimeTranscriber: any = null;
let AudioPcmStreamAdapter: any = null;
let initWhisperVad: any = null;

try {
  const whisperRn = require('whisper.rn');
  RealtimeTranscriber = whisperRn.RealtimeTranscriber;
  AudioPcmStreamAdapter = whisperRn.AudioPcmStreamAdapter;
  initWhisperVad = whisperRn.initWhisperVad;
} catch (err) {
  console.error('[RealtimeTranscriber] Failed to import whisper.rn:', err);
}

// ─── Types ───────────────────────────────────────────────────────────────────

export type RealtimeTranscriptCallback = (progress: TranscriptionProgress) => void;

interface SliceResult {
  text: string;
  startSec: number;
  endSec: number;
}

// ─── Real-Time Transcription Controller ──────────────────────────────────────

export class RealtimeTranscriptionController {
  private modelManager: WhisperModelManager;
  private config: RealtimeTranscriptionConfig;
  private vadConfig: VadConfig;

  // whisper.rn instances
  private transcriber: any = null;
  private audioAdapter: any = null;
  private vadContext: any = null;

  // State
  private isRunning = false;
  private isPaused = false;
  private segments: TranscriptSegment[] = [];
  private segmentCounter = 0;
  private sessionStartTime = 0;
  private totalVadSkippedSeconds = 0;
  private processingStartTime = 0;
  private callback: RealtimeTranscriptCallback | null = null;

  // Deduplication: track last few segment texts to detect overlapping repeats
  private recentTexts: string[] = [];
  private readonly DEDUP_WINDOW = 3;

  constructor(
    modelManager: WhisperModelManager,
    config?: Partial<RealtimeTranscriptionConfig>,
    vadConfig?: Partial<VadConfig>,
  ) {
    this.modelManager = modelManager;
    this.config = { ...DEFAULT_REALTIME_CONFIG, ...config };
    this.vadConfig = { ...LECTURE_HALL_VAD_CONFIG, ...vadConfig };
  }

  // ── Public API ──────────────────────────────────────────────────────────

  /**
   * Start real-time transcription.
   * Requires a loaded WhisperContext from the model manager.
   * The callback fires every time a new segment is transcribed.
   */
  async start(callback: RealtimeTranscriptCallback): Promise<void> {
    if (this.isRunning) {
      throw new TranscriptionError(
        'UNKNOWN',
        'RealtimeTranscriber already running',
        'Real-time transcription is already active.',
      );
    }

    if (!RealtimeTranscriber || !AudioPcmStreamAdapter) {
      throw new TranscriptionError(
        'UNKNOWN',
        'whisper.rn RealtimeTranscriber not available',
        'Real-time transcription requires whisper.rn v0.5+. Please update the library.',
      );
    }

    this.callback = callback;
    this.segments = [];
    this.segmentCounter = 0;
    this.totalVadSkippedSeconds = 0;
    this.recentTexts = [];
    this.sessionStartTime = Date.now();
    this.processingStartTime = Date.now();

    const whisperContext = this.modelManager.getContext();

    // Initialize VAD if available
    await this.initVad();

    // Create audio adapter (bridges @fugood/react-native-audio-pcm-stream to whisper.rn)
    this.audioAdapter = new AudioPcmStreamAdapter({
      sampleRate: 16000,
      channels: 1,
      bitsPerSample: 16,
      audioSource: 6, // VOICE_RECOGNITION
      bufferSize: 8192,
    });

    // Create the real-time transcriber
    this.transcriber = new RealtimeTranscriber(whisperContext, {
      audioAdapter: this.audioAdapter,
      audioSliceSec: this.config.audioSliceSec,
      autoSliceOnSpeechEnd: this.config.autoSliceOnSpeechEnd,
      vadContext: this.vadContext,

      // Whisper inference params
      language: 'en',
      beamSize: this.config.greedyDecoding ? 1 : 3,
      bestOf: this.config.greedyDecoding ? 1 : 3,
      temperature: 0,
      maxLen: 0, // No length limit
      tokenTimestamps: true,
      nThreads: this.config.nThreads,

      // Callbacks
      onTranscription: (result: any) => {
        this.handleTranscriptionResult(result);
      },
      onSliceStart: (sliceIndex: number, startSec: number) => {
        // A new audio slice has started — the previous one is being transcribed
        if (__DEV__)
          console.log(`[Realtime] Slice ${sliceIndex} started at ${startSec.toFixed(1)}s`);
      },
      onSilenceDetected: (startSec: number, durationSec: number) => {
        this.totalVadSkippedSeconds += durationSec;
        if (__DEV__)
          console.log(`[Realtime] Silence: ${durationSec.toFixed(1)}s at ${startSec.toFixed(1)}s`);
      },
    });

    // Start capture + transcription
    await this.transcriber.start();
    this.isRunning = true;
    this.isPaused = false;

    // Emit initial progress
    this.emitProgress();
  }

  /**
   * Stop real-time transcription and return all accumulated segments.
   */
  async stop(): Promise<TranscriptSegment[]> {
    if (!this.isRunning) return this.segments;

    try {
      // Stop captures any remaining audio and transcribes it
      if (this.transcriber) {
        const finalResult = await this.transcriber.stop();
        if (finalResult?.text?.trim()) {
          this.handleTranscriptionResult(finalResult);
        }
      }
    } catch (err) {
      console.warn('[RealtimeTranscriber] Error during stop:', err);
    }

    this.isRunning = false;
    this.isPaused = false;

    // Clean up
    await this.cleanup();

    return this.segments;
  }

  /**
   * Pause transcription (stops processing audio but keeps state).
   */
  pause(): void {
    if (!this.isRunning || this.isPaused) return;
    this.transcriber?.pause?.();
    this.isPaused = true;
    this.emitProgress();
  }

  /**
   * Resume transcription after pause.
   */
  resume(): void {
    if (!this.isRunning || !this.isPaused) return;
    this.transcriber?.resume?.();
    this.isPaused = false;
    this.emitProgress();
  }

  /**
   * Get current segments (without stopping).
   */
  getSegments(): TranscriptSegment[] {
    return [...this.segments];
  }

  /**
   * Get total seconds of silence skipped by VAD.
   */
  getVadSkippedSeconds(): number {
    return this.totalVadSkippedSeconds;
  }

  /**
   * Release all resources.
   */
  async destroy(): Promise<void> {
    if (this.isRunning) {
      await this.stop();
    }
    await this.cleanup();
  }

  // ── Private Methods ─────────────────────────────────────────────────────

  private async initVad(): Promise<void> {
    if (!initWhisperVad) {
      console.warn('[RealtimeTranscriber] initWhisperVad not available, proceeding without VAD');
      return;
    }

    try {
      const vadModelPath = await this.modelManager.getVadModelPath();
      this.vadContext = await initWhisperVad({
        modelPath: vadModelPath,
        threshold: this.vadConfig.speechThreshold,
        minSilenceDurationMs: this.vadConfig.minSilenceDurationMs,
        speechPadMs: this.vadConfig.speechPadMs,
      });
    } catch (err) {
      console.warn('[RealtimeTranscriber] VAD init failed:', err);
      // Continue without VAD — transcription still works, just processes silence too
      this.vadContext = null;
    }
  }

  private handleTranscriptionResult(result: any): void {
    if (!result?.text) return;

    const text = result.text.trim();
    if (!text || text === '[BLANK_AUDIO]' || text === '(blank audio)') {
      return; // Empty or hallucinated silence marker
    }

    // Hallucination detection: skip repeated phrases
    if (this.isLikelyHallucination(text)) {
      console.warn('[Realtime] Skipping likely hallucination:', text.slice(0, 50));
      return;
    }

    // Deduplication: check if this segment overlaps with recent ones
    if (this.isDuplicate(text)) {
      return;
    }

    const elapsedSec = (Date.now() - this.sessionStartTime) / 1000;
    const segmentDuration = result.endSec
      ? result.endSec - (result.startSec ?? 0)
      : this.config.audioSliceSec;

    const segment: TranscriptSegment = {
      id: this.segmentCounter++,
      start: result.startSec ?? Math.max(0, elapsedSec - segmentDuration),
      end: result.endSec ?? elapsedSec,
      text,
      confidence: result.confidence,
    };

    this.segments.push(segment);
    this.recentTexts.push(text);
    if (this.recentTexts.length > this.DEDUP_WINDOW) {
      this.recentTexts.shift();
    }

    this.emitProgress();
  }

  /**
   * Detect Whisper hallucinations:
   * - Repeated short phrases (e.g., "Thank you. Thank you. Thank you.")
   * - Common hallucination patterns on silence
   */
  private isLikelyHallucination(text: string): boolean {
    // Common whisper hallucination patterns
    const hallucinationPatterns = [
      /^(thank you\.?\s*){3,}/i,
      /^(you\.?\s*){5,}/i,
      /^(\.\s*){3,}$/,
      /^(♪\s*)+$/,
      /^\[music\]$/i,
      /^(okay\.?\s*){3,}/i,
      /^(um\.?\s*){5,}/i,
      /^(uh\.?\s*){5,}/i,
    ];

    return hallucinationPatterns.some((pattern) => pattern.test(text));
  }

  /**
   * Check if this text substantially overlaps with a recent segment.
   * This handles the overlap window at chunk boundaries.
   */
  private isDuplicate(text: string): boolean {
    const normalized = text.toLowerCase().trim();
    if (normalized.length < 10) return false; // Too short to reliably dedup

    for (const recent of this.recentTexts) {
      const recentNorm = recent.toLowerCase().trim();

      // Exact match
      if (normalized === recentNorm) return true;

      // Starts with the last ~60% of the previous segment (overlap artifact)
      const overlapThreshold = Math.floor(recentNorm.length * 0.6);
      const recentTail = recentNorm.slice(-overlapThreshold);
      if (recentTail.length > 20 && normalized.startsWith(recentTail)) {
        return true;
      }
    }

    return false;
  }

  private emitProgress(): void {
    if (!this.callback) return;

    const elapsedSeconds = (Date.now() - this.processingStartTime) / 1000;

    const progress: TranscriptionProgress = {
      state: this.isPaused ? 'paused' : this.isRunning ? 'transcribing' : 'completed',
      percentage: -1, // Indeterminate for real-time mode
      partialTranscript: this.segments.map((s) => s.text).join(' '),
      segments: [...this.segments],
      elapsedSeconds,
    };

    this.callback(progress);
  }

  private async cleanup(): Promise<void> {
    if (this.vadContext) {
      try {
        await this.vadContext.release?.();
      } catch {
        // Ignore
      }
      this.vadContext = null;
    }
    this.transcriber = null;
    this.audioAdapter = null;
    this.callback = null;
  }
}

import { TranscriptMerger } from './transcriptMerger';
import { TranscriptSegment } from './types';

jest.mock('expo-crypto', () => ({
  randomUUID: () => 'test-uuid',
}));

describe('TranscriptMerger', () => {
  let merger: TranscriptMerger;

  beforeEach(() => {
    merger = new TranscriptMerger();
  });

  describe('merge', () => {
    it('should merge segments and build full text', () => {
      const segments: TranscriptSegment[] = [
        { id: 0, start: 0, end: 5, text: 'Hello world from the transcriber.' },
        { id: 1, start: 5, end: 10, text: 'This is a test of the merger.' },
      ];
      const result = merger.merge(segments, 'Test Lecture', '2023-01-01T00:00:00Z', 10, 'base', {});

      expect(result.title).toBe('Test Lecture');
      expect(result.text).toBe('Hello world from the transcriber. This is a test of the merger.');
      expect(result.segments).toHaveLength(2);
      expect(result.segments[0].id).toBe(0);
      expect(result.segments[1].id).toBe(1);
      expect(result.id).toBe('lecture_test-uuid');
    });

    it('should sort segments by start time', () => {
      const segments: TranscriptSegment[] = [
        { id: 1, start: 5, end: 10, text: 'The second segment comes after.' },
        { id: 0, start: 0, end: 5, text: 'The first segment comes before.' },
      ];
      const result = merger.merge(segments, 'Sorted', '2023-01-01T00:00:00Z', 10, 'base', {});
      expect(result.text).toBe('The first segment comes before. The second segment comes after.');
      expect(result.segments[0].text).toBe('The first segment comes before.');
      expect(result.segments[1].text).toBe('The second segment comes after.');
    });

    it('should deduplicate overlaps', () => {
      const segments: TranscriptSegment[] = [
        { id: 0, start: 0, end: 10, text: 'the mitochondria is the powerhouse of' },
        { id: 1, start: 9, end: 20, text: 'powerhouse of the cell and it produces' },
      ];
      const result = merger.merge(segments, 'Overlap', '2023-01-01T00:00:00Z', 20, 'base', {});
      expect(result.text).toBe('the mitochondria is the powerhouse of the cell and it produces');
      expect(result.segments).toHaveLength(2);
      expect(result.segments[0].text).toBe('the mitochondria is the powerhouse of');
      expect(result.segments[1].text).toBe('the cell and it produces');
    });

    it('should fuzzy deduplicate overlaps', () => {
        // fuzzyWordMatch allows 1 word difference for overlapLen >= 4
        const segments: TranscriptSegment[] = [
          { id: 0, start: 0, end: 10, text: 'one two three four five' },
          { id: 1, start: 9, end: 20, text: 'two three something four five six' },
        ];
        // overlapLen = 5: "one two three four five" tails: "one two three four five"
        // "two three something four five six" heads: "two three something four five"
        // diffs: "one" vs "two", "two" vs "three", ... many diffs.
        
        // Let's try overlapLen = 4:
        // tailA: "two three four five"
        // headB: "two three something four"
        // diffs: 1 ("something" vs "four" ? no, "four" vs "five")
        // "two" === "two"
        // "three" === "three"
        // "four" !== "something" (diff 1)
        // "five" !== "four" (diff 2) -> fails.
        
        // Let's try:
        // textA: "this is a very long sentence"
        // textB: "is a REALLY long sentence that continues"
        // wordsA: ["this", "is", "a", "very", "long", "sentence"]
        // wordsB: ["is", "a", "REALLY", "long", "sentence", "that", "continues"]
        // overlapLen 5:
        // tailA: ["is", "a", "very", "long", "sentence"]
        // headB: ["is", "a", "REALLY", "long", "sentence"]
        // diffs: "very" vs "REALLY" (1 diff) -> Match!
        
        const segments2: TranscriptSegment[] = [
            { id: 0, start: 0, end: 10, text: 'this is a very long sentence' },
            { id: 1, start: 9, end: 20, text: 'is a REALLY long sentence that continues' },
        ];
        const result = merger.merge(segments2, 'Fuzzy Overlap', '2023-01-01T00:00:00Z', 20, 'base', {});
        // If matched with overlapLen 5:
        // remaining B: wordsB.slice(5) -> ["that", "continues"]
        expect(result.text).toBe('this is a very long sentence that continues');
    });

    it('should consolidate short segments', () => {
      const segments: TranscriptSegment[] = [
        { id: 0, start: 0, end: 5, text: 'This is a long segment.' },
        { id: 1, start: 5, end: 6, text: 'Short.' },
        { id: 2, start: 6, end: 10, text: 'Another long segment here.' },
      ];
      const result = merger.merge(segments, 'Consolidate', '2023-01-01T00:00:00Z', 10, 'base', {});
      expect(result.segments).toHaveLength(2);
      expect(result.segments[0].text).toBe('This is a long segment.');
      expect(result.segments[1].text).toBe('Short. Another long segment here.');
    });

    it('should handle edge case: only short segments', () => {
        const segments: TranscriptSegment[] = [
          { id: 0, start: 0, end: 1, text: 'One.' },
          { id: 1, start: 1, end: 2, text: 'Two.' },
          { id: 2, start: 2, end: 3, text: 'Three.' },
        ];
        const result = merger.merge(segments, 'Shorties', '2023-01-01T00:00:00Z', 3, 'base', {});
        // seg 0: "One." (1 word) -> buffer = seg 0
        // seg 1: "Two." (1 word) -> buffer = "One. Two."
        // seg 2: "Three." (1 word) -> buffer = "One. Two. Three."
        // flush buffer -> result = ["One. Two. Three."]
        expect(result.segments).toHaveLength(1);
        expect(result.segments[0].text).toBe('One. Two. Three.');
      });

    it('should handle empty segments array', () => {
      const result = merger.merge([], 'Empty', '2023-01-01T00:00:00Z', 0, 'base', {});
      expect(result.text).toBe('');
      expect(result.segments).toHaveLength(0);
    });

    it('should handle segment with no words', () => {
        const segments: TranscriptSegment[] = [
            { id: 0, start: 0, end: 5, text: 'Hello' },
            { id: 1, start: 5, end: 10, text: '   ' },
            { id: 2, start: 10, end: 15, text: 'World' },
        ];
        const result = merger.merge(segments, 'Spaces', '2023-01-01T00:00:00Z', 15, 'base', {});
        expect(result.text).toBe('Hello World');
    });
  });
});

