    subjectWeightSensitivity: 0.85,
  },
};

const MAX_DAILY_DISPLAY_MINUTES = 24 * 60;

export const SUBJECT_WORKLOAD_OVERRIDES: Record<string, number> = {
  MED: 1.35,
  SURG: 1.3,
  OBG: 1.2,
  PSM: 1.2,
  PEDS: 1.15,
  PATH: 1.12,
  PHAR: 1.08,
  ANAT: 1.08,
  PHYS: 1.05,
  MICR: 1.05,
  ORTH: 1.02,
  OPTH: 0.95,
  ENT: 0.92,
  FMT: 0.9,
  PSY: 0.88,
  DERM: 0.88,
  RADI: 0.9,
  ANES: 0.86,
  BIOC: 0.96,
};

function toDateOnly(dateLike: string | null): string | null {
  if (!dateLike) return null;
  return dateLike.slice(0, 10);
}

function buildReasonLabels(
  topic: TopicWithProgress,
  type: PlanActionType,
  today: string,
): string[] {
  const labels: string[] = [];
  const dueDate = toDateOnly(topic.progress.fsrsDue);

  if (type === 'review') {
    if (dueDate && dueDate < today) {
      const overdueDays = Math.max(
        1,
        Math.ceil((new Date(today).getTime() - new Date(dueDate).getTime()) / MS_PER_DAY),
      );
      labels.push(`Overdue ${overdueDays}d`);
    } else if (dueDate === today) {
      labels.push('Due today');
    } else {
      labels.push('Scheduled review');
    }
  }

  if (type === 'deep_dive') labels.push('Weak topic');
  if (topic.progress.confidence <= 1 && topic.progress.status !== 'unseen')
    labels.push('Foundation gap');
  if (type === 'study' && topic.progress.status === 'unseen') labels.push('Untouched');
  if (topic.inicetPriority >= 8) labels.push('High yield');
  if (topic.progress.isNemesis) labels.push('Nemesis');

  return labels.slice(0, 3);
}

function createPlanItem(
  id: string,
  topic: TopicWithProgress,
  type: PlanActionType,
  duration: number,
  today: string,
): PlanItem {
  return {
    id,
    topic,
    type,
    duration,
    reasonLabels: buildReasonLabels(topic, type, today),
  };
}

function getResourceProfile(mode: StudyResourceMode): ResourceProfile {
  return RESOURCE_PROFILES[mode] ?? RESOURCE_PROFILES.hybrid;
}

export function getDefaultSubjectLoadMultiplier(
  subjectCode: string,
  resourceMode?: StudyResourceMode,
): number {
  if (resourceMode === 'dbmci_live' && DBMCI_WORKLOAD_OVERRIDES[subjectCode]) {
    return DBMCI_WORKLOAD_OVERRIDES[subjectCode];
  }
  return SUBJECT_WORKLOAD_OVERRIDES[subjectCode] ?? 1;
}

function getSubjectLoadFactor(
  topic: TopicWithProgress,
  resourceMode: StudyResourceMode,
  customOverrides?: Record<string, number>,
): number {
  const resourceProfile = getResourceProfile(resourceMode);
  const baseline =
    customOverrides?.[topic.subjectCode] ??
    getDefaultSubjectLoadMultiplier(topic.subjectCode, resourceMode);
  return 1 + (baseline - 1) * resourceProfile.subjectWeightSensitivity;
}

function estimateActionDuration(
  topic: TopicWithProgress,
  type: PlanActionType,
  resourceMode: StudyResourceMode,
  customOverrides?: Record<string, number>,
): number {
  const profile = getResourceProfile(resourceMode);
  const baseMinutes = Math.max(topic.estimatedMinutes || 35, 20);
  const subjectFactor = getSubjectLoadFactor(topic, resourceMode, customOverrides);

  if (type === 'review') {
    return Math.round(
      (profile.reviewMinutes + (topic.inicetPriority >= 8 ? 5 : 0)) *
        Math.max(0.92, Math.min(1.15, subjectFactor)),
    );
  }

  if (type === 'deep_dive') {
    const scaled = Math.round(baseMinutes * profile.deepDiveMultiplier * subjectFactor);
    return Math.max(profile.minDeepDiveMinutes, scaled);
  }

  const scaled = Math.round(baseMinutes * profile.newTopicMultiplier * subjectFactor);
  const priorityBoost = topic.inicetPriority >= 8 ? 10 : 0;
  return Math.max(profile.minNewTopicMinutes, scaled + priorityBoost);
}

function getActiveSubjectLoadHighlights(
  resourceMode: StudyResourceMode,
  customOverrides?: Record<string, number>,
): string[] {
  const resourceProfile = getResourceProfile(resourceMode);
  const baseOverrides =
    resourceMode === 'dbmci_live'
      ? { ...SUBJECT_WORKLOAD_OVERRIDES, ...DBMCI_WORKLOAD_OVERRIDES }
      : SUBJECT_WORKLOAD_OVERRIDES;
  return Object.entries({ ...baseOverrides, ...(customOverrides ?? {}) })
    .map(([code, factor]) => ({
      code,
      applied: 1 + (factor - 1) * resourceProfile.subjectWeightSensitivity,
    }))
    .filter((item) => item.applied >= 1.1)
    .sort((a, b) => b.applied - a.applied)
    .slice(0, 4)
    .map((item) => `${item.code} ${item.applied.toFixed(2)}x`);
}

// In-memory cache to prevent heavy recomputation on every render
let cachedPlan: { plan: DailyPlan[]; summary: StudyPlanSummary } | null = null;
let lastCacheKey: string | null = null;

export function invalidatePlanCache() {
  cachedPlan = null;
  lastCacheKey = null;
}

export async function getTodaysAgendaWithTimes(): Promise<TodayTask[]> {
  const { plan } = await generateStudyPlan();
  const todayPlan = plan[0];
  if (!todayPlan || todayPlan.items.length === 0) return [];
  const todayIso = new Date().toISOString().slice(0, 10);

  const formatClock = (totalMinutes: number) => {
    const normalized = ((totalMinutes % (24 * 60)) + 24 * 60) % (24 * 60);
    const hour = Math.floor(normalized / 60);
    const minute = normalized % 60;
    return `${hour.toString().padStart(2, '0')}:${minute.toString().padStart(2, '0')}`;
  };

  const formatClockWithOffset = (totalMinutes: number) => {
    const dayOffset = Math.floor(totalMinutes / (24 * 60));
    const suffix = dayOffset > 0 ? ` (+${dayOffset}d)` : '';
    return `${formatClock(totalMinutes)}${suffix}`;
  };

  // Get user-stated availability from store
  const availability = useAppStore.getState().dailyAvailability;

  // 1. Filter items based on availability/capacity
  let items = todayPlan.items;

  // Home card should feel fresh: avoid repeating the same topic multiple times in one agenda,
  // except when a repeated item is an overdue review that must remain visible.
  const seenTopicIds = new Set<number>();
  items = items.filter((item) => {
    const due = item.topic.progress.fsrsDue?.slice(0, 10);
    const isOverdueReview = item.type === 'review' && Boolean(due && due < todayIso);
    if (isOverdueReview) return true;
    if (seenTopicIds.has(item.topic.id)) return false;
    seenTopicIds.add(item.topic.id);
    return true;
  });

  if (availability !== null) {
    // "Just Checking" -> Show nothing or maybe just 1 quick win
    if (availability === 0) return [];

    // Filter logic
    items = items.filter((item) => {
      // If short on time (< 45m), skip Deep Dives
      if (availability < 45 && item.type === 'deep_dive') return false;
      // If very short on time (< 20m), skip New Topics, keep only Reviews
      if (availability < 20 && item.type !== 'review') return false;
      return true;
    });

    // Truncate list to fit availability
    let total = 0;
    const fittingItems: PlanItem[] = [];
    for (const item of items) {
      if (total + item.duration <= availability) {
        fittingItems.push(item);
        total += item.duration;
      }
    }
    items = fittingItems;
  }

  const preferredHours = await getPreferredStudyHours();
  const now = new Date();
  const currentHour = now.getHours();

  // Filter out hours that have already passed, unless we have no future slots
  let availableHours = preferredHours.filter((h) => h >= currentHour);
  if (availableHours.length === 0) {
    // If all preferred times passed, just suggest next hour onwards
    availableHours = [currentHour + 1, currentHour + 2, currentHour + 3];
  }

  const schedule: TodayTask[] = [];
  let hourIndex = 0;
  let currentSlotMinutes = 0;

  // Group items into hour blocks
  for (const item of items) {
    const hour =
      availableHours[hourIndex] ??
      availableHours[availableHours.length - 1] + 1 + (hourIndex - availableHours.length);
    const slotStart = hour * 60 + currentSlotMinutes;
    const slotEnd = slotStart + item.duration;

    schedule.push({
      timeLabel: `${formatClockWithOffset(slotStart)} - ${formatClockWithOffset(slotEnd)}`,
      topic: item.topic,
      type: item.type,
      duration: item.duration,
    });

    currentSlotMinutes += item.duration;
    // If slot > 50 mins, move to next hour
    if (currentSlotMinutes >= 50) {
      hourIndex++;
      currentSlotMinutes = 0;
    }
  }

  return schedule;
}

export async function generateStudyPlan(
  options?: GeneratePlanOptions,
): Promise<{ plan: DailyPlan[]; summary: StudyPlanSummary }> {
  const todayStr = new Date().toISOString().slice(0, 10);
  const mode = options?.mode ?? 'balanced';
  const profile = await profileRepository.getProfile();
  const resourceMode = options?.resourceMode ?? profile.studyResourceMode ?? 'hybrid';
  const customSubjectLoads = profile.customSubjectLoadMultipliers ?? {};
  const resourceProfile = getResourceProfile(resourceMode);
  const cacheKey = JSON.stringify({
    todayStr,
    mode,
    resourceMode,
    customSubjectLoads,
    dailyGoalMinutes: options?.dailyGoalOverrideMinutes ?? profile.dailyGoalMinutes,
    inicetDate: profile.inicetDate,
    neetDate: profile.neetDate,
    dbmciClassStartDate: profile.dbmciClassStartDate ?? null,
    btrStartDate: profile.btrStartDate ?? null,
  });
  if (cachedPlan && lastCacheKey === cacheKey) {
    return cachedPlan;
  }

  const [allTopics, subjects] = await Promise.all([getAllTopicsWithProgress(), getAllSubjects()]);
  const examIntelligence = getExamTargetIntelligence(profile, profileRepository.getDaysToExam);
  const subjectWeights = new Map(
    subjects.map((s) => [s.id, getExamAwareSubjectWeight(s, examIntelligence.targetExam)]),
  );

  // 1. Initial State
  const today = new Date();
  const daysToExam = examIntelligence.daysToTarget;
  const dailyGoal =
    (options?.dailyGoalOverrideMinutes ?? profile.dailyGoalMinutes) > 0
      ? (options?.dailyGoalOverrideMinutes ?? profile.dailyGoalMinutes)
      : 120;

  // Get exam dates to mark as rest days
  const examDates = new Set([profile.inicetDate, profile.neetDate]);

  // Pending actions queue
  const pendingActions: PlanItem[] = [];

  // 2. Identify Tasks

  // A. Overdue Reviews (Priority 1)
  const due = await getTopicsDueForReview(DUE_TOPICS_FETCH_LIMIT);
  for (const t of due) {
    pendingActions.push(
      createPlanItem(
        `rev_${t.id}_init`,
        t,
        'review',
        estimateActionDuration(t, 'review', resourceMode, customSubjectLoads),
        todayStr,
      ),
    );
  }

  const { weak, newTopics } = buildPlanBuckets({
    allTopics,
    due,
    mode,
    resourceMode,
    subjectWeights,
    liveClassStartDate:
      resourceMode === 'btr'
        ? (profile.btrStartDate ?? null)
        : (profile.dbmciClassStartDate ?? null),
  });

  // B. Weak Topics (Priority 2 - Deep Dive)
  for (const t of weak) {
    pendingActions.push({
      ...createPlanItem(
        `dive_${t.id}_init`,
        t,
        'deep_dive',
        estimateActionDuration(t, 'deep_dive', resourceMode, customSubjectLoads),
        todayStr,
      ),
    });
  }

  // 2b. Mastery status counts (for summary)
  const unseenCount = allTopics.filter(
    (t) => !isParentTopic(t) && t.progress.status === 'unseen',
  ).length;
  const seenNeedingQuizCount = allTopics.filter(
    (t) => !isParentTopic(t) && t.progress.status === 'seen' && t.progress.confidence < 1,
  ).length;
  const reviewedCount = allTopics.filter(
    (t) => !isParentTopic(t) && t.progress.status === 'reviewed',
  ).length;
  const masteredCount = allTopics.filter(
    (t) => !isParentTopic(t) && t.progress.status === 'mastered',
  ).length;

  const foundationalGapTopics = allTopics.filter((t) => {
    if (isParentTopic(t)) return false;
    if (t.progress.status === 'unseen') return false;
    return t.progress.confidence <= 1 || (t.progress.wrongCount ?? 0) >= 2 || t.progress.isNemesis;
  });

  // 2c. Backlog pressure — how many days of just-reviews are sitting in the queue
  const overdueReviewMinutes = due.reduce(
    (sum, t) => sum + estimateActionDuration(t, 'review', resourceMode, customSubjectLoads),
    0,
  );
  const overdueBacklogDays =
    dailyGoal > 0 ? Math.round((overdueReviewMinutes / dailyGoal) * 10) / 10 : 0;
  // Gate new topics when overdue backlog exceeds 4× daily capacity
  const newTopicsGated = overdueBacklogDays > 4;
  const foundationalGapMinutes = foundationalGapTopics.reduce(
    (sum, t) => sum + estimateActionDuration(t, 'deep_dive', resourceMode, customSubjectLoads),
    0,
  );
  const foundationalGapDays =
    dailyGoal > 0 ? Math.round((foundationalGapMinutes / dailyGoal) * 10) / 10 : 0;
  const foundationalGapsNeedPriority = foundationalGapDays > 2;

  // C. New Topics (Priority 3 — gated when backlog is too large)
  for (const t of newTopics) {
    pendingActions.push(
      createPlanItem(
        `new_${t.id}_init`,
        t,
        'study',
        estimateActionDuration(t, 'study', resourceMode, customSubjectLoads),
        todayStr,
      ),
    );
  }

  // Sort Pending Queue: Reviews > Deep Dives > High Yield New
  // We'll just keep them in order of insertion roughly, but let's do a strict sort for the simulation
  // actually, let's keep separate queues for the simulation to interleave

  const { queueReviews, queueDeep, queueNew } = buildTopicQueues(pendingActions);

  const totalExpectedWorkloadMinutes =
    queueReviews.reduce((sum, item) => sum + item.duration, 0) +
    queueDeep.reduce(
      (sum, item) =>
        sum +
        item.duration +
        estimateActionDuration(item.topic, 'review', resourceMode, customSubjectLoads),
      0,
    ) +
    queueNew.reduce(
      (sum, item) =>
        sum +
        item.duration +
        estimateActionDuration(item.topic, 'review', resourceMode, customSubjectLoads) * 2,
      0,
    );

  // Simulation State
  const plan: DailyPlan[] = [];
  const futureReviews: Map<number, PlanItem[]> = new Map(); // DayOffset -> Items

  const daysToPlan = Math.min(daysToExam, 60);
  let totalMinutesScheduled = 0;
  const planEndDate = new Date(today);
  planEndDate.setDate(today.getDate() + daysToPlan);
  const planEndStr = planEndDate.toISOString().slice(0, 10);
  const studyDaysAvailable = Math.max(
    1,
    daysToPlan -
      Array.from(examDates).filter((date) => date >= todayStr && date <= planEndStr).length,
  );

  for (let i = 0; i < daysToPlan; i++) {
    const currentDate = new Date(today);
    currentDate.setDate(today.getDate() + i);
    const dateStr = currentDate.toISOString().slice(0, 10);

    // Check if this is an exam day - mark as rest day
    const isExamDay = examDates.has(dateStr);

    let label = dateStr;
    if (i === 0) label = 'Today';
    else if (i === 1) label = 'Tomorrow';
    else if (isExamDay)
      label = `🎯 ${currentDate.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })} (EXAM)`;
    else
      label = currentDate.toLocaleDateString('en-US', {
        weekday: 'short',
        month: 'short',
        day: 'numeric',
      });

    const dayItems: PlanItem[] = [];
    let dayMinutes = 0;

    // If exam day, don't schedule any topics - rest day
    if (isExamDay) {
      plan.push({
        date: dateStr,
        dayLabel: label,
        items: [],
        totalMinutes: 0,
        isRestDay: true,
      });
      continue;
    }

    const MAX_DAY_MINUTES = 1440;

    // 1. Must-do: Future Scheduled Reviews (SRS simulation)
    const scheduledToday = futureReviews.get(i) || [];
    futureReviews.delete(i);
    for (const item of scheduledToday) {
      if (dayMinutes + item.duration <= Math.min(dailyGoal * 1.2, MAX_DAY_MINUTES)) {
        // Allow slight overflow for reviews
        dayItems.push(item);
        dayMinutes += item.duration;
      } else {
        // Push to tomorrow if absolutely full
        const tomorrow = i + 1;
        const list = futureReviews.get(tomorrow) || [];
        list.unshift(item);
        futureReviews.set(tomorrow, list);
      }
    }

    // 2. Backlog Reviews
    while (queueReviews.length > 0 && dayMinutes < dailyGoal && dayMinutes < MAX_DAY_MINUTES) {
      const item = queueReviews.shift()!;
      dayItems.push(item);
      dayMinutes += item.duration;
    }

    // 3. Deep Dives (Limit 1 per day to avoid burnout, unless day is empty)
    let divesToday = 0;
    const deepDiveBudget = Math.max(
      dailyGoal,
      Math.round(
        dailyGoal * resourceProfile.deepDiveDailyBudgetMultiplier * examIntelligence.deepDiveBias,
      ),
    );
    while (queueDeep.length > 0 && dayMinutes < deepDiveBudget && dayMinutes < MAX_DAY_MINUTES) {
      const diveLimit = mode === 'exam_crunch' ? 2 : 1;
      const deepThreshold = mode === 'high_yield' ? deepDiveBudget * 0.85 : deepDiveBudget * 0.7;
      if (divesToday >= diveLimit && dayMinutes > deepThreshold) break; // Balance
      const item = queueDeep.shift()!;
      dayItems.push(item);
      dayMinutes += item.duration;
      divesToday++;

      // Schedule follow-up review
      const revDay = i + 2;
      const list = futureReviews.get(revDay) || [];
      list.push(
        createPlanItem(
          `rev_${item.topic.id}_post_dive`,
          item.topic,
          'review',
          estimateActionDuration(item.topic, 'review', resourceMode, customSubjectLoads),
          todayStr,
        ),
      );
      futureReviews.set(revDay, list);
    }

    // 4. New Study
    // When the overdue backlog is large (4+ days' worth), gate new topics so we clear
    // the review pile first — on day i, allow new topics only once the overdue
    // queue has been mostly absorbed.
    const baseNewTopicBudget = Math.round(
      dailyGoal * resourceProfile.newTopicDailyBudgetMultiplier,
    );
    const newTopicBudgetMultiplier =
      mode === 'exam_crunch' ? 0.55 : mode === 'high_yield' ? 0.8 : 1;
    const backlogGateFactor = newTopicsGated
      ? Math.max(0.25, 1 - Math.log2(Math.max(1, overdueBacklogDays - 3)) * 0.2) // logarithmic decay as backlog grows
      : 1;
    const foundationalGapGateFactor = foundationalGapsNeedPriority
      ? Math.max(0.2, 1 - Math.max(0, foundationalGapDays - 2) * 0.18)
      : 1;
    const newTopicBudget =
      baseNewTopicBudget *
      newTopicBudgetMultiplier *
      examIntelligence.newTopicBias *
      backlogGateFactor *
      foundationalGapGateFactor;
    while (queueNew.length > 0 && dayMinutes < newTopicBudget && dayMinutes < MAX_DAY_MINUTES) {
      const item = queueNew.shift()!;
      dayItems.push(item);
      dayMinutes += item.duration;

      // Schedule SRS reviews
      // Day + 1
      const r1 = i + 1;
      const l1 = futureReviews.get(r1) || [];
      l1.push(
        createPlanItem(
          `rev_${item.topic.id}_1`,
          item.topic,
          'review',
          estimateActionDuration(item.topic, 'review', resourceMode, customSubjectLoads),
          todayStr,
        ),
      );
      futureReviews.set(r1, l1);

      // Day + 4
      const r2 = i + 4;
      const l2 = futureReviews.get(r2) || [];
      l2.push(
        createPlanItem(
          `rev_${item.topic.id}_2`,
          item.topic,
          'review',
          estimateActionDuration(item.topic, 'review', resourceMode, customSubjectLoads),
          todayStr,
        ),
      );
      futureReviews.set(r2, l2);
    }

    plan.push({
      date: dateStr,
      dayLabel: label,
      items: dayItems,
      totalMinutes: dayMinutes,
      isRestDay: dayMinutes === 0,
    });

    totalMinutesScheduled += dayMinutes;

    // Break early if queues empty (and no future reviews pending for near future)
    if (
      queueReviews.length === 0 &&
      queueDeep.length === 0 &&
      queueNew.length === 0 &&
      futureReviews.size === 0
    ) {
      // Continue loop only to flush future reviews? No, effectively done.
      // But we might have reviews scheduled for day 60 when we are at day 5.
      // Let's just run the loop to fill the calendar.
    }
  }

  // Summary Logic
  const left = allTopics.filter((t) => t.progress.status !== 'mastered').length;

  // Total workload estimation includes the backlog + simulated reviews
  const rawRequiredMinutesPerDay =
    totalExpectedWorkloadMinutes > 0
      ? Math.ceil(totalExpectedWorkloadMinutes / Math.max(1, studyDaysAvailable))
      : 0;
  const requiredMinutesPerDay = Math.min(rawRequiredMinutesPerDay, MAX_DAILY_DISPLAY_MINUTES);
  const hoursPerDayCapped = rawRequiredMinutesPerDay > MAX_DAILY_DISPLAY_MINUTES;
  const remainingFutureReviewMinutes = Array.from(futureReviews.entries())
    .filter(([dayOffset]) => dayOffset >= daysToPlan)
    .reduce(
      (sum, [, items]) => sum + items.reduce((itemSum, item) => itemSum + item.duration, 0),
      0,
    );
  const remainingQueueMinutes =
    queueReviews.reduce((sum, item) => sum + item.duration, 0) +
    queueDeep.reduce((sum, item) => sum + item.duration, 0) +
    queueNew.reduce((sum, item) => sum + item.duration, 0) +
    remainingFutureReviewMinutes;
  const hasWorkBeyondHorizon = remainingFutureReviewMinutes > 0;
  const isFeasible = remainingQueueMinutes === 0 && rawRequiredMinutesPerDay <= dailyGoal * 1.15;

  const lastPlannedDay = [...plan].reverse().find((day) => day.totalMinutes > 0);
  const projectedFinishDate = remainingQueueMinutes > 0 ? null : (lastPlannedDay?.date ?? null);
  const projectedFinishOffset = projectedFinishDate
    ? Math.max(
        0,
        Math.ceil(
          (new Date(projectedFinishDate).getTime() - new Date(todayStr).getTime()) / MS_PER_DAY,
        ),
      )
    : 0;
  const bufferDays = Math.max(0, daysToExam - projectedFinishOffset - 1);

  let message = 'On track.';
  if (mode === 'high_yield')
    message = 'High-yield mode: prioritizing the most exam-relevant topics first.';
  if (mode === 'exam_crunch')
    message = 'Exam crunch mode: review-heavy with only the highest-yield new topics.';
  if (newTopicsGated)
    message = `Review backlog is ${overdueBacklogDays}d deep — new topics are gated until it clears. Focus on reviews first.`;
  else if (foundationalGapsNeedPriority)
    message = `Foundational gaps are ~${foundationalGapDays}d deep — plan is prioritizing weak basics before adding many new topics.`;
  else if (hoursPerDayCapped)
    message = `Impossible timeline: needs ${Number((rawRequiredMinutesPerDay / 60).toFixed(1))}h/day. Extend the exam date, reduce scope, or lower resource load.`;
  else if (hasWorkBeyondHorizon)
    message = `Planned work extends beyond the visible ${daysToPlan}-day horizon. Continue daily and roll forward.`;
  else if (remainingQueueMinutes > 0)
    message = `Course load exceeds the current horizon. Raise the daily goal or switch to a lighter resource profile.`;
  else if (rawRequiredMinutesPerDay > dailyGoal)
    message = `Heavy load! ${Number((rawRequiredMinutesPerDay / 60).toFixed(1))}h/day required with ${resourceProfile.label}.`;
  else if (projectedFinishDate)
    message = `Projected finish ${projectedFinishDate}${bufferDays > 0 ? ` with ${bufferDays} buffer days.` : '.'}`;
  else message = 'Plan looks solid. Stick to it!';

  message = `${message} ${examIntelligence.targetExam} phase: ${examIntelligence.phaseLabel}. ${examIntelligence.plannerFocus}`;

  const result = {
    plan,
    summary: {
      totalTopicsLeft: left,
      totalHoursLeft: Number((totalExpectedWorkloadMinutes / 60).toFixed(1)),
      hoursBeyondHorizon: Number((remainingFutureReviewMinutes / 60).toFixed(1)),
      targetExam: examIntelligence.targetExam,
      targetExamDate: examIntelligence.targetDate,
      daysToInicet: examIntelligence.daysToInicet,
      daysToNeetPg: examIntelligence.daysToNeetPg,
      phaseLabel: examIntelligence.phaseLabel,
      phaseFocus: examIntelligence.plannerFocus,
      daysRemaining: daysToExam,
      requiredHoursPerDay: Number((requiredMinutesPerDay / 60).toFixed(1)),
      requiredHoursPerDayRaw: Number((rawRequiredMinutesPerDay / 60).toFixed(1)),
      hoursPerDayCapped,
      feasible: isFeasible,
      hasWorkBeyondHorizon,
      message,
      projectedFinishDate,
      bufferDays,
      resourceMode,
      resourceLabel: resourceProfile.label,
      workloadAssumption: resourceProfile.workloadAssumption,
      subjectLoadHighlights: getActiveSubjectLoadHighlights(resourceMode, customSubjectLoads),
      unseenCount,
      seenNeedingQuizCount,
      reviewedCount,
      masteredCount,
      overdueBacklogDays,
      newTopicsGated,
    },
  };

  cachedPlan = result;
  lastCacheKey = cacheKey;
  return result;
}

import * as FileSystemLegacy from 'expo-file-system/legacy';
import { Platform } from 'react-native';
import { profileRepository } from '../db/repositories';
import { generateSecureRandomString } from './cryptoUtils';
import { buildLectureArtifactFileName } from './lecture/lectureIdentity';
import { isFileUri, stripFileUri, toFileUri } from './fileUri';
import { copyFileToPublicBackup } from '../../modules/app-launcher';

const TRANSCRIPT_DIR = FileSystemLegacy.documentDirectory + 'transcripts/';
const RECOVERY_DIR = FileSystemLegacy.documentDirectory + 'recovery/';
const BACKUP_ROOT = FileSystemLegacy.documentDirectory + 'backups/';
const PUBLIC_TRANSCRIPT_DIR = BACKUP_ROOT + 'Transcripts/';
const PUBLIC_NOTES_DIR = BACKUP_ROOT + 'Notes/';
const TRANSCRIPT_LOAD_FAILED_MESSAGE = 'Transcript file could not be loaded.';

// Durable external backups on Android should go through SAF when configured.
// The local fallback stays inside app-controlled storage instead of hardcoding /sdcard paths.

export interface LectureStorageIdentity {
  subjectName?: string | null;
  topics?: string[] | null;
}

async function ensureDirectoryExists(path: string): Promise<void> {
  const dirInfo = await FileSystemLegacy.getInfoAsync(path);
  if (!dirInfo?.exists) {
    await FileSystemLegacy.makeDirectoryAsync(path, { intermediates: true });
  }
}

async function backupTextToConfiguredSaf(
  backupDirectoryUri: string | null | undefined,
  fileName: string,
  content: string,
  successLogPrefix: string,
  failureLogPrefix: string,
): Promise<void> {
  if (!(Platform.OS === 'android' && backupDirectoryUri)) return;

  try {
    const { StorageAccessFramework } = FileSystemLegacy;
    const backupUri = await StorageAccessFramework.createFileAsync(
      backupDirectoryUri,
      fileName,
      'text/plain',
    );
    await FileSystemLegacy.writeAsStringAsync(backupUri, content, {
      encoding: FileSystemLegacy.EncodingType.UTF8,
    });
    if (__DEV__) console.log(successLogPrefix, fileName);
  } catch (safErr) {
    console.warn(failureLogPrefix, safErr);
  }
}

async function copyNativePublicBackupWithLogging(
  localUri: string,
  fileName: string,
  successLogPrefix: string,
  failureLogPrefix: string,
): Promise<void> {
  try {
    await copyFileToPublicBackup(stripFileUri(localUri), fileName);
    if (__DEV__) console.log(successLogPrefix, fileName);
  } catch (err) {
    console.warn(failureLogPrefix, err);
  }
}

function fromFileUri(path: string, preserveRawPath: boolean): string {
  return preserveRawPath ? stripFileUri(path) : path;
}

export async function backupNoteToPublic(
  noteId: number,
  identity: LectureStorageIdentity,
  noteText: string,
) {
  try {
    const profile = await profileRepository.getProfile();
    const fileName = buildLectureArtifactFileName('note', identity, Date.now(), '.txt');

    await backupTextToConfiguredSaf(
      profile.backupDirectoryUri,
      fileName,
      noteText,
      '[TranscriptStorage] Note cloud backup saved:',
      '[TranscriptStorage] Note cloud backup failed:',
    );

    // 2. Local Public Backup
    await ensureDirectoryExists(PUBLIC_NOTES_DIR);
    const localUri = PUBLIC_NOTES_DIR + fileName;
    await FileSystemLegacy.writeAsStringAsync(localUri, noteText, {
      encoding: FileSystemLegacy.EncodingType.UTF8,
    });
    await copyNativePublicBackupWithLogging(
      localUri,
      fileName,
      '[TranscriptStorage] Note native backup saved:',
      '[TranscriptStorage] Note backup failed:',
    );
  } catch (e) {
    console.warn('[TranscriptStorage] Note backup failed:', e);
  }
}

export async function moveFileToRecovery(fileUri: string): Promise<string> {
  await FileSystemLegacy.makeDirectoryAsync(RECOVERY_DIR, { intermediates: true });
  const fileName = 'recovery_' + Date.now() + '_' + generateSecureRandomString(7) + '.m4a';
  const targetUri = RECOVERY_DIR + fileName;
  try {
    await FileSystemLegacy.copyAsync({ from: fileUri, to: targetUri });
    return targetUri;
  } catch (err) {
    console.warn('[TranscriptStorage] Failed to move file to recovery:', err);
    return fileUri;
  }
}

export async function saveTranscriptToFile(
  transcriptText: string,
  identity?: LectureStorageIdentity,
): Promise<string | null> {
  const normalized = transcriptText.trim();
  if (!normalized) return null;
  if (isFileUri(normalized)) return normalized;

  const profile = await profileRepository.getProfile();
  await FileSystemLegacy.makeDirectoryAsync(TRANSCRIPT_DIR, { intermediates: true });
  const fileName = buildLectureArtifactFileName('transcript', identity ?? {}, Date.now(), '.txt');
  const fileUri = TRANSCRIPT_DIR + fileName;

  await FileSystemLegacy.writeAsStringAsync(fileUri, normalized, {
    encoding: FileSystemLegacy.EncodingType.UTF8,
  });

  // CRITICAL: AUTO-BACKUP to Public/Cloud Storage
  if (!profile) return toFileUri(fileUri);

  await backupTextToConfiguredSaf(
    profile.backupDirectoryUri,
    fileName,
    normalized,
    '[TranscriptStorage] Transcript cloud backup saved:',
    '[TranscriptStorage] Transcript cloud backup failed:',
  );

  // 2. Local Public Backup (Native)
  await copyNativePublicBackupWithLogging(
    fileUri,
    fileName,
    '[TranscriptStorage] Native public backup saved:',
    '[TranscriptStorage] Native public backup failed:',
  );
  // Ensure loadTranscriptFromFile can recognize this as a file URI
  return toFileUri(fileUri);
}

export async function renameRecordingToLectureIdentity(
  recordingPath: string,
  identity: LectureStorageIdentity,
): Promise<string> {
  if (!recordingPath) return recordingPath;

  const preserveRawPath = !isFileUri(recordingPath);
  const sourceUri = toFileUri(recordingPath);
  const sourceInfo = await FileSystemLegacy.getInfoAsync(sourceUri);
  if (!sourceInfo.exists) return recordingPath;

  const extensionMatch = sourceUri.match(/\.[a-z0-9]+$/i);
  const extension = extensionMatch?.[0] ?? '.m4a';
  const targetUri = sourceUri.replace(
    /[^/]+$/,
    buildLectureArtifactFileName('recording', identity, Date.now(), extension),
  );

  if (targetUri === sourceUri) return recordingPath;

  try {
    await FileSystemLegacy.deleteAsync(targetUri, { idempotent: true });
    await FileSystemLegacy.moveAsync({ from: sourceUri, to: targetUri });
    return fromFileUri(targetUri, preserveRawPath);
  } catch (err) {
    console.warn('[TranscriptStorage] Recording rename failed:', err);
    return recordingPath;
  }
}

export async function loadTranscriptFromFile(
  transcriptUriOrText: string | null,
): Promise<string | null> {
  if (!transcriptUriOrText) return null;
  if (!isFileUri(transcriptUriOrText)) return transcriptUriOrText;

  try {
    const content = await FileSystemLegacy.readAsStringAsync(transcriptUriOrText, {
      encoding: FileSystemLegacy.EncodingType.UTF8,
    });
    return content;
  } catch (err) {
    // FAILED — it might be a stale absolute path from a previous app version/install
    // Extract filename and try to find it in current TRANSCRIPT_DIR
    const parts = transcriptUriOrText.split('/');
    const fileName = parts[parts.length - 1];
    const currentUri = TRANSCRIPT_DIR + fileName;

    if (currentUri === transcriptUriOrText) {
      // It's already the current path, so it really is missing
      console.warn('[TranscriptStorage] Failed to read transcript file (not found):', err);
      return TRANSCRIPT_LOAD_FAILED_MESSAGE;
    }

    try {
      const content = await FileSystemLegacy.readAsStringAsync(currentUri, {
        encoding: FileSystemLegacy.EncodingType.UTF8,
      });
      if (__DEV__)
        console.log(
          '[TranscriptStorage] Successfully recovered transcript from new path:',
          currentUri,
        );
      return content;
    } catch (err2) {
      console.warn(
        '[TranscriptStorage] Failed to read transcript file from both old and new paths:',
        err,
        err2,
      );
      return TRANSCRIPT_LOAD_FAILED_MESSAGE;
    }
  }
}

/**
 * Resolves transcript column value (file URI or raw text) to actual transcript text.
 * Use when re-analyzing or enhancing notes so the LLM always receives text, not a path.
 */
export async function getTranscriptText(uriOrText: string | null): Promise<string | null> {
  if (uriOrText == null || uriOrText.trim() === '') return null;
  return loadTranscriptFromFile(uriOrText);
}

import { generateJSONWithRouting } from '../aiService';
import { z } from 'zod';

export const LectureAnalysisSchema = z.object({
  subject: z.string().nullable().catch('Unknown'),
  topics: z.array(z.string()).catch([]),
  key_concepts: z.array(z.string()).catch([]),
  high_yield_highlights: z.array(z.string()).catch([]),
  lecture_summary: z.string().nullable().catch('Lecture content recorded.'),
  estimated_confidence: z.number().min(1).max(3).catch(1),
});

export type LectureAnalysis = {
  subject: string;
  topics: string[];
  keyConcepts: string[];
  highYieldPoints: string[];
  lectureSummary: string;
  estimatedConfidence: 1 | 2 | 3;
  transcript?: string;
  modelUsed?: string;
  embedding?: number[] | null;
};

export interface TranscriptAnalysisProgress {
  message: string;
  detail?: string;
  currentStep: number;
  totalSteps: number;
  percent: number;
}

const NON_MEANINGFUL_SUMMARIES = new Set([
  'No audio recorded (empty file)',
  'No speech detected (silent audio)',
  'No speech detected',
  'Lecture content recorded',
  'No medical content detected',
  'Lecture content recorded. Review transcript for details.',
  'Lecture summary captured.',
]);
const isDev = typeof __DEV__ !== 'undefined' && __DEV__;

const MEDICAL_EXTRACT_PROMPT = `You are a medical scribe. Extract key clinical facts, subject, and topics from the following transcript segment.`;
const META_SUMMARIZE_PROMPT = `Combine the following medical transcript segment analyses into a single coherent lecture analysis.`;
const ANALYSIS_COMPLEXITY = 'low' as const;

function normalizeSummary(summary: string | null | undefined): string {
  return summary?.trim().replace(/[.]+$/, '') ?? '';
}

function hasMeaningfulSummary(summary: string | null | undefined): boolean {
  const normalized = normalizeSummary(summary);
  return (
    !!normalized &&
    !NON_MEANINGFUL_SUMMARIES.has(normalized) &&
    !NON_MEANINGFUL_SUMMARIES.has(`${normalized}.`)
  );
}

function cleanTopicLabel(topic: string): string {
  return topic.replace(/\s+/g, ' ').trim();
}

function buildLectureFallbackTitle(parsed: ParsedAnalysis): string {
  const subject = parsed.subject?.trim();
  const topics = (Array.isArray(parsed.topics) ? parsed.topics : [])
    .map(cleanTopicLabel)
    .filter(Boolean)
    .slice(0, 2);
  const keyConcepts = (Array.isArray(parsed.key_concepts) ? parsed.key_concepts : [])
    .map(cleanTopicLabel)
    .filter(Boolean)
    .slice(0, 2);

  if (topics.length >= 2) {
    return `${topics[0]} & ${topics[1]}`;
  }
  if (topics.length === 1) {
    return topics[0];
  }
  if (subject && subject !== 'Unknown' && keyConcepts.length >= 2) {
    return `${subject}: ${keyConcepts[0]} & ${keyConcepts[1]}`;
  }
  if (subject && subject !== 'Unknown' && keyConcepts.length === 1) {
    return `${subject}: ${keyConcepts[0]}`;
  }
  if (subject && subject !== 'Unknown') {
    return `${subject} Lecture Highlights`;
  }
  if (keyConcepts.length >= 2) {
    return `${keyConcepts[0]} & ${keyConcepts[1]}`;
  }
  if (keyConcepts.length === 1) {
    return keyConcepts[0];
  }
  return 'Lecture Review Notes';
}

/**
 * Split transcript into manageable segments for hierarchical analysis.
 */
function splitTranscript(transcript: string, maxChars = 12000): string[] {
  const segments: string[] = [];
  let currentPos = 0;
  while (currentPos < transcript.length) {
    segments.push(transcript.slice(currentPos, currentPos + maxChars));
    currentPos += maxChars;
  }
  return segments;
}

export async function analyzeTranscript(
  transcript: string,
  onProgress?: (progress: TranscriptAnalysisProgress) => void,
): Promise<LectureAnalysis> {
  const segments = splitTranscript(transcript);
  const segmentAnalyses: LectureAnalysis[] = [];
  const totalSteps = segments.length + (segments.length > 1 ? 1 : 0);

  for (let i = 0; i < segments.length; i++) {
    onProgress?.({
      message:
        segments.length === 1
          ? 'Extracting subject, topics, and key concepts'
          : `Analyzing transcript segment ${i + 1} of ${segments.length}`,
      detail:
        segments.length === 1
          ? 'Identifying the lecture subject and high-yield points'
          : 'Summarizing this transcript slice before combining the full lecture',
      currentStep: i + 1,
      totalSteps,
      percent: Math.round(((i + 1) / totalSteps) * 100),
    });
    if (isDev) console.log(`[Analysis] Analyzing segment ${i + 1}/${segments.length}`);
    try {
      const analysis = await runSingleAnalysisPass(segments[i]);
      segmentAnalyses.push(analysis);
    } catch (_e) {
      console.warn(`[Analysis] Failed to analyze segment ${i}, skipping.`);
    }
  }

  if (segmentAnalyses.length === 0) {
    console.warn('[Analysis] All segment analyses failed, returning fallback.');
    return {
      subject: 'Unknown',
      topics: [],
      keyConcepts: [],
      highYieldPoints: [],
      lectureSummary: 'Lecture Review Notes',
      estimatedConfidence: 1,
    };
  }

  if (segmentAnalyses.length === 1) {
    return segmentAnalyses[0];
  }

  onProgress?.({
    message: 'Combining segment analyses into one lecture summary',
    detail: 'Merging subject guesses, topics, and high-yield takeaways',
    currentStep: totalSteps,
    totalSteps,
    percent: 100,
  });

  return metaSummarize(segmentAnalyses);
}

export function isMeaningfulLectureAnalysis(analysis: Partial<LectureAnalysis> | null | undefined) {
  if (!analysis?.transcript?.trim()) {
    return false;
  }

  if ((analysis.topics?.length ?? 0) > 0) return true;
  if ((analysis.keyConcepts?.length ?? 0) > 0) return true;
  if ((analysis.highYieldPoints?.length ?? 0) > 0) return true;

  const summary = analysis.lectureSummary?.trim();
  return !!summary && !NON_MEANINGFUL_SUMMARIES.has(summary);
}

async function runSingleAnalysisPass(text: string): Promise<LectureAnalysis> {
  const extractPrompt = `${MEDICAL_EXTRACT_PROMPT}\n\nHere is the transcript segment:\n"""\n${text}\n"""`;
  const { parsed, modelUsed } = await generateJSONWithRouting(
    [{ role: 'user', content: extractPrompt }],
    LectureAnalysisSchema,
    ANALYSIS_COMPLEXITY,
    true,
    'groq',
  );
  return { ...mapParsedAnalysis(parsed), modelUsed };
}

async function metaSummarize(analyses: LectureAnalysis[]): Promise<LectureAnalysis> {
  const aggregatedInput = analyses
    .map(
      (a, i) => `
Segment ${i + 1}:
- Subject: ${a.subject}
- Topics: ${a.topics.join(', ')}
- Key Concepts: ${a.keyConcepts.join('; ')}
- High Yield: ${a.highYieldPoints.join('; ')}
- Summary: ${a.lectureSummary}
`,
    )
    .join('\n');

  const extractPrompt = `${META_SUMMARIZE_PROMPT}\n\nHere are the segment summaries:\n"""\n${aggregatedInput}\n"""`;

  if (isDev) console.log('[Analysis] Running final meta-summarization pass...');
  try {
    const { parsed, modelUsed } = await generateJSONWithRouting(
      [{ role: 'user', content: extractPrompt }],
      LectureAnalysisSchema,
      ANALYSIS_COMPLEXITY,
      true,
      'groq',
    );
    return { ...mapParsedAnalysis(parsed), modelUsed };
  } catch (_err) {
    console.warn('[Analysis] Meta-summarization failed, using basic aggregation fallback.');
    // Fallback: Just smash everything together and take the first few
    return {
      subject: analyses[0]?.subject ?? 'Unknown',
      topics: [...new Set(analyses.flatMap((a: LectureAnalysis) => a.topics))].slice(0, 5),
      keyConcepts: [...new Set(analyses.flatMap((a: LectureAnalysis) => a.keyConcepts))].slice(
        0,
        8,
      ),
      highYieldPoints: [
        ...new Set(analyses.flatMap((a: LectureAnalysis) => a.highYieldPoints)),
      ].slice(0, 5),
      lectureSummary:
        analyses
          .map((a: LectureAnalysis) => a.lectureSummary)
          .join(' ')
          .slice(0, 200) + '...',
      estimatedConfidence: Math.max(
        1,
        Math.min(3, Math.round(analyses[0]?.estimatedConfidence ?? 2)),
      ) as 1 | 2 | 3,
    };
  }
}

interface ParsedAnalysis {
  subject?: string | null;
  topics?: string[];
  key_concepts?: string[];
  high_yield_highlights?: string[];
  lecture_summary?: string | null;
  estimated_confidence?: number;
}

function parseArrayOrString(val: any, limit: number): string[] {
  if (Array.isArray(val)) return val.slice(0, limit);
  if (typeof val === 'string')
    return val
      .split(',')
      .map((s) => s.trim())
      .filter(Boolean)
      .slice(0, limit);
  return [];
}

function mapParsedAnalysis(parsed: ParsedAnalysis): LectureAnalysis {
  const lectureSummary = hasMeaningfulSummary(parsed.lecture_summary)
    ? parsed.lecture_summary!.trim()
    : buildLectureFallbackTitle(parsed);
  return {
    subject: parsed.subject ?? 'Unknown',
    topics: parseArrayOrString(parsed.topics, 5),
    keyConcepts: parseArrayOrString(parsed.key_concepts, 8),
    highYieldPoints: parseArrayOrString(parsed.high_yield_highlights, 5),
    lectureSummary,
    estimatedConfidence: Math.max(1, Math.min(3, Math.round(parsed.estimated_confidence ?? 2))) as
      | 1
      | 2
      | 3,
  };
}

/**
 * deepgramLive.ts — WebSocket-based live transcription via Deepgram Nova-2 Medical.
 *
 * Streams audio chunks to Deepgram and emits interim/final transcript fragments.
 * Optionally runs a lightweight topic-extraction pass every ~30s of accumulated text.
 */

type TranscriptCallback = (text: string, isFinal: boolean) => void;
type LiveTopicsCallback = (topics: string[], concepts: string[]) => void;

const TOPIC_EXTRACTION_INTERVAL_MS = 30_000;

export class DeepgramLiveTranscriber {
  private ws: WebSocket | null = null;
  private apiKey: string;
  private accumulatedTranscript = '';
  private topicExtractionTimer: ReturnType<typeof setInterval> | null = null;
  private connected = false;

  onTranscript: TranscriptCallback = () => {};
  onLiveTopics: LiveTopicsCallback | null = null;
  onError: ((error: Error) => void) | null = null;
  onClose: (() => void) | null = null;

  constructor(apiKey: string) {
    this.apiKey = apiKey;
  }

  /** Open WebSocket connection to Deepgram. */
  connect(options?: { model?: string; language?: string }): void {
    if (this.ws) this.disconnect();

    const model = options?.model ?? 'nova-2-medical';
    const language = options?.language ?? 'en';
    const params = new URLSearchParams({
      model,
      language,
      smart_format: 'true',
      punctuate: 'true',
      interim_results: 'true',
      endpointing: '300',
      encoding: 'linear16',
      sample_rate: '16000',
      channels: '1',
    });

    const url = `wss://api.deepgram.com/v1/listen?${params.toString()}`;

    // React Native WebSocket accepts (url, protocols, options) but TS types only allow 2 args.
    // Pass auth via the protocols parameter as a workaround; Deepgram also accepts query param.
    const authUrl = `${url}&token=${this.apiKey}`;
    this.ws = new WebSocket(authUrl);

    this.ws.onopen = () => {
      this.connected = true;
      this.startTopicExtraction();
    };

    this.ws.onmessage = (event: WebSocketMessageEvent) => {
      try {
        const data = JSON.parse(event.data as string);
        const alt = data?.channel?.alternatives?.[0];
        if (!alt) return;

        const transcript = alt.transcript ?? '';
        const isFinal = data.is_final === true;

        if (transcript.trim()) {
          this.onTranscript(transcript, isFinal);
          if (isFinal) {
            this.accumulatedTranscript += ' ' + transcript;
          }
        }
      } catch (err) {
        if (__DEV__) console.warn('[DeepgramLive] Parse error:', err);
      }
    };

    this.ws.onerror = (event: Event) => {
      const msg = (event as any)?.message ?? 'WebSocket error';
      this.onError?.(new Error(msg));
    };

    this.ws.onclose = () => {
      this.connected = false;
      this.stopTopicExtraction();
      this.onClose?.();
    };
  }

  /** Send a chunk of raw PCM audio (base64-encoded) to Deepgram. */
  sendAudioChunk(pcmBase64: string): void {
    if (!this.ws || !this.connected) return;
    try {
      // Decode base64 to binary and send
      const binaryString = atob(pcmBase64);
      const bytes = new Uint8Array(binaryString.length);
      for (let i = 0; i < binaryString.length; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }
      this.ws.send(bytes.buffer);
    } catch (err) {
      if (__DEV__) console.warn('[DeepgramLive] Send error:', err);
    }
  }

  /** Send raw ArrayBuffer audio data. */
  sendAudioBuffer(buffer: ArrayBuffer): void {
    if (!this.ws || !this.connected) return;
    try {
      this.ws.send(buffer);
    } catch (err) {
      if (__DEV__) console.warn('[DeepgramLive] Send buffer error:', err);
    }
  }

  /** Gracefully close the connection. */
  disconnect(): void {
    this.stopTopicExtraction();
    if (this.ws) {
      try {
        // Send close frame per Deepgram protocol
        this.ws.send(JSON.stringify({ type: 'CloseStream' }));
      } catch {
        // Already closed
      }
      this.ws.close();
      this.ws = null;
    }
    this.connected = false;
  }

  /** Get the full accumulated transcript so far. */
  getAccumulatedTranscript(): string {
    return this.accumulatedTranscript.trim();
  }

  /** Check if currently connected. */
  isConnected(): boolean {
    return this.connected;
  }

  // ── Topic extraction ────────────────────────────────────────────────────────

  private startTopicExtraction(): void {
    if (!this.onLiveTopics) return;
    this.topicExtractionTimer = setInterval(() => {
      this.extractTopics();
    }, TOPIC_EXTRACTION_INTERVAL_MS);
  }

  private stopTopicExtraction(): void {
    if (this.topicExtractionTimer) {
      clearInterval(this.topicExtractionTimer);
      this.topicExtractionTimer = null;
    }
  }

  private async extractTopics(): Promise<void> {
    if (!this.onLiveTopics) return;
    const text = this.accumulatedTranscript.trim();
    if (text.length < 100) return; // Not enough text yet

    try {
      // Lazy-import to avoid circular deps and keep this module lightweight
      const { generateTextWithRouting } = await import('../ai/generate');
      const prompt = `Extract the medical topics and key concepts from this lecture transcript segment. Return ONLY a JSON object like: {"topics": ["topic1", "topic2"], "concepts": ["concept1", "concept2"]}

Transcript:
${text.slice(-2000)}`;

      const { text: response } = await generateTextWithRouting(
        [
          { role: 'system', content: 'You are a medical lecture topic extractor. Return only valid JSON.' },
          { role: 'user', content: prompt },
        ],
        { preferCloud: true },
      );

      const parsed = JSON.parse(response);
      if (parsed.topics || parsed.concepts) {
        this.onLiveTopics(parsed.topics ?? [], parsed.concepts ?? []);
      }
    } catch (err) {
      if (__DEV__) console.warn('[DeepgramLive] Topic extraction failed:', err);
    }
  }
}

import * as FileSystem from 'expo-file-system/legacy';
import { convertToWav } from '../../../modules/app-launcher';
import { BatchTranscriber } from '../offlineTranscription/batchTranscriber';
import { DEFAULT_HF_TRANSCRIPTION_MODEL } from '../../config/appConfig';
import { toFileUri } from '../fileUri';
import { getWhisperModelManager } from '../offlineTranscription/whisperModelManager';

const WHISPER_MEDICAL_PROMPT =
  'Medical lecture: NEET-PG, INICET preparation. ' +
  'Common terms: hemostasis, renin-angiotensin system, glomerular filtration rate, ' +
  'brachial plexus, pneumonia, cirrhosis, pharmacokinetics, pharmacodynamics, ' +
  'myocardial infarction, atherosclerosis, nephrotic syndrome, ' +
  'ECG, ABG, CSF, MRI, CT scan, CBC, LFT, RFT, ABG. ' +
  'Hindi-English mix (Hinglish). Toh, matlab, yahan pe, dekhiye, samajh lo.';

// Known Whisper hallucination patterns on silent/short audio
const HALLUCINATION_PATTERNS = [
  /^(thank you\.?\s*){2,}$/i,
  /^(thanks for watching\.?\s*){1,}$/i,
  /^(please subscribe\.?\s*){1,}$/i,
  /^(♪\s*)+$/,
  /^\[music\]$/i,
  /^\[silence\]$/i,
  /^\(silence\)$/i,
  /^\[blank audio\]$/i,
  /^(okay\.?\s*){3,}$/i,
  /^(um\.?\s*){3,}$/i,
  /^(uh\.?\s*){3,}$/i,
  /^(you\.?\s*){4,}$/i,
  // Repeated phrase hallucinations (e.g. "The muscles. The muscles. The muscles.")
  /^(.{5,40})\s*[.,]?\s*(\1\s*[.,]?\s*){2,}$/i,
];

const HUGGINGFACE_MAX_SAFE_UPLOAD_BYTES = 20 * 1024 * 1024;
const LOCAL_WHISPER_BATCH_THRESHOLD_BYTES = 24 * 1024 * 1024;
const GROQ_MAX_SAFE_UPLOAD_BYTES = 25 * 1024 * 1024;
const TRANSCRIPTION_BASE_TIMEOUT_MS = 45_000;
const TRANSCRIPTION_UPLOAD_BYTES_PER_SECOND = 500_000;

// Keep local Whisper transcriptions serialized.
// whisper.rn contexts are native resources and should not be shared concurrently.
let _whisperTranscriptionMutex: Promise<void> = Promise.resolve();
function acquireWhisperTranscriptionMutex(): Promise<() => void> {
  let release!: () => void;
  const prev = _whisperTranscriptionMutex;
  _whisperTranscriptionMutex = new Promise<void>((resolve) => {
    release = resolve;
  });
  return prev.then(() => release);
}

function isLikelyHallucination(text: string): boolean {
  const trimmed = text.trim();
  if (!trimmed) return false;
  // Very short single-sentence transcripts from what should be a long recording
  // are usually hallucinations — handled at call site with file size check.
  return HALLUCINATION_PATTERNS.some((p) => p.test(trimmed));
}

function sanitizeTranscript(rawTranscript: string): string {
  const NOISE_PATTERNS = /^\s*(\(background noise\)|\[music\]|\*silence\*|\[inaudible\])\s*$/i;

  const cleaned = rawTranscript
    .split('\n')
    .map((l) => l.trim())
    .filter((l) => l && !NOISE_PATTERNS.test(l))
    .join('\n')
    .trim();

  if (!cleaned && rawTranscript.trim().length > 0) {
    return rawTranscript.trim();
  }
  return cleaned;
}

function getAudioMimeType(audioFilePath: string): string {
  const normalizedPath = audioFilePath.toLowerCase();
  if (normalizedPath.endsWith('.wav')) return 'audio/wav';
  if (normalizedPath.endsWith('.mp3')) return 'audio/mpeg';
  if (normalizedPath.endsWith('.aac')) return 'audio/aac';
  if (normalizedPath.endsWith('.m4a') || normalizedPath.endsWith('.mp4')) return 'audio/mp4';
  return 'application/octet-stream';
}

function formatMegabytes(bytes: number): string {
  return `${Math.round(bytes / (1024 * 1024))} MB`;
}

function computeTranscriptionTimeoutMs(fileSizeBytes?: number | null): number {
  if (!fileSizeBytes || fileSizeBytes <= 0) {
    return TRANSCRIPTION_BASE_TIMEOUT_MS;
  }
  const uploadEstimateMs = Math.ceil(
    (fileSizeBytes / TRANSCRIPTION_UPLOAD_BYTES_PER_SECOND) * 1000,
  );
  return Math.max(TRANSCRIPTION_BASE_TIMEOUT_MS, uploadEstimateMs + 15_000);
}

async function fetchWithTimeout(
  input: Parameters<typeof fetch>[0],
  init: Parameters<typeof fetch>[1],
  timeoutMs: number,
  label: string,
): Promise<Response> {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);

  try {
    return await fetch(input, {
      ...init,
      signal: controller.signal,
    });
  } catch (error) {
    if (error instanceof Error && error.name === 'AbortError') {
      throw new Error(`${label} timed out after ${Math.round(timeoutMs / 1000)}s`, {
        cause: error,
      });
    }
    throw error;
  } finally {
    clearTimeout(timeout);
  }
}

/** Cloud fallback: Groq Whisper transcription */
export async function transcribeRawWithGroq(
  audioFilePath: string,
  groqKey: string,
): Promise<string> {
  if (!groqKey?.trim()) {
    throw new Error('Groq API key missing. Add one in Settings or enable Local Whisper.');
  }
  const fileUri = toFileUri(audioFilePath);
  const fileInfo = await FileSystem.getInfoAsync(fileUri);
  if (!fileInfo?.exists || fileInfo.size === 0) {
    throw new Error(`Audio file is missing or empty: ${audioFilePath}`);
  }
  if (fileInfo.size > GROQ_MAX_SAFE_UPLOAD_BYTES) {
    throw new Error(
      `Groq transcription is limited to ${formatMegabytes(GROQ_MAX_SAFE_UPLOAD_BYTES)} files in Guru. Use chunked transcription for larger recordings.`,
    );
  }
  const timeoutMs = computeTranscriptionTimeoutMs(fileInfo.size);

  const formData = new FormData();
  formData.append('file', {
    uri: fileUri,
    name: 'lecture.m4a',
    type: 'audio/mp4',
  } as any);
  formData.append('model', 'whisper-large-v3-turbo');
  formData.append('temperature', '0');
  formData.append('prompt', WHISPER_MEDICAL_PROMPT);

  console.log('[LecturePipeline] Groq transcription request starting', {
    audioFilePath,
    model: 'whisper-large-v3-turbo',
    fileSizeBytes: fileInfo.size,
    timeoutMs,
  });

  const res = await fetchWithTimeout(
    'https://api.groq.com/openai/v1/audio/transcriptions',
    {
      method: 'POST',
      headers: { Authorization: `Bearer ${groqKey}` },
      body: formData,
    },
    timeoutMs,
    'Groq transcription',
  );

  if (!res.ok) {
    const err = await res.text().catch(() => res.status.toString());
    console.warn('[LecturePipeline] Groq transcription request failed', {
      audioFilePath,
      status: res.status,
      error: err,
    });
    throw new Error(`Groq transcription error ${res.status}: ${err}`);
  }

  const data = await res.json();
  const transcript = sanitizeTranscript(String(data?.text ?? '').trim());
  console.log('[LecturePipeline] Groq transcription response received', {
    audioFilePath,
    transcriptChars: transcript.length,
  });
  // Reject single short sentences that are classic Whisper hallucinations on silence
  if (isLikelyHallucination(transcript)) return '';
  return transcript;
}

/** Cloud fallback: Hugging Face Automatic Speech Recognition */
export async function transcribeRawWithHuggingFace(
  audioFilePath: string,
  huggingFaceToken: string,
  modelId = DEFAULT_HF_TRANSCRIPTION_MODEL,
): Promise<string> {
  if (!huggingFaceToken?.trim()) {
    throw new Error('Hugging Face token missing. Add one in Settings or choose another provider.');
  }

  const fileUri = toFileUri(audioFilePath);
  const fileInfo = await FileSystem.getInfoAsync(fileUri);
  if (!fileInfo?.exists || fileInfo.size === 0) {
    throw new Error(`Audio file is missing or empty: ${audioFilePath}`);
  }
  if (fileInfo.size > HUGGINGFACE_MAX_SAFE_UPLOAD_BYTES) {
    throw new Error(
      `Hugging Face transcription is limited to ${formatMegabytes(HUGGINGFACE_MAX_SAFE_UPLOAD_BYTES)} files in Guru to avoid memory crashes. Use Groq or Local Whisper for larger recordings.`,
    );
  }
  const timeoutMs = computeTranscriptionTimeoutMs(fileInfo.size);

  const response = await fetch(fileUri);
  if (!response.ok) {
    throw new Error(`Failed to read local audio file for Hugging Face: ${response.status}`);
  }

  const audioBlob = await response.blob();
  const res = await fetchWithTimeout(
    `https://router.huggingface.co/hf-inference/models/${encodeURIComponent(modelId)}`,
    {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${huggingFaceToken}`,
        'Content-Type': getAudioMimeType(audioFilePath),
      },
      body: audioBlob,
    },
    timeoutMs,
    'Hugging Face transcription',
  );

  if (!res.ok) {
    const err = await res.text().catch(() => res.status.toString());
    throw new Error(`Hugging Face transcription error ${res.status}: ${err}`);
  }

  const data = await res.json();
  const rawText =
    typeof data?.text === 'string'
      ? data.text
      : typeof data?.generated_text === 'string'
        ? data.generated_text
        : Array.isArray(data) && typeof data[0]?.text === 'string'
          ? data[0].text
          : '';
  const transcript = sanitizeTranscript(rawText.trim());
  if (isLikelyHallucination(transcript)) return '';
  return transcript;
}

/** Cloud fallback: Cloudflare Workers AI Whisper transcription */
export async function transcribeRawWithCloudflare(
  audioFilePath: string,
  accountId: string,
  apiToken: string,
): Promise<string> {
  if (!accountId?.trim() || !apiToken?.trim()) {
    throw new Error('Cloudflare account ID or API token missing. Add them in Settings.');
  }

  const fileUri = toFileUri(audioFilePath);
  const fileInfo = await FileSystem.getInfoAsync(fileUri);
  if (!fileInfo?.exists || fileInfo.size === 0) {
    throw new Error(`Audio file is missing or empty: ${audioFilePath}`);
  }
  const timeoutMs = computeTranscriptionTimeoutMs(fileInfo.size);

  // Read audio as base64 for Cloudflare's JSON endpoint
  const audioBase64 = await FileSystem.readAsStringAsync(fileUri, {
    encoding: FileSystem.EncodingType.Base64,
  });

  const res = await fetchWithTimeout(
    `https://api.cloudflare.com/client/v4/accounts/${accountId}/ai/run/@cf/openai/whisper-large-v3-turbo`,
    {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${apiToken}`,
      },
      body: JSON.stringify({
        audio: audioBase64,
        language: 'en',
        vad_filter: true,
        condition_on_previous_text: false,
      }),
    },
    timeoutMs,
    'Cloudflare transcription',
  );

  if (!res.ok) {
    const err = await res.text().catch(() => res.status.toString());
    throw new Error(`Cloudflare transcription error ${res.status}: ${err}`);
  }

  const data = await res.json();
  const rawText = String(data?.result?.text ?? '').trim();
  const transcript = sanitizeTranscript(rawText);
  if (isLikelyHallucination(transcript)) return '';
  return transcript;
}

/** Cloud fallback: Deepgram Nova-2 Medical transcription */
export async function transcribeRawWithDeepgram(
  audioFilePath: string,
  deepgramKey: string,
): Promise<string> {
  if (!deepgramKey?.trim()) {
    throw new Error('Deepgram API key missing. Add one in Settings.');
  }

  const fileUri = toFileUri(audioFilePath);
  const fileInfo = await FileSystem.getInfoAsync(fileUri);
  if (!fileInfo?.exists || fileInfo.size === 0) {
    throw new Error(`Audio file is missing or empty: ${audioFilePath}`);
  }
  const timeoutMs = computeTranscriptionTimeoutMs(fileInfo.size);

  const response = await fetch(fileUri);
  if (!response.ok) {
    throw new Error(`Failed to read local audio file for Deepgram: ${response.status}`);
  }

  const audioBlob = await response.blob();
  const mimeType = getAudioMimeType(audioFilePath);
  const res = await fetchWithTimeout(
    'https://api.deepgram.com/v1/listen?model=nova-2-medical&language=en&smart_format=true&punctuate=true&diarize=false',
    {
      method: 'POST',
      headers: {
        Authorization: `Token ${deepgramKey}`,
        'Content-Type': mimeType,
      },
      body: audioBlob,
    },
    timeoutMs,
    'Deepgram transcription',
  );

  if (!res.ok) {
    const err = await res.text().catch(() => res.status.toString());
    throw new Error(`Deepgram transcription error ${res.status}: ${err}`);
  }

  const data = await res.json();
  const rawText = String(data?.results?.channels?.[0]?.alternatives?.[0]?.transcript ?? '').trim();
  const transcript = sanitizeTranscript(rawText);
  if (isLikelyHallucination(transcript)) return '';
  return transcript;
}

/** Engine 2: Local Whisper.rn */
export async function transcribeRawWithLocalWhisper(
  audioFilePath: string,
  localWhisperPath: string,
): Promise<string> {
  const fileUri = toFileUri(audioFilePath);

  const fileInfo = await FileSystem.getInfoAsync(fileUri);
  if (!fileInfo?.exists || fileInfo.size === 0) return '';

  let whisperInputUri = fileUri;
  if (audioFilePath.endsWith('.m4a') || audioFilePath.endsWith('.mp4')) {
    const wavPath = await convertToWav(audioFilePath);
    if (wavPath) {
      whisperInputUri = toFileUri(wavPath);
    }
  }

  const whisperModelManager = getWhisperModelManager();
  const whisperInputInfo = await FileSystem.getInfoAsync(whisperInputUri);
  if (!whisperInputInfo?.exists || whisperInputInfo.size === 0) return '';

  const release = await acquireWhisperTranscriptionMutex();
  try {
    await whisperModelManager.loadModelFromFilePath(localWhisperPath);

    if (whisperInputInfo.size > LOCAL_WHISPER_BATCH_THRESHOLD_BYTES) {
      const batch = new BatchTranscriber(whisperModelManager, {
        chunkDurationSec: 30,
        overlapSec: 1,
        beamSize: 1,
        bestOf: 1,
        nThreads: 4,
      });
      const { segments } = await batch.transcribe(whisperInputUri);
      const transcript = sanitizeTranscript(
        segments
          .map((segment) => segment.text.trim())
          .filter(Boolean)
          .join(' ')
          .trim(),
      );
      return isLikelyHallucination(transcript) ? '' : transcript;
    }

    const whisperContext = whisperModelManager.getContext();
    const { promise } = whisperContext.transcribe(whisperInputUri, {
      language: 'en',
      maxThreads: 4,
      maxContext: 0,
      maxLen: 0,
      tokenTimestamps: false,
      beamSize: 1,
      bestOf: 1,
      temperature: 0,
      prompt: WHISPER_MEDICAL_PROMPT,
    });

    const { result } = await promise;
    const transcript = sanitizeTranscript(result?.trim() ?? '');
    return isLikelyHallucination(transcript) ? '' : transcript;
  } finally {
    release();
    if (whisperInputUri !== fileUri) {
      try {
        await FileSystem.deleteAsync(whisperInputUri, { idempotent: true });
      } catch {
        /* best effort */
      }
    }
  }
}

/**
 * transcribeAudio.ts — Unified transcription entry point.
 *
 * Groq first, Cloudflare / Hugging Face / local Whisper fallback.
 * Includes retry logic, analysis, and embedding.
 */
import { profileRepository } from '../../db/repositories';
import * as FileSystem from 'expo-file-system/legacy';
import { getApiKeys } from '../aiService';
import { toFileUri } from '../fileUri';
import {
  transcribeRawWithGroq,
  transcribeRawWithHuggingFace,
  transcribeRawWithCloudflare,
  transcribeRawWithDeepgram,
  transcribeRawWithLocalWhisper,
} from './engines';
import {
  buildTranscriptionProviderOrder,
  runTranscriptionProviders,
  type RunnableTranscriptionProvider,
  type TranscriptionProvider,
} from './providerFallback';
import {
  analyzeTranscript,
  type LectureAnalysis,
  type TranscriptAnalysisProgress,
} from './analysis';
import { generateEmbedding } from '../ai/embeddingService';
import { BUNDLED_HF_TOKEN, DEFAULT_HF_TRANSCRIPTION_MODEL } from '../../config/appConfig';

export type { LectureAnalysis };

export interface TranscriptionProgressUpdate {
  stage: 'transcribing' | 'analyzing';
  message: string;
  detail?: string;
  percent?: number;
  provider?: RunnableTranscriptionProvider;
  step?: number;
  totalSteps?: number;
  attempt?: number;
  maxAttempts?: number;
}

function previewTranscript(text: string, maxChars = 600): string {
  const normalized = text.replace(/\s+/g, ' ').trim();
  if (normalized.length <= maxChars) return normalized;
  return `${normalized.slice(0, maxChars)}...`;
}

function formatAudioSize(bytes: number): string {
  if (bytes >= 1024 * 1024) {
    const mb = bytes / (1024 * 1024);
    return `${mb >= 10 ? Math.round(mb) : mb.toFixed(1)} MB`;
  }
  if (bytes >= 1024) {
    return `${Math.max(1, Math.round(bytes / 1024))} KB`;
  }
  return `${bytes} B`;
}

function clampPercent(percent: number | undefined): number | undefined {
  if (typeof percent !== 'number' || Number.isNaN(percent)) return undefined;
  return Math.max(0, Math.min(100, Math.round(percent)));
}

function mapAnalysisProgressToOverall(progress: TranscriptAnalysisProgress): number {
  return clampPercent(64 + progress.percent * 0.26) ?? 75;
}

/**
 * Unified transcription entry point — Groq first, local Whisper fallback.
 * Includes retry logic and analysis.
 */
export async function transcribeAudio(opts: {
  audioFilePath: string;
  groqKey?: string;
  huggingFaceToken?: string;
  huggingFaceModel?: string;
  deepgramKey?: string;
  useLocalWhisper?: boolean;
  localWhisperPath?: string;
  transcriptionProvider?: TranscriptionProvider;
  includeEmbedding?: boolean;
  maxRetries?: number;
  logId?: number;
  onProgress?: (progress: TranscriptionProgressUpdate) => void;
}): Promise<LectureAnalysis & { embedding?: number[] }> {
  const profile = await profileRepository.getProfile();
  const {
    audioFilePath,
    groqKey = getApiKeys(profile).groqKey,
    huggingFaceToken = profile.huggingFaceToken || BUNDLED_HF_TOKEN,
    huggingFaceModel = profile.huggingFaceTranscriptionModel || DEFAULT_HF_TRANSCRIPTION_MODEL,
    deepgramKey = (profile as any).deepgramApiKey || getApiKeys(profile).deepgramKey,
    useLocalWhisper = profile.useLocalWhisper,
    localWhisperPath = profile.localWhisperPath,
    transcriptionProvider = profile.transcriptionProvider || 'auto',
    includeEmbedding = true,
    onProgress,
    maxRetries = 2,
    logId,
  } = opts;

  const fileInfo = await FileSystem.getInfoAsync(toFileUri(audioFilePath));
  if (!fileInfo?.exists || fileInfo.size === 0) {
    throw new Error(
      `Audio file is missing or empty: ${audioFilePath}. Check that recording started correctly.`,
    );
  }

  const audioSizeLabel = formatAudioSize(fileInfo.size ?? 0);

  onProgress?.({
    stage: 'transcribing',
    message: 'Preparing lecture transcription',
    detail: `Checking ${audioSizeLabel} recording and choosing the best provider`,
    percent: 6,
  });

  let transcript = '';
  const hasGroq = !!groqKey?.trim();
  const hasHuggingFace = !!huggingFaceToken?.trim();
  const hasDeepgram = !!deepgramKey?.trim();
  const hasLocalWhisper = !!(useLocalWhisper && localWhisperPath);
  const { cfAccountId, cfApiToken } = getApiKeys(profile);
  const hasCloudflare = !!(cfAccountId && cfApiToken);
  const providerAvailability = {
    groq: hasGroq,
    huggingface: hasHuggingFace,
    cloudflare: hasCloudflare,
    deepgram: hasDeepgram,
    local: hasLocalWhisper,
  } as const;
  const providerOrder = buildTranscriptionProviderOrder(
    transcriptionProvider,
    providerAvailability,
  );

  if (__DEV__) {
    console.log('[Transcription] Starting lecture transcription', {
      logId: logId ?? null,
      audioFilePath,
      audioSizeBytes: fileInfo.size ?? 0,
      audioSizeLabel,
      preferredProvider: transcriptionProvider,
      includeEmbedding,
      maxRetries,
    });
    console.log('[Transcription] Provider plan', {
      logId: logId ?? null,
      availability: providerAvailability,
      providerOrder,
    });
  }

  const { result, provider, lastError } = await runTranscriptionProviders<string>({
    preferredProvider: transcriptionProvider,
    availability: providerAvailability,
    isUsableResult: (value) => typeof value === 'string' && value.trim().length > 0,
    fallbackOnError: true,
    onProviderStart: (provider) => {
      if (__DEV__) {
        console.log('[Transcription] Provider starting', {
          logId: logId ?? null,
          provider,
          orderIndex: providerOrder.indexOf(provider) + 1,
          providerOrder,
        });
      }
      if (provider === 'groq') {
        onProgress?.({
          stage: 'transcribing',
          message: 'Transcribing with Groq Whisper',
          detail: `Primary provider selected for ${audioSizeLabel} audio`,
          provider,
          percent: 14,
        });
      } else if (provider === 'cloudflare') {
        onProgress?.({
          stage: 'transcribing',
          message: 'Transcribing with Cloudflare Whisper',
          detail: 'Groq was unavailable, so Guru switched providers',
          provider,
          percent: 14,
        });
      } else if (provider === 'huggingface') {
        onProgress?.({
          stage: 'transcribing',
          message: 'Transcribing with Hugging Face',
          detail: 'Trying the Hugging Face speech model as a fallback',
          provider,
          percent: 14,
        });
      } else if (provider === 'deepgram') {
        onProgress?.({
          stage: 'transcribing',
          message: 'Transcribing with Deepgram Nova-2',
          detail: 'Trying the Deepgram medical speech model',
          provider,
          percent: 14,
        });
      } else {
        onProgress?.({
          stage: 'transcribing',
          message: 'Using local transcription engine',
          detail: 'Running on-device Whisper for this recording',
          provider,
          percent: 14,
        });
      }
    },
    onProviderError: (provider, err) => {
      if (provider === 'groq') {
        if (__DEV__) {
          console.warn(`[Transcription] Groq failed after ${maxRetries} retries:`, err);
        }
      } else if (provider === 'cloudflare') {
        if (__DEV__) console.warn('[Transcription] Cloudflare failed:', err);
      } else if (provider === 'huggingface') {
        if (__DEV__) console.warn('[Transcription] Hugging Face failed:', err);
      } else if (provider === 'deepgram') {
        if (__DEV__) console.warn('[Transcription] Deepgram failed:', err);
      } else {
        if (__DEV__) console.warn('[Transcription] Local Whisper failed:', err);
      }
    },
    onProviderResult: (provider, value, usable) => {
      if (!__DEV__) return;
      const transcriptValue = typeof value === 'string' ? value : '';
      if (usable) {
        console.log('[Transcription] Provider transcript ready', {
          logId: logId ?? null,
          provider,
          transcriptChars: transcriptValue.length,
          preview: previewTranscript(transcriptValue, 220),
        });
      } else {
        console.log('[Transcription] Provider returned empty transcript', {
          logId: logId ?? null,
          provider,
          transcriptChars: transcriptValue.length,
        });
      }
    },
    runners: {
      groq: async () => {
        if (!groqKey?.trim()) return '';

        let attempt = 0;
        let providerError: unknown;
        const maxAttempts = maxRetries + 1;
        while (attempt <= maxRetries) {
          const attemptNumber = attempt + 1;
          onProgress?.({
            stage: 'transcribing',
            message:
              attemptNumber === 1
                ? 'Uploading recording to Groq Whisper'
                : `Retrying Groq Whisper (${attemptNumber}/${maxAttempts})`,
            detail: `Attempt ${attemptNumber} of ${maxAttempts} for ${audioSizeLabel} audio`,
            provider: 'groq',
            attempt: attemptNumber,
            maxAttempts,
            percent: attemptNumber === 1 ? 20 : 24,
          });
          try {
            if (process.env.NODE_ENV === 'test') {
              return await transcribeRawWithGroq(audioFilePath, groqKey);
            }
            const { transcribeWithGroqChunking } = await import('../lecture/transcription');
            const res = await transcribeWithGroqChunking(
              audioFilePath,
              groqKey,
              logId,
              (progress) =>
                onProgress?.({
                  stage: 'transcribing',
                  message: progress.message,
                  detail: progress.detail,
                  provider: 'groq',
                  attempt: attemptNumber,
                  maxAttempts,
                  step: progress.step,
                  totalSteps: progress.totalSteps,
                  percent: progress.percent,
                }),
            );
            return res.transcript;
          } catch (err) {
            providerError = err;
            attempt++;
            if (attempt > maxRetries) {
              throw providerError;
            }
            const delay = process.env.NODE_ENV === 'test' ? 10 : Math.pow(2, attempt) * 1000;
            onProgress?.({
              stage: 'transcribing',
              message: `Groq failed, retrying in ${Math.round(delay / 1000)}s`,
              detail: 'Guru will fall back to other providers if retries keep failing',
              provider: 'groq',
              attempt: attempt + 1,
              maxAttempts,
              percent: 24,
            });
            await new Promise((resolve) => setTimeout(resolve, delay));
          }
        }
        return '';
      },
      cloudflare: async () => {
        if (!cfAccountId || !cfApiToken) return '';
        return transcribeRawWithCloudflare(audioFilePath, cfAccountId, cfApiToken);
      },
      huggingface: async () => {
        if (!huggingFaceToken?.trim()) return '';
        return transcribeRawWithHuggingFace(audioFilePath, huggingFaceToken, huggingFaceModel);
      },
      deepgram: async () => {
        if (!deepgramKey?.trim()) return '';
        return transcribeRawWithDeepgram(audioFilePath, deepgramKey);
      },
      local: async () => {
        if (!(useLocalWhisper && localWhisperPath)) return '';
        return transcribeRawWithLocalWhisper(audioFilePath, localWhisperPath);
      },
    },
  });

  if (result) {
    transcript = result;
  }

  if (__DEV__ && transcript) {
    console.log('[Transcription] Transcript generated', {
      audioFilePath,
      provider: provider ?? 'unknown',
      transcriptChars: transcript.length,
      preview: previewTranscript(transcript),
    });
  }

  if (!transcript) {
    if (__DEV__) {
      console.log('[Transcription] No transcript text returned', {
        logId: logId ?? null,
        audioFilePath,
        providerOrder,
        lastError: lastError instanceof Error ? lastError.message : (lastError ?? null),
      });
    }
    if (!hasGroq && !hasHuggingFace && !hasCloudflare && !hasDeepgram && !hasLocalWhisper) {
      throw new Error(
        'No transcription engine available. Configure Groq, Cloudflare, Deepgram, or Hugging Face, or enable local Whisper in Settings.',
      );
    }
    if (lastError) {
      throw lastError;
    }
    // Transcript is empty but engines were available — likely silence or very short audio
    return {
      subject: 'Unknown',
      topics: [],
      keyConcepts: [],
      lectureSummary: 'No speech detected in recording (silent or very short audio)',
      estimatedConfidence: 1,
      transcript: '',
      highYieldPoints: [],
    };
  }

  if (__DEV__) {
    console.log('[Transcription] Starting lecture analysis', {
      logId: logId ?? null,
      transcriptChars: transcript.length,
      provider: provider ?? 'unknown',
    });
  }

  onProgress?.({
    stage: 'analyzing',
    message: 'Transcript ready, extracting lecture structure',
    detail: 'Finding subject, topics, and high-yield concepts',
    percent: 64,
  });
  const analysis = await analyzeTranscript(transcript, (progress) =>
    onProgress?.({
      stage: 'analyzing',
      message: progress.message,
      detail: progress.detail,
      step: progress.currentStep,
      totalSteps: progress.totalSteps,
      percent: mapAnalysisProgressToOverall(progress),
    }),
  );

  if (__DEV__) {
    console.log('[Transcription] Lecture analysis generated', {
      audioFilePath,
      subject: analysis.subject,
      topics: analysis.topics,
      keyConcepts: analysis.keyConcepts,
      summaryPreview: previewTranscript(analysis.lectureSummary, 240),
    });
  }

  let embedding: number[] | null | undefined;
  if (includeEmbedding && analysis.lectureSummary) {
    try {
      if (__DEV__) {
        console.log('[Transcription] Generating lecture embedding', {
          logId: logId ?? null,
          summaryChars: analysis.lectureSummary.length,
        });
      }
      onProgress?.({
        stage: 'analyzing',
        message: 'Finalizing lecture summary',
        detail: 'Generating a semantic embedding for later search and matching',
        percent: 92,
      });
      embedding = await generateEmbedding(analysis.lectureSummary);
    } catch (err) {
      embedding = null;
      if (__DEV__) console.warn('[Transcription] Embedding generation failed:', err);
    }
  } else if (__DEV__) {
    console.log('[Transcription] Embedding skipped', {
      logId: logId ?? null,
      includeEmbedding,
      hasSummary: !!analysis.lectureSummary,
    });
  }

  if (embedding) {
    return { ...analysis, transcript, embedding };
  } else {
    const { embedding: _, ...rest } = analysis;
    return { ...rest, transcript };
  }
}

import { XP_REWARDS, LEVELS } from '../constants/gamification';
import { profileRepository } from '../db/repositories';
import { runInTransaction } from '../db/database';
import { addXpInTx } from '../db/queries/progress';
import type { TopicWithProgress, LevelInfo } from '../types';

export interface XpBreakdown {
  label: string;
  amount: number;
}

export interface SessionXpResult {
  total: number;
  breakdown: XpBreakdown[];
  leveledUp: boolean;
  newLevel: number;
  newLevelName: string;
}

export async function grantXp(amount: number): Promise<{ leveledUp: boolean; newLevel: number }> {
  if (amount <= 0) return { leveledUp: false, newLevel: 1 };
  const { leveledUp, newLevel } = await profileRepository.addXp(amount);
  return { leveledUp, newLevel };
}

export async function calculateAndAwardSessionXp(
  completedTopics: TopicWithProgress[],
  quizResults: Array<{ correct: number; total: number }>,
  isFirstSessionToday: boolean,
): Promise<SessionXpResult> {
  const breakdown: XpBreakdown[] = [];
  let totalQuizCorrect = 0;

  for (const topic of completedTopics) {
    const isUnseen = topic.progress.status === 'unseen';
    const xp = isUnseen ? XP_REWARDS.TOPIC_UNSEEN : XP_REWARDS.TOPIC_REVIEW;
    breakdown.push({ label: `${topic.name}`, amount: xp });
  }

  for (const result of quizResults) {
    if (result.correct > 0) {
      totalQuizCorrect += result.correct;
      breakdown.push({
        label: 'Quiz correct answers',
        amount: result.correct * XP_REWARDS.QUIZ_CORRECT,
      });
    }
    if (result.correct === result.total && result.total > 0) {
      breakdown.push({ label: 'Perfect quiz bonus!', amount: XP_REWARDS.QUIZ_PERFECT });
    }
  }

  if (isFirstSessionToday) {
    breakdown.push({ label: 'Session complete', amount: XP_REWARDS.SESSION_COMPLETE });
  }

  let total = breakdown.reduce((s, b) => s + b.amount, 0);

  // Streak bonus: 10% per streak day, max 50%
  const _profile = await profileRepository.getProfile();
  const streakBonus = Math.min((_profile.streakCurrent ?? 0) * 0.1, 0.5);
  if (streakBonus > 0) {
    const bonus = Math.round(total * streakBonus);
    total += bonus;
    breakdown.push({
      label: `🔥 ${_profile.streakCurrent}-day streak (+${Math.round(streakBonus * 100)}%)`,
      amount: bonus,
    });
  }

  // Atomic: update quiz count + XP in a single transaction to prevent drift on crash
  const { newTotal, leveledUp, newLevel } = await runInTransaction(async (db) => {
    if (totalQuizCorrect > 0) {
      await db.runAsync(
        'UPDATE user_profile SET quiz_correct_count = quiz_correct_count + ? WHERE id = 1',
        [totalQuizCorrect],
      );
    }
    return addXpInTx(db, total);
  });

  const levelInfo = LEVELS.find((l) => l.level === newLevel) ?? LEVELS[0];

  return { total, breakdown, leveledUp, newLevel, newLevelName: levelInfo.name };
}

export function getLevelInfo(totalXp: number, currentLevel: number): LevelInfo {
  const level = LEVELS.find((l) => l.level === currentLevel) ?? LEVELS[0];
  const nextLevel = LEVELS.find((l) => l.level === currentLevel + 1);

  const xpInCurrentLevel = totalXp - level.xpRequired;
  const xpForNext = nextLevel ? nextLevel.xpRequired - level.xpRequired : 1;
  const progress = Math.min(1, xpInCurrentLevel / xpForNext);

  return {
    level: level.level,
    name: level.name,
    xpRequired: level.xpRequired,
    xpForNext: nextLevel?.xpRequired ?? level.xpRequired,
    progress,
  };
}

